const api = async (path, options = {}) => {
  const response = await fetch(path, {
    credentials: "same-origin",
    headers: { "Content-Type": "application/json" },
    ...options
  });
  if (response.status === 401 && !path.startsWith("/api/auth/") && !path.startsWith("/api/passwords") && !path.startsWith("/api/2fa")) {
    await renderAuth();
    throw new Error("Login necessario");
  }
  if (!response.ok) throw new Error((await response.json()).error || "Erro no sistema");
  return response.json();
};

const passwordApi = (path, options = {}) => api(path, {
  ...options,
  headers: {
    "Content-Type": "application/json",
    "X-Password-Vault-Token": state.passwordVaultToken || "",
    ...(options.headers || {})
  }
});

const twofaApi = (path, options = {}) => api(path, {
  ...options,
  headers: {
    "Content-Type": "application/json",
    "X-2FA-Vault-Token": state.twofaToken || "",
    ...(options.headers || {})
  }
});

