const money = (value) => {
  const raw = String(value ?? "0").trim();
  const normalized = typeof value === "number"
    ? value
    : Number(raw.includes(",") ? raw.replace(/\./g, "").replace(",", ".").replace(/[^\d.-]/g, "") : raw.replace(/[^\d.-]/g, ""));
  const number = Number.isFinite(normalized) ? normalized : 0;
  const rounded = Math.round((number + Number.EPSILON) * 100) / 100;
  return rounded.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
};
const percent = (value) => `${Number(value || 0).toFixed(2)}%`;
function moneyTone(value) {
  const amount = Number(value || 0);
  if (amount > 0) return "positive";
  if (amount < 0) return "negative";
  return "warn";
}

function expenseTone(value) {
  const amount = Number(value || 0);
  if (amount > 0) return "negative";
  if (amount < 0) return "positive";
  return "warn";
}
const APP_TIME_ZONE = "America/Sao_Paulo";
function localDateParts(date = new Date()) {
  return new Intl.DateTimeFormat("en-CA", {
    timeZone: APP_TIME_ZONE,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(date).reduce((result, part) => {
    if (part.type !== "literal") result[part.type] = part.value;
    return result;
  }, {});
}
function localDateTime(date = new Date(), includeSeconds = true, separator = "T") {
  const parts = localDateParts(date);
  const hour = parts.hour === "24" ? "00" : parts.hour;
  const time = includeSeconds ? `${hour}:${parts.minute}:${parts.second}` : `${hour}:${parts.minute}`;
  return `${parts.year}-${parts.month}-${parts.day}${separator}${time}`;
}
const today = () => localDateTime(new Date(), false).slice(0, 10);
function addDays(dateText, days) {
  const date = new Date(`${dateText || today()}T00:00:00`);
  date.setDate(date.getDate() + Number(days || 0));
  return date.toISOString().slice(0, 10);
}
function addMonths(dateText, months) {
  const date = new Date(`${dateText || today()}T12:00:00`);
  date.setMonth(date.getMonth() + Number(months || 0));
  return date.toISOString().slice(0, 10);
}
const nowDateTime = () => localDateTime(new Date(), false);
const nowDateTimeSeconds = () => localDateTime(new Date(), true);
const localDateTimeFromMilliseconds = (milliseconds) => localDateTime(new Date(milliseconds), true, " ");
const currentMonth = () => today().slice(0, 7);
const brlFormatter = new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" });
