function getSectionNavMenuKey(sectionId) {
  if (financeMenuSectionIds.includes(sectionId)) return "financeMenuOpen";
  if (goodsServicesMenuSectionIds.includes(sectionId)) return "goodsServicesMenuOpen";
  if (gamesMenuSectionIds.includes(sectionId)) return "gamesMenuOpen";
  if (personalMenuSectionIds.includes(sectionId)) return "personalMenuOpen";
  if (sectionId === "settings" || settingsMenuSectionIds.includes(sectionId)) return "settingsMenuOpen";
  return "";
}

function closeInactiveNavMenus(activeKey = "") {
  for (const key of navMenuStateKeys) state[key] = key === activeKey;
}

function syncNavMenusWithSection(sectionId) {
  closeInactiveNavMenus(getSectionNavMenuKey(sectionId));
}

function toggleNavMenu(menuKey, isOpen) {
  closeInactiveNavMenus(isOpen ? "" : menuKey);
  renderNav();
}

