function loginForm() {
  const usernameError = el("small", { class: "auth-field-error", id: "login-username-error", "aria-live": "polite" });
  const passwordError = el("small", { class: "auth-field-error", id: "login-password-error", "aria-live": "polite" });
  const passwordInput = el("input", { id: "login-password", name: "password", type: "password", required: "required", autocomplete: "current-password", placeholder: "Digite sua senha", value: "", "aria-describedby": "login-password-error" });
  const passwordToggle = el("button", {
    class: "auth-password-toggle",
    type: "button",
    "aria-label": "Mostrar senha",
    onclick: () => {
      const visible = passwordInput.type === "text";
      passwordInput.type = visible ? "password" : "text";
      passwordToggle.textContent = visible ? "◌" : "◉";
      passwordToggle.setAttribute("aria-label", visible ? "Mostrar senha" : "Ocultar senha");
    }
  }, ["◌"]);
  const keepConnectedInput = el("input", {
    id: "login-keep-connected",
    name: "keepConnected",
    type: "checkbox",
    value: "1",
    checked: localStorage.getItem("drso_keep_connected") !== "0" ? "checked" : undefined
  });
  return authShell(
    "Bem-vindo de volta",
    "Acesse seu painel pessoal e continue de onde parou.",
    [
      el("div", { class: "field full auth-input-field" }, [el("label", { for: "login-username" }, ["Usuario"]), el("div", { class: "auth-input-shell" }, [el("span", {}, ["♙"]), el("input", { id: "login-username", name: "username", type: "text", required: "required", autocomplete: "username", inputmode: "text", placeholder: "Digite seu usuario", value: "", "aria-describedby": "login-username-error" })]), usernameError]),
      el("div", { class: "field full" }, [
        el("div", { class: "auth-label-row" }, [el("label", { for: "login-password" }, ["Senha"]), el("button", { type: "button", onclick: openAuthRecoveryModal }, ["Esqueceu sua senha?"])]),
        el("div", { class: "auth-password-field auth-input-shell" }, [el("span", {}, ["▣"]), passwordInput, passwordToggle]),
        passwordError
      ]),
      el("label", { class: "auth-keep-connected full", for: "login-keep-connected" }, [
        keepConnectedInput,
        el("span", {}, [
          el("strong", {}, ["Manter conectado"]),
          el("small", {}, ["Evita sair por inatividade neste dispositivo."])
        ])
      ])
    ],
    "Entrar no sistema",
    async (event) => {
      event.preventDefault();
      const form = event.currentTarget;
      const submit = form.querySelector(".auth-submit");
      const submitLabel = submit.querySelector(".auth-submit-label");
      const generalError = form.querySelector("#auth-general-error");
      usernameError.textContent = "";
      passwordError.textContent = "";
      generalError.textContent = "";
      const username = form.elements.username.value.trim();
      const password = form.elements.password.value;
      if (!username || !password) {
        if (!username) usernameError.textContent = "Informe seu usuario.";
        if (!password) passwordError.textContent = "Informe sua senha.";
        (!username ? form.elements.username : form.elements.password).focus();
        return;
      }
      try {
        submit.disabled = true;
        submit.classList.add("is-loading");
        submitLabel.textContent = "Entrando...";
        const payload = Object.fromEntries(new FormData(form).entries());
        payload.keepConnected = payload.keepConnected === "1";
        const result = await api("/api/auth/login", { method: "POST", body: JSON.stringify(payload) });
        authRememberLastAccess();
        setKeepConnectedSession(Boolean(result.session?.keepConnected));
        await bootApp();
      } catch (error) {
        submit.disabled = false;
        submit.classList.remove("is-loading");
        submitLabel.textContent = "Entrar no sistema";
        generalError.textContent = "Nao foi possivel entrar. Verifique seus dados e tente novamente.";
        toast(error.message);
      }
    }
  );
}

function installIdleLogoutTracking() {
  if (idleTrackingInstalled) return;
  idleTrackingInstalled = true;
  ["click", "keydown", "mousemove", "scroll", "touchstart"].forEach((eventName) => {
    window.addEventListener(eventName, resetIdleLogoutTimer, { passive: true });
  });
}

function clearIdleLogoutTimer() {
  if (idleLogoutTimer) clearTimeout(idleLogoutTimer);
  idleLogoutTimer = null;
}

function resetIdleLogoutTimer() {
  clearIdleLogoutTimer();
  if (!authState.authenticated || localStorage.getItem("drso_keep_connected") === "1" || document.body.classList.contains("locked")) return;
  idleLogoutTimer = setTimeout(async () => {
    toast("Sessao encerrada por inatividade.");
    await logout({ clearRemember: false });
  }, IDLE_LOGOUT_MS);
}

function setKeepConnectedSession(keepConnected) {
  if (keepConnected) {
    localStorage.setItem("drso_keep_connected", "1");
    clearIdleLogoutTimer();
    return;
  }
  localStorage.removeItem("drso_keep_connected");
  installIdleLogoutTracking();
  resetIdleLogoutTimer();
}

function currentBiSection() {
  const section = sections.find((item) => item.id === state.section) || sections[0];
  return { id: section?.id || state.section || "dashboard", title: section?.title || state.section || "Modulo" };
}

function sendBiUsage(force = false) {
  const now = Date.now();
  const duration = Math.round((now - biUsageLastAt) / 1000);
  if (!force && duration < 45) return;
  biUsageLastAt = now;
  if (!authState.authenticated || duration <= 0) return;
  const section = currentBiSection();
  const music = currentMusic();
  const musicPlaying = state.musicPlayerState === "playing" && Boolean(music);
  fetch("/api/bi/usage", {
    method: "POST",
    credentials: "same-origin",
    keepalive: true,
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      module: section.id,
      module_title: section.title,
      duration_seconds: duration,
      music_playing: musicPlaying ? 1 : 0,
      music_id: musicPlaying ? music.id : "",
      music_title: musicPlaying ? music.titulo : "",
      music_artist: musicPlaying ? music.artista : ""
    })
  }).catch(() => {});
}

function startBiUsageTracker() {
  biUsageLastAt = Date.now();
  if (!biUsageTimer) biUsageTimer = setInterval(() => sendBiUsage(false), 60000);
  if (biUsageEventsInstalled) return;
  biUsageEventsInstalled = true;
  document.addEventListener("visibilitychange", () => {
    if (document.hidden) sendBiUsage(true);
    else biUsageLastAt = Date.now();
  });
  window.addEventListener("beforeunload", () => sendBiUsage(true));
}

function stopBiUsageTracker() {
  sendBiUsage(true);
  if (biUsageTimer) clearInterval(biUsageTimer);
  biUsageTimer = null;
  biUsageLastAt = Date.now();
}

async function setSection(id) {
  const previousSection = state.section;
  if (previousSection === "timeCenter" && id !== "timeCenter") {
    clearInterval(TimeCenter.pageEnvironmentTimer);
    TimeCenter.pageEnvironmentTimer = null;
  }
  sendBiUsage(true);
  if (id === "settings" && state.section !== "settings" && !state.settingsUnlocked) {
    const ok = await openPasswordGateModal({
      title: "Acesso as configuracoes",
      message: "Confirme seu usuario e senha para abrir as configuracoes do sistema."
    });
    if (!ok) return;
    state.settingsUnlocked = true;
  }
  const leavingDatabase = state.section === "database" && id !== "database";
  const enteringDatabase = state.section !== "database" && id === "database";
  const leavingSettings = state.section === "settings" && id !== "settings";
  const leavingPasswords = state.section === "passwords" && id !== "passwords";
  state = { ...state, section: id, editing: null };
  document.body.dataset.section = id;
  if (id === "agenda" && previousSection !== "agenda") {
    state.agendaMonth = currentMonth();
    state.agendaSelectedDate = today();
    state.agendaPage = 1;
  }
  if (leavingDatabase || enteringDatabase) {
    state.databaseToken = "";
    state.databaseOverview = null;
    state.databaseQueryResult = null;
  }
  if (leavingSettings) state.settingsUnlocked = false;
  if (leavingPasswords) {
    state.passwordVaultToken = "";
    state.visiblePasswords = {};
    state.passwordFilters = { search: "" };
  }
  syncNavMenusWithSection(id);
  if (id !== "notes") {
    state.notesConfidentialUnlocked = false;
    if (state.notesTab === "confidential") state.notesTab = "active";
  }
  const section = sections.find((item) => item.id === id);
  const financeCreditActive = id === "finance" && state.financeTab === "creditCards";
  const sectionTitle = financeCreditActive ? financeCreditMenuItem.title : section.title;
  const sectionIcon = financeCreditActive ? financeCreditMenuItem.icon : section.icon;
  const sectionIconClass = financeCreditActive ? "" : section.iconClass || "";
  const sectionKicker = financeCreditActive ? "Faturas, limites, parcelas e pagamentos" : section.kicker;
  document.querySelector("#section-title").replaceChildren(
    el("span", { class: `section-title-icon ${sectionIconClass}`.trim(), "aria-hidden": "true" }, [sectionIcon || ""]),
    document.createTextNode(sectionTitle)
  );
  document.querySelector("#section-kicker").textContent = sectionKicker;
  renderNav();
  renderContextDock();
  render().then(() => {
    renderContextDock();
    updateGlobalMusicBar();
  }).catch((error) => {
    const view = document.querySelector("#view");
    if (view) {
      view.replaceChildren(el("section", { class: "card" }, [
        el("div", { class: "card-body" }, [
          el("h2", {}, ["Nao foi possivel abrir esta tela"]),
          el("p", { class: "muted" }, [error.message || "Erro inesperado ao carregar o modulo."])
        ])
      ]));
    }
    toast(error.message || "Erro ao abrir tela.");
  });
}

