function planningColumnWidth(key) {
  const label = labels[key] || key;
  const fallback = Math.max(96, Math.min(240, String(label).length * 10 + 54));
  if (key === "actions" || key === "actions_start") {
    return Math.max(116, Math.min(148, Number(planningColumnWidths[key] || planningColumnDefaults[key] || 132)));
  }
  return Math.max(72, Number(planningColumnWidths[key] || planningColumnDefaults[key] || fallback));
}

function savePlanningColumnWidth(key, width) {
  planningColumnWidths = { ...planningColumnWidths, [key]: Math.max(72, Math.round(width)) };
  localStorage.setItem("drso_table_column_widths", JSON.stringify(planningColumnWidths));
}

function tableVisibleColumnKeys(table) {
  return [...table.querySelectorAll("col[data-column]")].map((column) => column.dataset.column);
}

function measureTextWidth(text, sampleElement) {
  const measurer = document.createElement("span");
  const style = getComputedStyle(sampleElement || document.body);
  measurer.style.position = "fixed";
  measurer.style.left = "-9999px";
  measurer.style.top = "-9999px";
  measurer.style.visibility = "hidden";
  measurer.style.whiteSpace = "nowrap";
  measurer.style.font = style.font;
  measurer.textContent = String(text || "");
  document.body.append(measurer);
  const width = measurer.getBoundingClientRect().width;
  measurer.remove();
  return width;
}

function autoFitTableColumn(table, key) {
  const column = table?.querySelector(`col[data-column="${key}"]`);
  if (!table || !column) return;
  const visibleKeys = tableVisibleColumnKeys(table);
  const index = visibleKeys.indexOf(key);
  if (index < 0) return;
  const cells = [
    ...table.querySelectorAll(`thead tr > *:nth-child(${index + 1})`),
    ...table.querySelectorAll(`tbody tr > *:nth-child(${index + 1})`)
  ];
  const maxContent = cells.reduce((max, cell) => {
    const text = cell.textContent.trim();
    const width = measureTextWidth(text, cell);
    const naturalWidth = cell.scrollWidth;
    const buttonsWidth = [...cell.querySelectorAll("button")].reduce((sum, button) => sum + button.getBoundingClientRect().width + 8, 0);
    return Math.max(max, width, naturalWidth, buttonsWidth);
  }, 0);
  const width = Math.max(72, Math.min(900, Math.ceil(maxContent + 42)));
  column.style.width = `${width}px`;
  savePlanningColumnWidth(key, width);
  const allColumns = [...table.querySelectorAll("col[data-column]")];
  table.style.width = `${allColumns.reduce((sum, item) => sum + Number(String(item.style.width || "").replace("px", "") || planningColumnWidth(item.dataset.column)), 0)}px`;
}

function tableColumnSettingsKey(columns, options = {}) {
  return `drso_table_columns:${options.columnKey || columns.join("|")}`;
}

function hiddenTableColumns(columns, options = {}) {
  try {
    return new Set(JSON.parse(localStorage.getItem(tableColumnSettingsKey(columns, options)) || "[]"));
  } catch {
    return new Set();
  }
}

function saveHiddenTableColumns(columns, hidden, options = {}) {
  localStorage.setItem(tableColumnSettingsKey(columns, options), JSON.stringify([...hidden]));
}

function tableColumnOrderKey(columns, options = {}) {
  return `drso_table_column_order:${options.columnKey || columns.join("|")}`;
}

function orderedTableColumnIndexes(columns, options = {}) {
  let saved = [];
  try {
    saved = JSON.parse(localStorage.getItem(tableColumnOrderKey(columns, options)) || "[]");
  } catch {
    saved = [];
  }
  const validSaved = saved.filter((key) => columns.includes(key));
  const ordered = [...validSaved, ...columns.filter((key) => !validSaved.includes(key))];
  return ordered.map((key) => columns.indexOf(key));
}

function saveTableColumnOrder(columns, sourceKey, targetKey, options = {}) {
  const indexes = orderedTableColumnIndexes(columns, options);
  const ordered = indexes.map((index) => columns[index]);
  const sourceIndex = ordered.indexOf(sourceKey);
  const targetIndex = ordered.indexOf(targetKey);
  if (sourceIndex < 0 || targetIndex < 0 || sourceIndex === targetIndex) return false;
  ordered.splice(sourceIndex, 1);
  ordered.splice(targetIndex, 0, sourceKey);
  localStorage.setItem(tableColumnOrderKey(columns, options), JSON.stringify(ordered));
  return true;
}

function openTableColumnsModal(table) {
  if (!table) return;
  const columns = JSON.parse(table.dataset.columns || "[]");
  if (!columns.length) return;
  const options = { columnKey: table.dataset.columnKey || "" };
  const hidden = hiddenTableColumns(columns, options);
  document.body.classList.add("modal-open");

  const close = () => {
    document.body.classList.remove("modal-open");
    overlay.remove();
  };
  const overlay = el("div", { class: "confirm-modal-backdrop", onclick: close }, [
    el("article", { class: "confirm-modal table-columns-modal", onclick: (event) => event.stopPropagation() }, [
      el("div", { class: "settings-card-head" }, [
        el("div", {}, [
          el("h2", {}, ["Colunas da listagem"]),
          el("p", { class: "muted" }, ["Escolha o que aparece nesta tabela."])
        ]),
        el("button", { class: "icon-button", type: "button", onclick: close, title: "Fechar" }, ["x"])
      ]),
      el("div", { class: "table-columns-list" }, columns.map((key) => el("label", { class: "table-column-option" }, [
        el("input", {
          type: "checkbox",
          checked: hidden.has(key) ? undefined : "checked",
          onchange: (event) => {
            if (event.currentTarget.checked) hidden.delete(key);
            else hidden.add(key);
          }
        }),
        el("span", {}, [labels[key] || key])
      ]))),
      el("div", { class: "confirm-actions" }, [
        el("button", {
          class: "secondary-button",
          type: "button",
          onclick: () => {
            hidden.clear();
            saveHiddenTableColumns(columns, hidden, options);
            close();
            render();
          }
        }, ["Mostrar todas"]),
        el("button", { class: "secondary-button", type: "button", onclick: close }, ["Cancelar"]),
        el("button", {
          class: "primary-button",
          type: "button",
          onclick: () => {
            const visibleCount = columns.filter((key) => !hidden.has(key)).length;
            if (!visibleCount) hidden.delete(columns[0]);
            saveHiddenTableColumns(columns, hidden, options);
            close();
            render();
          }
        }, ["Aplicar"])
      ])
    ])
  ]);
  document.body.append(overlay);
}

function openTableColumnsModalFromEvent(event) {
  event.preventDefault();
  event.stopPropagation();
  openTableColumnsModal(event.currentTarget.closest("table"));
}

function planningColumnResizeHandle(key) {
  return el("span", {
    class: "column-resizer",
    title: "Arrastar para redimensionar coluna. Duplo clique ajusta ao conteudo.",
    oncontextmenu: openTableColumnsModalFromEvent,
    ondblclick: (event) => {
      event.preventDefault();
      event.stopPropagation();
      autoFitTableColumn(event.currentTarget.closest("table"), key);
    },
    onpointerdown: (event) => {
      if (event.detail > 1) return;
      event.preventDefault();
      event.stopPropagation();
      const table = event.currentTarget.closest("table");
      const column = table?.querySelector(`col[data-column="${key}"]`);
      if (!table || !column) return;

      const startX = event.clientX;
      const startWidth = Number(String(column.style.width || "").replace("px", "")) || planningColumnWidth(key);
      const allColumns = [...table.querySelectorAll("col[data-column]")];

      const resize = (moveEvent) => {
        const width = Math.max(72, startWidth + moveEvent.clientX - startX);
        column.style.width = `${width}px`;
        savePlanningColumnWidth(key, width);
        table.style.width = `${allColumns.reduce((sum, item) => sum + Number(String(item.style.width || "").replace("px", "") || 0), 0)}px`;
      };
      const stop = () => {
        document.body.classList.remove("resizing-column");
        window.removeEventListener("pointermove", resize);
        window.removeEventListener("pointerup", stop);
      };

      document.body.classList.add("resizing-column");
      window.addEventListener("pointermove", resize);
      window.addEventListener("pointerup", stop, { once: true });
    }
  });
}

function tableHeaderCell(key, content = labels[key] || key) {
  const displayContent = key === "actions" || key === "actions_start" ? "Ações" : content;
  return el("th", { class: `resizable-th ${key === "actions" || key === "actions_start" ? "action-column" : ""}`.trim(), oncontextmenu: openTableColumnsModalFromEvent }, [
    el("div", { class: "resizable-th-content" }, [displayContent]),
    planningColumnResizeHandle(key)
  ]);
}

function sortableTextValue(text) {
  const value = String(text || "").trim();
  const brDate = value.match(/^(\d{2})\/(\d{2})\/(\d{4})(?:\s+(\d{2}):(\d{2})(?::(\d{2}))?)?/);
  if (brDate) {
    const [, day, month, year, hour = "00", minute = "00", second = "00"] = brDate;
    return { type: "number", value: new Date(`${year}-${month}-${day}T${hour}:${minute}:${second}`).getTime() || 0 };
  }
  if (/R\$\s*[\d.,-]+/.test(value)) return { type: "number", value: parseBRL(value) };
  if (/^#?\d+(?:[.,]\d+)?$/.test(value)) return { type: "number", value: Number(value.replace("#", "").replace(",", ".")) };
  if (/^-?\d+(?:[.,]\d+)?%$/.test(value)) return { type: "number", value: Number(value.replace("%", "").replace(",", ".")) };
  return { type: "text", value: value.toLocaleLowerCase("pt-BR") };
}

function sortTableByColumn(table, columnIndex, direction) {
  const tbody = table.querySelector("tbody");
  if (!tbody) return;
  const rows = table.__allRows || [...tbody.querySelectorAll("tr")];
  rows.sort((a, b) => {
    const av = sortableTextValue(a.children[columnIndex]?.textContent || "");
    const bv = sortableTextValue(b.children[columnIndex]?.textContent || "");
    const result = av.type === "number" && bv.type === "number"
      ? av.value - bv.value
      : String(av.value).localeCompare(String(bv.value), "pt-BR", { numeric: true, sensitivity: "base" });
    return direction === "asc" ? result : -result;
  });
  if (table.__allRows) {
    table.__allRows = rows;
    table.__tablePage = 1;
    table.__applyTableView?.();
  } else {
    tbody.replaceChildren(...rows);
  }
}

function setTableSortHeader(table, activeHeader, direction) {
  table.querySelectorAll("th").forEach((header) => {
    header.classList.remove("table-sort-asc", "table-sort-desc");
    header.removeAttribute("aria-sort");
  });
  activeHeader.classList.add(direction === "asc" ? "table-sort-asc" : "table-sort-desc");
  activeHeader.setAttribute("aria-sort", direction === "asc" ? "ascending" : "descending");
}

let activeTableActionMenu = null;
let activeTableActionAnchor = null;

function tableActionMeta(source) {
  const label = String(source?.dataset?.actionLabel || source?.textContent || source?.title || "Ação").trim();
  const normalized = normalizeSearch(label);
  if (/excluir|remover|apagar/.test(normalized)) return { label, type: "danger", icon: "🗑︎" };
  if (/visualizar|ver detalhe|detalhes|abrir/.test(normalized)) return { label, type: "view", icon: "◉" };
  if (/editar|alterar/.test(normalized)) return { label, type: "edit", icon: "✎" };
  if (/duplicar|copiar/.test(normalized)) return { label, type: "duplicate", icon: "⧉" };
  if (/reverter|desfazer|desguardar/.test(normalized)) return { label, type: "revert", icon: "↶" };
  if (/cash out|cashout/.test(normalized)) return { label, type: "cashout", icon: "↗" };
  if (/confirmar|ganhei|pago|guardar|salvar|liquidar/.test(normalized)) return { label, type: "success", icon: "✓" };
  if (/cancelar|perdi|anular|anulada/.test(normalized)) return { label, type: "neutral", icon: "−" };
  if (/baixar|download/.test(normalized)) return { label, type: "download", icon: "↓" };
  return { label, type: "neutral", icon: "›" };
}

function closeTableActionMenu() {
  activeTableActionMenu?.remove();
  activeTableActionAnchor?.setAttribute("aria-expanded", "false");
  activeTableActionMenu = null;
  activeTableActionAnchor = null;
}

async function runTableAction(source, trigger, meta) {
  if (!source || source.disabled || source.getAttribute("aria-disabled") === "true") return;
  trigger?.classList.add("loading");
  trigger?.setAttribute("aria-busy", "true");
  closeTableActionMenu();
  source.click();
  window.setTimeout(() => {
    trigger?.classList.remove("loading");
    trigger?.removeAttribute("aria-busy");
  }, 650);
}

function createTableActionMenuItem(source) {
  const meta = tableActionMeta(source);
  const item = el("button", {
    class: `action-menu-item action-menu-item--${meta.type} ${meta.type === "danger" ? "action-menu-item--danger" : ""}`.trim(),
    type: "button",
    role: "menuitem",
    disabled: source.disabled ? "disabled" : null,
    onclick: (event) => {
      event.stopPropagation();
      runTableAction(source, item, meta);
    }
  }, [
    el("span", { class: "action-menu-item-icon", "aria-hidden": "true" }, [meta.icon]),
    el("span", {}, [meta.label])
  ]);
  return item;
}

function openTableActionMenu(anchor, sources) {
  const wasOpen = activeTableActionAnchor === anchor;
  closeTableActionMenu();
  if (wasOpen) return;
  const menu = el("div", { class: "action-menu", role: "menu", "aria-label": "Opções do registro" }, sources.map(createTableActionMenuItem));
  document.body.append(menu);
  const anchorRect = anchor.getBoundingClientRect();
  const menuRect = menu.getBoundingClientRect();
  const viewportGap = 12;
  const left = Math.max(viewportGap, Math.min(window.innerWidth - menuRect.width - viewportGap, anchorRect.right - menuRect.width));
  const below = anchorRect.bottom + 8;
  const top = below + menuRect.height <= window.innerHeight - viewportGap
    ? below
    : Math.max(viewportGap, anchorRect.top - menuRect.height - 8);
  menu.style.left = `${Math.round(left)}px`;
  menu.style.top = `${Math.round(top)}px`;
  anchor.setAttribute("aria-expanded", "true");
  activeTableActionMenu = menu;
  activeTableActionAnchor = anchor;
}

function createTableDirectAction(source) {
  const meta = tableActionMeta(source);
  const emphasis = meta.type === "view" ? "action-button--primary" : "action-button--ghost";
  const button = el("button", {
    class: `action-button ${emphasis} action-button--${meta.type}`,
    type: "button",
    title: meta.type === "view" ? "Visualizar" : "Editar",
    "aria-label": meta.type === "view" ? "Visualizar" : "Editar",
    disabled: source.disabled ? "disabled" : null,
    onclick: (event) => {
      event.stopPropagation();
      runTableAction(source, button, meta);
    }
  }, [el("span", { "aria-hidden": "true" }, [meta.icon])]);
  return button;
}

function tableActionSources(container) {
  return [...container.querySelectorAll(":scope > button, :scope > a")].filter((item) => !item.classList.contains("action-button"));
}

function enhanceTableActionGroup(container) {
  if (!container || container.dataset.actionEnhanced === "true") return;
  if (container.tagName === "TD") {
    container.dataset.actionEnhanced = "true";
    const wrapper = el("div", { class: "actions" }, [...container.children]);
    container.replaceChildren(wrapper);
    container.classList.add("action-column");
    enhanceTableActionGroup(wrapper);
    return;
  }
  const sources = tableActionSources(container);
  if (!sources.length) return;
  container.dataset.actionEnhanced = "true";
  container.classList.add("action-cell");
  const sourceBox = el("div", { class: "action-menu-source", "aria-hidden": "true" });
  sources.forEach((source) => sourceBox.append(source));
  const directSources = [
    sources.find((source) => tableActionMeta(source).type === "view"),
    sources.find((source) => tableActionMeta(source).type === "edit")
  ].filter(Boolean);
  const controls = el("div", { class: "action-cell-controls" }, [
    ...directSources.map(createTableDirectAction),
    el("button", {
      class: "action-button action-button--ghost action-menu-trigger",
      type: "button",
    title: "Mais opções",
    "aria-label": "Mais opções",
      "aria-haspopup": "menu",
      "aria-expanded": "false",
      onclick: (event) => {
        event.stopPropagation();
        openTableActionMenu(event.currentTarget, sources);
      }
    }, [el("span", { class: "action-more-icon", "aria-hidden": "true" }, ["•••"])])
  ]);
  container.replaceChildren(sourceBox, controls);
  container.closest("td")?.classList.add("action-column");
}

function enhanceTableActions(root = document) {
  const selectors = [
    "table td.action-column > .actions",
    "table td > .actions",
    "table td.actions-cell",
    "table td > .instagram-row-actions",
    ".subscription-row .actions",
    ".vendinha-consumption-row .actions"
  ];
  root.querySelectorAll?.(selectors.join(",")).forEach(enhanceTableActionGroup);
  root.querySelectorAll?.(".pill").forEach((badge) => {
    const status = normalizeSearch(badge.textContent);
    badge.classList.add("status-badge");
    if (/anulada|anulado/.test(status)) badge.classList.add("status-badge--neutral");
    else if (/cancelada|cancelado/.test(status)) badge.classList.add("status-badge--danger");
    else if (badge.classList.contains("green") || badge.classList.contains("positive") || /confirmada|confirmado/.test(status)) badge.classList.add("status-badge--success");
    else if (badge.classList.contains("warn") || /pendente/.test(status)) badge.classList.add("status-badge--warning");
    else if (badge.classList.contains("red") || badge.classList.contains("negative")) badge.classList.add("status-badge--danger");
    else badge.classList.add("status-badge--neutral");
  });
}

document.addEventListener("click", (event) => {
  if (!event.target.closest?.(".action-menu, .action-menu-trigger")) closeTableActionMenu();
});
document.addEventListener("keydown", (event) => {
  if (event.key === "Escape") closeTableActionMenu();
});
window.addEventListener("resize", closeTableActionMenu);
window.addEventListener("scroll", closeTableActionMenu, true);

function isTableFullscreen(wrap) {
  return document.fullscreenElement === wrap || wrap.classList.contains("table-fullscreen-fallback");
}

function updateTableFullscreenButton(wrap) {
  const button = wrap.querySelector(".table-fullscreen-button");
  if (!button) return;
  const active = isTableFullscreen(wrap);
  button.textContent = active ? "Sair da tela cheia" : "Tela cheia";
  button.title = active ? "Sair da tela cheia" : "Ver esta lista em tela cheia";
  button.setAttribute("aria-pressed", active ? "true" : "false");
}

async function toggleTableFullscreen(wrap) {
  if (!wrap) return;
  if (document.fullscreenElement === wrap) {
    await document.exitFullscreen();
    return;
  }
  if (wrap.classList.contains("table-fullscreen-fallback")) {
    wrap.classList.remove("table-fullscreen-fallback");
    document.body.classList.remove("modal-open");
    updateTableFullscreenButton(wrap);
    return;
  }
  try {
    await wrap.requestFullscreen();
  } catch {
    wrap.classList.add("table-fullscreen-fallback");
    document.body.classList.add("modal-open");
    updateTableFullscreenButton(wrap);
  }
}

document.addEventListener("fullscreenchange", () => {
  document.querySelectorAll(".system-table-wrap").forEach(updateTableFullscreenButton);
});

function systemTable(tableColumns, headerCells, bodyRows, options = {}) {
  const hidden = hiddenTableColumns(tableColumns, options);
  const orderedIndexes = orderedTableColumnIndexes(tableColumns, options);
  let visibleIndexes = orderedIndexes.filter((index) => !hidden.has(tableColumns[index]));
  if (!visibleIndexes.length) visibleIndexes = [0];
  const visibleColumns = visibleIndexes.map((index) => tableColumns[index]);
  const visibleHeaders = visibleIndexes.map((index) => headerCells[index]);
  const visibleRows = bodyRows.map((row) => {
    const cells = [...row.children];
    row.replaceChildren(...visibleIndexes.map((index) => cells[index]).filter(Boolean));
    [...row.children].forEach((cell, index) => {
      cell.dataset.label = String(visibleHeaders[index]?.textContent || visibleColumns[index] || "").trim();
    });
    row.querySelectorAll("button").forEach((button) => {
      const text = button.textContent.trim().toLocaleLowerCase("pt-BR");
      const icon = text.includes("visual") || text.includes("mostrar") ? "👁"
        : text.includes("baix") || text.includes("download") ? "⬇"
          : text.includes("editar") ? "✏"
            : text.includes("excluir") ? "🗑"
              : text.includes("mais") || text.includes("op") ? "⚙"
                : text.includes("pago") || text.includes("ganhei") ? "✓"
                  : text.includes("perdi") ? "!"
                    : "";
      if (icon) {
        button.classList.add("table-icon-action");
        button.dataset.actionIcon = icon;
        if (!button.title) button.title = button.textContent.trim();
      }
    });
    if (row.querySelector(".pill.green")) row.classList.add("table-row-success");
    if (row.querySelector(".pill.saved")) row.classList.add("table-row-saved");
    if (row.querySelector(".pill.warn")) row.classList.add("table-row-pending");
    if (row.querySelector(".pill.red")) row.classList.add("table-row-danger");
    return row;
  });
  const tableWidth = visibleColumns.reduce((sum, key) => sum + planningColumnWidth(key), 0);
  const children = [];
  if (options.title) children.push(el("div", { class: "card-body" }, [el("h2", {}, [options.title])]));
  const table = el("table", {
    class: options.tableClass || "system-table",
    style: `width:${tableWidth}px`,
    "data-columns": JSON.stringify(tableColumns),
    "data-column-key": options.columnKey || tableColumns.join("|")
  }, [
    el("colgroup", {}, visibleColumns.map((key) => el("col", { "data-column": key, style: `width:${planningColumnWidth(key)}px` }))),
    el("thead", {}, [el("tr", {}, visibleHeaders)]),
    el("tbody", {}, visibleRows)
  ]);
  const tbody = table.querySelector("tbody");
  const tableKey = `drso_table_size_${options.columnKey || tableColumns.join("|")}`;
  const savedPageSize = Number(localStorage.getItem(tableKey) || 10);
  table.__allRows = visibleRows;
  table.__tablePage = 1;
  table.__pageSize = [10, 25, 50, 100].includes(savedPageSize) ? savedPageSize : 10;
  table.__tableSearch = "";
  let tableSummary;
  let tableSummaryFooter;
  let paginationButtons;
  const tableSearchInput = el("input", {
    class: "table-search-input",
    type: "search",
    placeholder: "Buscar nesta lista...",
    oninput: (event) => {
      table.__tableSearch = event.currentTarget.value.trim().toLocaleLowerCase("pt-BR");
      table.__tablePage = 1;
      table.__applyTableView();
    }
  });
  const pageSizeSelect = el("select", {
    class: "table-page-size",
    onchange: (event) => {
      table.__pageSize = Number(event.currentTarget.value);
      localStorage.setItem(tableKey, String(table.__pageSize));
      table.__tablePage = 1;
      table.__applyTableView();
    }
  }, [10, 25, 50, 100].map((size) => el("option", { value: String(size), selected: size === table.__pageSize ? "selected" : null }, [String(size)])));
  const renderTablePagination = (total, page, pages) => {
    const buttons = [];
    const addButton = (label, target, disabled = false, active = false) => buttons.push(el("button", {
      class: `pagination-button ${active ? "active" : ""}`.trim(),
      type: "button",
      disabled: disabled ? "disabled" : null,
      onclick: () => {
        table.__tablePage = target;
        table.__applyTableView();
      }
    }, [label]));
    addButton("<", Math.max(1, page - 1), page <= 1);
    for (let item = 1; item <= pages; item += 1) {
      if (pages > 7 && item !== 1 && item !== pages && Math.abs(item - page) > 1) {
        if (!buttons.at(-1)?.classList?.contains("pagination-gap")) buttons.push(el("span", { class: "pagination-gap" }, ["..."]));
        continue;
      }
      addButton(String(item), item, false, item === page);
    }
    addButton(">", Math.min(pages, page + 1), page >= pages);
    paginationButtons.replaceChildren(...buttons);
    const summaryText = total
      ? `Mostrando ${Math.min(table.__pageSize, Math.max(0, total - ((page - 1) * table.__pageSize)))} de ${total} registros`
      : "Nenhum registro encontrado";
    tableSummary.textContent = summaryText;
    tableSummaryFooter.textContent = summaryText;
  };
  table.__applyTableView = () => {
    const search = table.__tableSearch;
    const filtered = search
      ? table.__allRows.filter((row) => row.textContent.toLocaleLowerCase("pt-BR").includes(search))
      : table.__allRows;
    const pages = Math.max(1, Math.ceil(filtered.length / table.__pageSize));
    table.__tablePage = Math.min(table.__tablePage, pages);
    const start = (table.__tablePage - 1) * table.__pageSize;
    tbody.replaceChildren(...filtered.slice(start, start + table.__pageSize));
    renderTablePagination(filtered.length, table.__tablePage, pages);
  };
  visibleHeaders.forEach((header, index) => {
    const key = visibleColumns[index];
    header.dataset.column = key;
    header.setAttribute("draggable", "true");
    header.title = `${header.title ? `${header.title} ` : ""}Clique para ordenar. Arraste para reorganizar a coluna.`;
    header.addEventListener("dragstart", (event) => {
      header.classList.add("dragging-column");
      event.dataTransfer.effectAllowed = "move";
      event.dataTransfer.setData("text/plain", key);
    });
    header.addEventListener("dragend", () => {
      table.querySelectorAll("th").forEach((item) => item.classList.remove("dragging-column", "column-drop-target"));
    });
    header.addEventListener("dragover", (event) => {
      event.preventDefault();
      event.dataTransfer.dropEffect = "move";
      table.querySelectorAll("th.column-drop-target").forEach((item) => item.classList.remove("column-drop-target"));
      header.classList.add("column-drop-target");
    });
    header.addEventListener("drop", async (event) => {
      event.preventDefault();
      const sourceKey = event.dataTransfer.getData("text/plain");
      table.querySelectorAll("th").forEach((item) => item.classList.remove("dragging-column", "column-drop-target"));
      if (!sourceKey || sourceKey === key) return;
      const ok = await confirmAction({
        title: "Alterar ordem das colunas?",
        message: `Mover ${labels[sourceKey] || sourceKey} para antes de ${labels[key] || key}? Essa ordem ficara salva nesta listagem.`,
        confirmText: "Salvar ordem"
      });
      if (!ok) return;
      if (saveTableColumnOrder(tableColumns, sourceKey, key, options)) {
        toast("Ordem das colunas salva.");
        render();
      }
    });
    if (key !== "actions") {
      header.addEventListener("click", (event) => {
        if (event.target.closest("button, .column-resizer")) return;
        const currentKey = table.dataset.sortColumn;
        const direction = currentKey === key && table.dataset.sortDirection === "asc" ? "desc" : "asc";
        table.dataset.sortColumn = key;
        table.dataset.sortDirection = direction;
        sortTableByColumn(table, index, direction);
        setTableSortHeader(table, header, direction);
      });
    }
  });
  children.push(table);
  const wrap = el("div", { class: `card table-wrap system-table-wrap modern-list-shell ${options.wrapClass || ""}`.trim() }, children);
  const fullscreenToolbar = el("div", { class: "table-toolbar" }, [
    el("div", { class: "table-toolbar-left" }, [
      el("label", { class: "table-search-wrap" }, [
        el("span", {}, ["Buscar"]),
        tableSearchInput
      ]),
      el("button", { class: "secondary-button table-filter-button", type: "button", title: "Filtros avancados" }, ["Filtros"])
    ]),
    el("div", { class: "table-toolbar-right" }, [
      tableSummary = el("span", { class: "table-summary" }, [""]),
      el("label", { class: "table-page-size-wrap" }, [el("span", {}, ["Itens por pagina"]), pageSizeSelect]),
      el("button", {
        class: "secondary-button table-fullscreen-button",
        type: "button",
        title: "Ver esta lista em tela cheia",
        "aria-pressed": "false",
        onclick: () => toggleTableFullscreen(wrap)
      }, ["Tela cheia"])
    ])
  ]);
  paginationButtons = el("div", { class: "pagination-buttons table-pagination-buttons" }, []);
  tableSummaryFooter = el("span", { class: "table-summary" }, [""]);
  const pagination = el("div", { class: "modern-pagination" }, [tableSummaryFooter, paginationButtons]);
  wrap.classList.add("has-table-toolbar");
  wrap.prepend(fullscreenToolbar);
  wrap.append(pagination);
  table.__applyTableView();
  table.addEventListener("click", (event) => {
    if (event.target.closest("button, a, input, select, textarea, label")) return;
    const row = event.target.closest("tbody tr");
    if (!row) return;
    const selected = row.classList.contains("selected-table-row");
    table.querySelectorAll("tbody tr.selected-table-row").forEach((item) => item.classList.remove("selected-table-row"));
    if (!selected) row.classList.add("selected-table-row");
  });
  enhanceTableActions(wrap);
  return wrap;
}

function renderNav() {
  const nav = document.querySelector("#nav");
  renderDashboardReferenceNav(nav);
  return;
  const personalChildSectionIds = personalMenuSectionIds.filter((id) => id !== "personal");
  const mainSections = sections.filter((section) => !settingsMenuSectionIds.includes(section.id) && !gamesMenuSectionIds.includes(section.id) && !financeMenuSectionIds.includes(section.id) && !goodsServicesMenuSectionIds.includes(section.id) && !personalChildSectionIds.includes(section.id));
  const financeChildren = [
    ...financeMenuSectionIds.map((id) => sections.find((section) => section.id === id)).filter(Boolean),
    financeCreditMenuItem
  ];
  const financeOpen = Boolean(state.financeMenuOpen);
  const goodsServicesChildren = goodsServicesMenuSectionIds.map((id) => sections.find((section) => section.id === id)).filter(Boolean);
  const goodsServicesOpen = Boolean(state.goodsServicesMenuOpen);
  const gamesChildren = gamesMenuSectionIds.map((id) => sections.find((section) => section.id === id)).filter(Boolean);
  const gamesOpen = Boolean(state.gamesMenuOpen);
  const personalChildren = personalMenuSectionIds.map((id) => sections.find((section) => section.id === id)).filter(Boolean);
  const personalOpen = Boolean(state.personalMenuOpen);
  const settingsChildren = ["settings", ...settingsMenuSectionIds].map((id) => sections.find((section) => section.id === id)).filter(Boolean);
  const settingsOpen = Boolean(state.settingsMenuOpen);
  const nodes = [];
  for (const section of mainSections) {
    if (section.id === "agenda") {
      nodes.push(el("button", {
        class: `nav-button nav-group-button ${financeOpen ? "active" : ""}`,
        type: "button",
        onclick: () => {
          toggleNavMenu("financeMenuOpen", financeOpen);
        }
      }, [el("span", { class: "nav-icon" }, [String.fromCodePoint(0x1F4B0)]), el("span", { class: "nav-label" }, ["Financeiro"]), el("span", { class: `nav-chevron ${financeOpen ? "open" : ""}` }, ["›"])]));
      if (financeOpen) {
        nodes.push(el("div", { class: "nav-submenu" }, financeChildren.map((child) => {
          const childActive = child.financeTab
            ? state.section === child.section && state.financeTab === child.financeTab
            : child.id === state.section && !(child.id === "finance" && state.financeTab === "creditCards");
          return el("button", {
            class: `nav-button nav-subbutton ${childActive ? "active" : ""}`,
            "data-section": child.section || child.id,
            onclick: () => {
              state.financeMenuOpen = true;
              if (child.financeTab) state.financeTab = child.financeTab;
              else if (child.id === "finance" && state.financeTab === "creditCards") state.financeTab = "dashboard";
              setSection(child.section || child.id);
            }
          }, [el("span", { class: "nav-icon" }, [child.icon]), el("span", {}, [child.title])]);
        })));
      }
    }
    if (section.id === "documents") {
      nodes.push(el("button", {
        class: `nav-button nav-group-button ${gamesOpen ? "active" : ""}`,
        type: "button",
        onclick: () => {
          toggleNavMenu("gamesMenuOpen", gamesOpen);
        }
      }, [el("span", { class: "nav-icon" }, [String.fromCodePoint(0x1F3AE)]), el("span", { class: "nav-label" }, ["Games"]), el("span", { class: `nav-chevron ${gamesOpen ? "open" : ""}` }, ["›"])]));
      if (gamesOpen) {
        nodes.push(el("div", { class: "nav-submenu" }, gamesChildren.map((child) => el("button", {
          class: `nav-button nav-subbutton ${child.id === state.section ? "active" : ""}`,
          "data-section": child.id,
          onclick: () => {
            state.gamesMenuOpen = true;
            setSection(child.id);
          }
        }, [el("span", { class: `nav-icon ${child.iconClass || ""}`.trim() }, [child.icon || ""]), el("span", {}, [child.title])]))));
      }
    }
    if (section.id === "personal") {
      nodes.push(el("button", {
        class: `nav-button nav-group-button ${goodsServicesOpen ? "active" : ""}`,
        type: "button",
        onclick: () => {
          toggleNavMenu("goodsServicesMenuOpen", goodsServicesOpen);
        }
      }, [el("span", { class: "nav-icon" }, [String.fromCodePoint(0x1F4E6)]), el("span", { class: "nav-label" }, ["Bens & Serviços"]), el("span", { class: `nav-chevron ${goodsServicesOpen ? "open" : ""}` }, ["›"])]));
      if (goodsServicesOpen) {
        nodes.push(el("div", { class: "nav-submenu" }, goodsServicesChildren.map((child) => el("button", {
          class: `nav-button nav-subbutton ${child.id === state.section ? "active" : ""}`,
          "data-section": child.id,
          onclick: () => {
            state.goodsServicesMenuOpen = true;
            setSection(child.id);
          }
        }, [el("span", { class: `nav-icon ${child.iconClass || ""}`.trim() }, [child.icon || ""]), el("span", {}, [child.title])]))));
      }
      nodes.push(el("button", {
        class: `nav-button nav-group-button ${personalOpen ? "active" : ""}`,
        type: "button",
        onclick: () => {
          toggleNavMenu("personalMenuOpen", personalOpen);
        }
      }, [el("span", { class: "nav-icon" }, [section.icon]), el("span", { class: "nav-label" }, [section.menuTitle || section.title]), el("span", { class: `nav-chevron ${personalOpen ? "open" : ""}` }, ["›"])]));
      if (personalOpen) {
        nodes.push(el("div", { class: "nav-submenu" }, personalChildren.map((child) => el("button", {
          class: `nav-button nav-subbutton ${child.id === state.section ? "active" : ""}`,
          "data-section": child.id,
          onclick: () => {
            state.personalMenuOpen = true;
            setSection(child.id);
          }
        }, [el("span", { class: `nav-icon ${child.iconClass || ""}`.trim() }, [child.icon || ""]), el("span", {}, [child.title])]))));
      }
      nodes.push(el("button", {
        class: `nav-button nav-group-button ${gamesOpen ? "active" : ""}`,
        type: "button",
        onclick: () => {
          toggleNavMenu("gamesMenuOpen", gamesOpen);
        }
      }, [el("span", { class: "nav-icon" }, [String.fromCodePoint(0x1F3AE)]), el("span", { class: "nav-label" }, ["Games"]), el("span", { class: `nav-chevron ${gamesOpen ? "open" : ""}` }, ["›"])]));
      if (gamesOpen) {
        nodes.push(el("div", { class: "nav-submenu" }, gamesChildren.map((child) => el("button", {
          class: `nav-button nav-subbutton ${child.id === state.section ? "active" : ""}`,
          "data-section": child.id,
          onclick: () => {
            state.gamesMenuOpen = true;
            setSection(child.id);
          }
        }, [el("span", { class: "nav-icon" }, [child.icon]), el("span", {}, [child.title])]))));
      }
      continue;
    }
    if (section.id === "settings") {
      nodes.push(el("button", {
        class: `nav-button nav-group-button ${settingsOpen ? "active" : ""}`,
        type: "button",
        onclick: () => {
          toggleNavMenu("settingsMenuOpen", settingsOpen);
        }
      }, [
        el("span", { class: "nav-icon" }, [section.icon]),
        el("span", { class: "nav-label" }, [section.title]),
        el("span", { class: `nav-chevron ${settingsOpen ? "open" : ""}` }, ["›"])
      ]));
    } else {
      nodes.push(el("button", {
        class: `nav-button ${section.id === state.section ? "active" : ""}`.trim(),
        "data-section": section.id,
        onclick: () => setSection(section.id)
      }, [el("span", { class: "nav-icon" }, [section.icon]), el("span", { class: "nav-label" }, [section.title])]));
    }
    if (section.id === "settings" && settingsOpen) {
      nodes.push(el("div", { class: "nav-submenu" }, settingsChildren.map((child) => el("button", {
        class: `nav-button nav-subbutton ${child.id === state.section ? "active" : ""}`,
        "data-section": child.id,
        onclick: () => {
          state.settingsMenuOpen = true;
          setSection(child.id);
        }
      }, [el("span", { class: "nav-icon" }, [child.icon]), el("span", {}, [child.title])]))));
    }
  }
  nodes.push(el("div", { class: "sidebar-focus-card" }, [
    el("div", {}, [
      el("strong", {}, ["Foco do dia"]),
      el("span", {}, ["◎"])
    ]),
    el("p", {}, ["Pequenas acoes geram grandes resultados."])
  ]));
  nav.replaceChildren(...nodes);
}

function renderDashboardReferenceNav(nav) {
  const items = navigationConfig.filter((item) => item.id !== "agenda");
  nav.replaceChildren(
    ...items.map((item) => el("button", {
      class: `nav-button dashboard-reference-nav-item ${item.accent || ""} ${item.active.includes(state.section) ? "active" : ""}`.trim(),
      "data-section": item.target,
      "data-tooltip": item.label,
      "aria-label": item.label,
      type: "button",
      onclick: () => setSection(item.target)
    }, [
      el("span", { class: "nav-icon" }, [item.icon]),
      el("span", { class: "nav-label" }, [item.label]),
      el("span", { class: "nav-tooltip", role: "tooltip" }, [item.label])
    ].filter(Boolean))),
    el("div", { class: "sidebar-focus-card" }, [
      el("div", {}, [
        el("strong", {}, ["Foco do dia"]),
        el("span", {}, ["◎"])
      ]),
      el("p", {}, ["Pequenas ações geram grandes resultados."])
    ])
  );
}

function activeNavigationModule() {
  return navigationConfig.find((item) => item.active.includes(state.section)) || navigationConfig[0];
}

function isDockItemActive(item) {
  if (item.stateKey) return state[item.stateKey] === item.id && (!item.target || item.target === state.section);
  if (item.target) return item.target === state.section;
  return activeNavigationModule().tabs?.[0] === item;
}

function applyDockItem(item) {
  if (item.stateKey) state[item.stateKey] = item.id;
  const target = item.target || activeNavigationModule().target;
  if (target && target !== state.section) return setSection(target);
  render();
  renderContextDock();
}

function renderContextDock() {
  const dock = document.querySelector("#context-dock");
  if (!dock) return;
  const module = activeNavigationModule();
  const items = module.tabs || [];
  dock.classList.toggle("hidden", !items.length);
  dock.replaceChildren(...items.map((item) => el("button", {
    class: `context-dock-item ${isDockItemActive(item) ? "active" : ""}`.trim(),
    type: "button",
    title: item.label,
    "aria-label": item.label,
    onclick: () => applyDockItem(item)
  }, [
    el("span", {}, [item.icon || "•"]),
    el("strong", {}, [item.label])
  ])));
}

function stat(label, value, tone = "") {
  const normalized = String(label || "").toLowerCase();
  const icon = normalized.includes("pago") || normalized.includes("resolvido") ? "\u2713"
    : normalized.includes("guardado") || normalized.includes("sobra") ? "\u2191"
      : normalized.includes("pendente") ? "!"
        : normalized.includes("atrasado") || normalized.includes("preju") ? "\u2193"
          : normalized.includes("itens") || normalized.includes("total") ? "\u03a3"
            : "\u2022";
  const visualTone = tone || (normalized.includes("pendente") ? "warn" : normalized.includes("atrasado") ? "negative" : normalized.includes("pago") || normalized.includes("sobra") ? "positive" : "");
  return el("div", { class: `card stat-card ${visualTone}`.trim() }, [el("div", { class: "card-body" }, [
    el("div", { class: "stat-card-head" }, [
      el("span", { class: "muted" }, [label]),
      el("span", { class: "stat-card-icon", "aria-hidden": "true" }, [icon])
    ]),
    el("p", { class: `stat-value ${visualTone}`.trim() }, [value])
  ])]);
}

function topbarClock() {
  const time = document.querySelector("#topbar-clock-time");
  const date = document.querySelector("#topbar-clock-date");
  const seconds = document.querySelector("#topbar-clock-seconds");
  if (!time || !date) return null;
  const update = () => {
    const now = new Date();
    const use24Hours = TimeCenter.settings?.format24h !== false;
    time.textContent = now.toLocaleTimeString("pt-BR", { hour: "2-digit", minute: "2-digit", hour12: !use24Hours });
    if (seconds) seconds.textContent = now.toLocaleTimeString("pt-BR", { second: "2-digit" }).slice(-2);
    const weekday = now.toLocaleDateString("pt-BR", { weekday: "long" });
    const month = now.toLocaleDateString("pt-BR", { month: "long" });
    const capitalize = (value) => value.charAt(0).toUpperCase() + value.slice(1);
    date.textContent = `${capitalize(weekday)}, ${String(now.getDate()).padStart(2, "0")} de ${capitalize(month)}`;
  };
  update();
  const timer = setInterval(() => {
    if (!time.isConnected || !date.isConnected) return clearInterval(timer);
    update();
  }, 1000);
  return timer;
}

function currentProfile() {
  return authState.user || {};
}

function displayUserName() {
  const user = currentProfile();
  return String(user.name || user.first_name || "Dauan").trim() || "Dauan";
}

function userInitials() {
  return displayUserName().split(/\s+/).slice(0, 2).map((part) => part[0] || "").join("").toUpperCase() || "D";
}

function normalizeAccentColor(value) {
  const color = String(value || "").trim();
  return /^#[0-9a-f]{6}$/i.test(color) ? color.toUpperCase() : "#2563EB";
}

function applyAccentColor(value) {
  const accent = normalizeAccentColor(value);
  const targets = [document.documentElement, document.body].filter(Boolean);
  for (const target of targets) {
    target.style.setProperty("--app-accent", accent);
    target.style.setProperty("--accent", accent);
    target.style.setProperty("--accent-strong", `color-mix(in srgb, ${accent} 76%, #0f172a)`);
    target.style.setProperty("--primary", accent);
    target.style.setProperty("--primary-light", `color-mix(in srgb, ${accent} 12%, #ffffff)`);
    target.style.setProperty("--primary-border", `color-mix(in srgb, ${accent} 38%, #ffffff)`);
    target.style.setProperty("--surface-hover", `color-mix(in srgb, ${accent} 10%, #ffffff)`);
    target.style.setProperty("--accent-glow", `0 0 0 1px color-mix(in srgb, ${accent} 22%, transparent), 0 18px 46px color-mix(in srgb, ${accent} 14%, transparent)`);
  }
}

function applyUserShell() {
  const user = currentProfile();
  document.querySelector("#topbar-profile-name")?.replaceChildren(document.createTextNode("Opções"));
  updateProfileAvatarElement(document.querySelector("#topbar-profile-avatar"), user.avatar_url);
  applyAccentColor(user.accent_color);
}

function updateProfileAvatarElement(avatar, avatarUrl, fallback = userInitials()) {
  if (avatar) {
    avatar.replaceChildren();
    avatar.style.backgroundImage = "";
    const image = String(avatarUrl || "").trim();
    if (image) {
      const img = el("img", {
        src: image,
        alt: "",
        onerror: () => updateProfileAvatarElement(avatar, "", fallback)
      });
      avatar.append(img);
      avatar.classList.add("has-image");
    } else {
      avatar.classList.remove("has-image");
      avatar.textContent = fallback;
    }
  }
}

function isLegacyTruncatedAvatar(value) {
  const avatar = String(value || "");
  return avatar.startsWith("data:image/") && avatar.length === 250000;
}

function setAuthenticatedUser(user) {
  authState.user = user || authState.user;
  applyUserShell();
}

async function dashboard() {
  const data = await api("/api/dashboard");
  const view = document.querySelector("#view");
  const upcoming = [
    ...(data.upcomingPlanning || []).map((item) => ({ ...item, kind: "Conta", date: item.due_date, label: item.title, section: "planning" })),
    ...(data.upcomingDocuments || []).map((item) => ({ ...item, kind: "Documento", date: item.due_date, label: item.name, section: "documents" })),
    ...(data.agendaEvents || []).map((item) => ({ ...item, kind: item.source === "google" ? "Google Agenda" : "Agenda", date: item.start_at, label: item.title, section: "agenda" }))
  ].filter((item) => item.date).sort((a, b) => String(a.date).localeCompare(String(b.date))).slice(0, 6);
  view.replaceChildren(
    el("div", { class: "dashboard-os dashboard-v2" }, [
      dashboardV2Hero(data, upcoming),
      dashboardOsSummary(data),
      el("section", { class: "dashboard-v2-main-grid" }, [
        dashboardQuickAccess(),
        dashboardUpcomingCard(upcoming),
        dashboardRecentActivityCard(data.latest || [])
      ]),
      el("section", { class: "dashboard-v2-lower-grid" }, [
        dashboardFinanceCard(data.finance || {}),
        dashboardQuickNotesCard(data.recentIdeas || []),
        dashboardNowPlayingCard()
      ]),
      dashboardInsightsCard()
    ])
  );
}

