function dashboardChartCard(module, title, rows, type) {
  const max = Math.max(1, ...rows.map((row) => Math.abs(Number(row.value || 0))));
  if (type === "donut") {
    const total = rows.reduce((sum, row) => sum + Math.abs(Number(row.value || 0)), 0) || 1;
    const first = Math.round((Math.abs(Number(rows[0]?.value || 0)) / total) * 100);
    return el("article", { class: "dashboard-chart-card donut" }, [
      el("div", { class: "dashboard-chart-head" }, [el("span", {}, [module]), el("strong", {}, [title])]),
      el("div", { class: "dashboard-donut-wrap" }, [
        el("div", { class: "dashboard-donut", style: `--donut:${first}%` }, [el("span", {}, [`${first}%`])]),
        el("div", { class: "dashboard-donut-legend" }, rows.map((row) => el("div", { class: row.tone || "" }, [
          el("span", {}, [row.label]),
          el("strong", {}, [row.display || money(row.value || 0)])
        ])))
      ])
    ]);
  }
  return el("article", { class: `dashboard-chart-card ${type}` }, [
    el("div", { class: "dashboard-chart-head" }, [el("span", {}, [module]), el("strong", {}, [title])]),
    el("div", { class: "dashboard-chart-bars" }, rows.map((row) => el("div", { class: row.tone || "" }, [
      el("span", {}, [row.label]),
      el("i", { style: `--bar:${Math.max(6, Math.round((Math.abs(Number(row.value || 0)) / max) * 100))}%` }),
      el("b", {}, [row.display || money(row.value || 0)])
    ])))
  ]);
}

