function queueGlobalSearch(container, query, delay = 180) {
  if (globalSearchTimer) clearTimeout(globalSearchTimer);
  if (!query) {
    container.classList.add("hidden");
    container.replaceChildren();
    return;
  }
  container.classList.remove("hidden");
  container.replaceChildren(el("p", { class: "muted" }, ["Procurando no sistema inteiro..."]));
  globalSearchTimer = setTimeout(() => renderGlobalSearchResults(container, query), delay);
}

async function renderGlobalSearchResults(container, query) {
  const requestId = ++globalSearchRequestId;
  try {
    const data = await api(`/api/search?q=${encodeURIComponent(query)}`);
    if (requestId !== globalSearchRequestId) return;
    const found = data.results || [];
    container.classList.remove("hidden");
    container.replaceChildren(
      found.length ? el("div", {}, found.map((row) => el("button", {
      type: "button",
      onclick: () => openGlobalSearchResult(row)
    }, [
      el("span", {}, [row.module]),
      el("strong", {}, [row.title || "Resultado"]),
      el("small", {}, [row.detail || "Abrir modulo"]),
      el("em", {}, [row.snippet || "Clique para abrir"])
    ]))) : el("p", { class: "muted" }, [`Nenhum resultado para "${query}".`])
    );
  } catch (error) {
    if (requestId !== globalSearchRequestId) return;
    container.classList.remove("hidden");
    container.replaceChildren(el("p", { class: "muted" }, [error.message || "Nao foi possivel buscar agora."]));
  }
}

function openGlobalSearchResult(row) {
  if (row.section === "notes" && row.id) {
    state.notesTab = "active";
    state.notesFilters = { ...state.notesFilters, id: `#${row.id}` };
  }
  if (row.section === "finance") state.financeTab = "dashboard";
  setSection(row.section || "dashboard");
}

function setupTopbarGlobalSearch() {
  const input = document.querySelector("#global-search-input");
  const results = document.querySelector("#global-search-results");
  const clearButton = document.querySelector("#global-search-clear");
  if (!input || !results) return;
  input.addEventListener("input", () => queueGlobalSearch(results, input.value.trim()));
  input.addEventListener("focus", () => {
    if (!input.value.trim()) {
      results.classList.remove("hidden");
      results.replaceChildren(el("p", { class: "muted" }, ["Digite para pesquisar no sistema."]));
    } else {
      queueGlobalSearch(results, input.value.trim(), 0);
    }
  });
  clearButton?.addEventListener("click", () => {
    input.value = "";
    results.classList.add("hidden");
    results.replaceChildren();
    input.focus();
  });
  document.addEventListener("keydown", (event) => {
    if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "k") {
      event.preventDefault();
      input.focus();
      input.select();
    }
    if (event.key === "Escape" && document.activeElement === input) {
      input.blur();
      results.classList.add("hidden");
    }
  });
  document.addEventListener("click", (event) => {
    if (!event.target.closest(".topbar-global-search")) results.classList.add("hidden");
  });
}

