const LIFE_STATUS = [
  { id: "not_started", title: "Nao Iniciado", hint: "Ideias e objetivos ainda parados" },
  { id: "in_progress", title: "Em Andamento", hint: "O que ja esta em movimento" },
  { id: "done", title: "Concluido", hint: "Conquistas finalizadas" }
];
const LIFE_CATEGORIES = ["Pessoal", "Financeiro", "Carreira", "Estudos", "Saude", "Viagens", "Casa", "Moto/Veiculo", "Documentos", "Sonhos", "Projetos", "Outros"];
const LIFE_PRIORITIES = ["Baixa", "Media", "Alta", "Muito Alta"];

function lifeStatusLabel(status) {
  return LIFE_STATUS.find((item) => item.id === status)?.title || status;
}

function lifePriorityClass(priority) {
  return `priority-${normalizeSearch(priority || "Media").replace(/\s+/g, "-")}`;
}

function filteredLifeObjectives(items) {
  const filters = state.lifeKanbanFilters;
  const search = normalizeSearch(filters.search);
  return items.filter((item) => {
    const text = normalizeSearch([item.title, item.short_description, item.reason, item.notes, item.current_action].join(" "));
    if (search && !text.includes(search)) return false;
    if (filters.category && item.category !== filters.category) return false;
    if (filters.priority && item.priority !== filters.priority) return false;
    if (filters.status && item.status !== filters.status) return false;
    if (filters.due === "overdue" && (!item.target_date || item.target_date >= today() || item.status === "done")) return false;
    if (filters.due === "month" && (!item.target_date || item.target_date.slice(0, 7) !== currentMonth())) return false;
    return true;
  });
}

function lifeSummaryPanel(summary) {
  return el("section", { class: "life-summary" }, [
    stat("Total de objetivos", String(summary.total || 0), "saved"),
    stat("Nao iniciados", String(summary.not_started || 0), "warn"),
    stat("Em andamento", String(summary.in_progress || 0), "blue"),
    stat("Concluidos", String(summary.done || 0), "positive"),
    el("article", { class: "card stat-card positive" }, [el("div", { class: "card-body" }, [
      el("div", { class: "stat-card-head" }, [el("span", { class: "muted" }, ["Conclusao geral"]), el("span", { class: "stat-card-icon" }, ["%"])]),
      el("p", { class: "stat-value positive" }, [`${summary.progress || 0}%`]),
      el("div", { class: "life-progress-track" }, [el("span", { style: `width:${Math.min(100, Number(summary.progress || 0))}%` })])
    ])]),
    el("article", { class: "card stat-card" }, [el("div", { class: "card-body" }, [
      el("div", { class: "stat-card-head" }, [el("span", { class: "muted" }, ["Ultima conquista"]), el("span", { class: "stat-card-icon" }, ["✓"])]),
      el("p", { class: "life-latest-win" }, [summary.latest_done?.title || "Nada concluido ainda"])
    ])])
  ]);
}

function lifeFiltersBar() {
  const filters = state.lifeKanbanFilters;
  const setFilter = (key, value) => {
    state.lifeKanbanFilters = { ...state.lifeKanbanFilters, [key]: value };
    renderLifeKanban();
  };
  return el("section", { class: "card life-toolbar" }, [
    el("div", { class: "field" }, [el("label", {}, ["Busca"]), el("input", { value: filters.search, placeholder: "titulo ou descricao", oninput: (event) => setFilter("search", event.currentTarget.value) })]),
    el("div", { class: "field" }, [el("label", {}, ["Categoria"]), inputFor({ name: "category", type: "select", options: [{ value: "", label: "Todas" }, ...LIFE_CATEGORIES.map((value) => ({ value, label: value }))] }, filters.category)]),
    el("div", { class: "field" }, [el("label", {}, ["Prioridade"]), inputFor({ name: "priority", type: "select", options: [{ value: "", label: "Todas" }, ...LIFE_PRIORITIES.map((value) => ({ value, label: value }))] }, filters.priority)]),
    el("div", { class: "field" }, [el("label", {}, ["Status"]), inputFor({ name: "status", type: "select", options: [{ value: "", label: "Todos" }, ...LIFE_STATUS.map((item) => ({ value: item.id, label: item.title }))] }, filters.status)]),
    el("div", { class: "field" }, [el("label", {}, ["Prazo"]), inputFor({ name: "due", type: "select", options: [{ value: "", label: "Todos" }, { value: "month", label: "Este mes" }, { value: "overdue", label: "Atrasados" }] }, filters.due)]),
    el("button", { class: "primary-button", type: "button", onclick: () => openLifeObjectiveModal() }, ["Novo objetivo"])
  ]);
}

function bindLifeFilters(view) {
  view.querySelector('.life-toolbar [name="category"]')?.addEventListener("change", (event) => { state.lifeKanbanFilters.category = event.currentTarget.value; renderLifeKanban(); });
  view.querySelector('.life-toolbar [name="priority"]')?.addEventListener("change", (event) => { state.lifeKanbanFilters.priority = event.currentTarget.value; renderLifeKanban(); });
  view.querySelector('.life-toolbar [name="status"]')?.addEventListener("change", (event) => { state.lifeKanbanFilters.status = event.currentTarget.value; renderLifeKanban(); });
  view.querySelector('.life-toolbar [name="due"]')?.addEventListener("change", (event) => { state.lifeKanbanFilters.due = event.currentTarget.value; renderLifeKanban(); });
}

function lifeCard(item) {
  const done = item.status === "done";
  const stepProgress = item.steps_total ? Math.round((Number(item.steps_done || 0) / Number(item.steps_total || 1)) * 100) : 0;
  return el("article", {
    class: `life-card ${done ? "done" : ""} ${lifePriorityClass(item.priority)}`,
    draggable: "true",
    "data-id": item.id,
    onclick: (event) => event.currentTarget.classList.toggle("selected"),
    ondblclick: () => openLifeObjectiveDetail(item.id),
    ondragstart: (event) => {
      event.dataTransfer.setData("text/plain", String(item.id));
      event.currentTarget.classList.add("dragging");
    },
    ondragend: (event) => event.currentTarget.classList.remove("dragging"),
    ondragover: (event) => event.preventDefault(),
    ondrop: async (event) => {
      event.preventDefault();
      event.stopPropagation();
      const draggedId = Number(event.dataTransfer.getData("text/plain"));
      if (!draggedId || draggedId === item.id) return;
      await moveLifeCard(draggedId, item.status, item.id);
    }
  }, [
    el("div", { class: "life-card-title" }, [
      el("span", { class: `life-status-dot ${done ? "filled" : ""}`, title: done ? "Concluido" : "Nao concluido" }),
      el("strong", {}, [item.title])
    ]),
    item.short_description ? el("p", {}, [item.short_description]) : el("p", { class: "muted" }, ["Sem descricao curta"]),
    el("div", { class: "life-card-meta" }, [
      el("span", {}, [item.category || "Pessoal"]),
      el("span", {}, [item.priority || "Media"]),
      item.target_date ? el("span", {}, [`Meta: ${formatDateBR(item.target_date)}`]) : el("span", {}, ["Sem prazo"])
    ]),
    done ? el("span", { class: "life-done-badge" }, [`Concluido${item.completed_date ? ` em ${formatDateBR(item.completed_date)}` : ""}`]) : el("span"),
    el("div", { class: "life-subgoal-progress" }, [
      el("div", {}, [
        el("small", {}, [item.steps_total ? `Subobjetivos ${item.steps_done || 0}/${item.steps_total}` : "Sem subobjetivos"]),
        item.steps_total ? el("small", {}, [`${stepProgress}%`]) : el("small")
      ]),
      el("span", {}, [el("i", { style: `width:${stepProgress}%` })])
    ])
  ]);
}

function lifeColumn(column, items) {
  const collapsed = Boolean(state.lifeCollapsedColumns?.[column.id]);
  return el("section", {
    class: `life-column ${column.id} ${collapsed ? "collapsed" : ""}`.trim(),
    "data-status": column.id,
    ondragover: (event) => {
      event.preventDefault();
      if (collapsed) return;
      event.currentTarget.classList.add("drag-over");
    },
    ondragleave: (event) => event.currentTarget.classList.remove("drag-over"),
    ondrop: async (event) => {
      event.preventDefault();
      event.currentTarget.classList.remove("drag-over");
      const id = Number(event.dataTransfer.getData("text/plain"));
      if (!id) return;
      await moveLifeCard(id, column.id);
    }
  }, [
    el("header", {}, [
      el("button", {
        class: "life-column-toggle",
        type: "button",
        title: collapsed ? `Mostrar ${column.title}` : `Esconder ${column.title}`,
        onclick: () => {
          state.lifeCollapsedColumns = { ...(state.lifeCollapsedColumns || {}), [column.id]: !collapsed };
          renderLifeKanban();
        }
      }, [
        el("span", { class: "life-column-chevron" }, [collapsed ? "+" : "-"]),
        el("span", {}, [el("h2", {}, [column.title]), el("p", { class: "muted" }, [column.hint])])
      ]),
      el("span", { class: "life-column-count" }, [String(items.length)])
    ]),
    collapsed
      ? el("button", { class: "life-column-collapsed-note", type: "button", onclick: () => { state.lifeCollapsedColumns = { ...(state.lifeCollapsedColumns || {}), [column.id]: false }; renderLifeKanban(); } }, [`${items.length} objetivo(s) escondido(s)`])
      : el("div", { class: "life-column-cards" }, items.length ? items.map(lifeCard) : [el("div", { class: "life-empty-column" }, ["Nenhum objetivo aqui."])])
  ]);
}

async function moveLifeCard(id, status, beforeId = null) {
  const data = await api("/api/life-kanban");
  const current = data.items.find((item) => item.id === id);
  if (!current) return;
  const nextItems = data.items.map((item) => ({ id: item.id, status: item.id === id ? status : item.status, column_order: item.column_order }));
  const columnItems = nextItems
    .filter((item) => item.status === status && item.id !== id)
    .sort((a, b) => Number(a.column_order || 0) - Number(b.column_order || 0));
  const moved = { id, status, column_order: 0 };
  const targetIndex = beforeId ? Math.max(0, columnItems.findIndex((item) => item.id === beforeId)) : columnItems.length;
  columnItems.splice(targetIndex < 0 ? columnItems.length : targetIndex, 0, moved);
  columnItems.forEach((item, index) => { item.column_order = (index + 1) * 1000; });
  const payload = nextItems.map((item) => columnItems.find((columnItem) => columnItem.id === item.id) || item);
  await api("/api/life-kanban/reorder", { method: "POST", body: JSON.stringify({ items: payload }) });
  toast(status === "done" ? "Objetivo concluido." : "Objetivo movido.");
  renderLifeKanban();
}

function lifeObjectiveForm(record = {}) {
  const form = el("form", { class: "life-objective-form form-grid" }, [
    el("div", { class: "field full" }, [el("label", {}, ["Titulo do objetivo"]), inputFor({ name: "title", required: true }, record.title || "")]),
    el("div", { class: "field full" }, [el("label", {}, ["Descricao curta"]), inputFor({ name: "short_description", type: "textarea" }, record.short_description || "")]),
    el("div", { class: "field" }, [el("label", {}, ["Categoria"]), inputFor({ name: "category", type: "select", options: LIFE_CATEGORIES }, record.category || "Pessoal")]),
    el("div", { class: "field" }, [el("label", {}, ["Prioridade"]), inputFor({ name: "priority", type: "select", options: LIFE_PRIORITIES }, record.priority || "Media")]),
    el("div", { class: "field" }, [el("label", {}, ["Status"]), inputFor({ name: "status", type: "select", options: LIFE_STATUS.map((item) => ({ value: item.id, label: item.title })) }, record.status || "not_started")]),
    el("div", { class: "field" }, [el("label", {}, ["Prazo/meta"]), inputFor({ name: "target_date", type: "date" }, record.target_date || "")]),
    el("div", { class: "field full" }, [el("label", {}, ["Motivo do objetivo"]), inputFor({ name: "reason", type: "textarea" }, record.reason || "")]),
    el("div", { class: "field full" }, [el("label", {}, ["O que estou fazendo atualmente"]), inputFor({ name: "current_action", type: "textarea" }, record.current_action || "")]),
    el("div", { class: "field full" }, [el("label", {}, ["Proximos passos / observacoes"]), inputFor({ name: "notes", type: "textarea" }, record.notes || "")]),
    el("div", { class: "field full" }, [el("label", {}, ["Links uteis"]), inputFor({ name: "useful_links", type: "textarea" }, record.useful_links || "")]),
    el("div", { class: "form-actions full" }, [
      el("button", { class: "primary-button" }, [record.id ? "Salvar objetivo" : "Criar objetivo"]),
      record.id ? el("button", { class: "danger-button", type: "button", onclick: async () => {
        if (!(await confirmAction({ title: "Excluir objetivo?", message: record.title, confirmText: "Excluir", danger: true }))) return;
        await api(`/api/life-kanban/${record.id}`, { method: "DELETE" });
        closeLifeModal();
        toast("Objetivo excluido.");
        renderLifeKanban();
      } }, ["Excluir"]) : el("span")
    ])
  ]);
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = Object.fromEntries(new FormData(form).entries());
    const url = record.id ? `/api/life-kanban/${record.id}` : "/api/life-kanban";
    const method = record.id ? "PUT" : "POST";
    try {
      await api(url, { method, body: JSON.stringify(payload) });
      closeLifeModal();
      toast(record.id ? "Objetivo salvo." : "Objetivo criado.");
      renderLifeKanban();
    } catch (error) {
      toast(error.message);
    }
  });
  return form;
}

function closeLifeModal() {
  document.querySelector(".life-modal-backdrop")?.remove();
  document.body.classList.remove("modal-open");
}

function openLifeObjectiveModal(record = {}) {
  closeLifeModal();
  const overlay = el("div", { class: "confirm-modal-backdrop life-modal-backdrop", onclick: closeLifeModal }, [
    el("article", { class: "confirm-modal life-modal", onclick: (event) => event.stopPropagation() }, [
      el("div", { class: "life-modal-head" }, [
        el("div", {}, [el("span", { class: "mini-badge" }, ["Kanban da Vida"]), el("h2", {}, [record.id ? "Editar objetivo" : "Novo objetivo"])]),
        el("button", { class: "icon-button", type: "button", onclick: closeLifeModal }, ["x"])
      ]),
      lifeObjectiveForm(record)
    ])
  ]);
  document.body.append(overlay);
  document.body.classList.add("modal-open");
}

function lifeObjectiveOverview(item) {
  const steps = item.steps || [];
  const doneCount = steps.filter((step) => step.completed).length;
  const progress = steps.length ? Math.round((doneCount / steps.length) * 100) : 0;
  return el("section", { class: "life-detail-overview" }, [
    el("div", { class: "life-detail-progress-card" }, [
      el("div", {}, [
        el("span", { class: "mini-badge" }, [lifeStatusLabel(item.status)]),
        el("h3", {}, ["Progresso dos subobjetivos"]),
        el("p", { class: "muted" }, [steps.length ? `${doneCount} de ${steps.length} passos concluidos` : "Adicione pequenos passos para acompanhar esse projeto."])
      ]),
      el("strong", {}, [`${progress}%`]),
      el("div", { class: "life-progress-track" }, [el("span", { style: `width:${progress}%` })])
    ]),
    el("div", { class: "life-detail-tags" }, [item.category, item.priority, item.target_date ? `Prazo ${formatDateBR(item.target_date)}` : "Sem prazo"].map((text) => el("span", {}, [text]))),
    el("div", { class: "life-detail-copy" }, [
      lifeTextBlock("Resumo", item.short_description || "Sem descricao."),
      lifeTextBlock("Motivo", item.reason || "Nao informado."),
      lifeTextBlock("Estou fazendo agora", item.current_action || "Nada registrado ainda."),
      lifeTextBlock("Observacoes", item.notes || "Sem observacoes."),
      item.useful_links ? lifeTextBlock("Links uteis", item.useful_links, true) : el("span")
    ])
  ]);
}

function lifeTextBlock(title, text, muted = false) {
  return el("article", { class: "life-text-block" }, [
    el("h3", {}, [title]),
    el("p", { class: muted ? "muted" : "" }, [text])
  ]);
}

function lifeStepList(item) {
  const steps = item.steps || [];
  if (!steps.length) return el("div", { class: "life-empty-column" }, ["Nenhum subobjetivo ainda. Adicione o primeiro passo abaixo."]);
  return el("div", { class: "life-steps" }, steps.map((step, index) => el("label", { class: `life-step ${step.completed ? "completed" : ""}`.trim() }, [
    el("span", { class: "life-step-index" }, [String(index + 1).padStart(2, "0")]),
    el("input", { type: "checkbox", checked: step.completed ? "checked" : undefined, onchange: async (event) => {
      await api(`/api/life-kanban/${item.id}/steps/${step.id}`, { method: "PUT", body: JSON.stringify({ completed: event.currentTarget.checked }) });
      openLifeObjectiveDetail(item.id);
    } }),
    el("span", { class: "life-step-check" }, [step.completed ? "✓" : ""]),
    el("span", { class: "life-step-title" }, [step.title]),
    el("button", { type: "button", class: "icon-button", onclick: async (event) => {
      event.preventDefault();
      await api(`/api/life-kanban/${item.id}/steps/${step.id}`, { method: "DELETE" });
      openLifeObjectiveDetail(item.id);
    } }, ["x"])
  ])));
}

function lifeProjectLogs(item) {
  const logs = [...(item.history || [])].sort((a, b) => String(b.created_at || "").localeCompare(String(a.created_at || "")));
  const pageSize = 5;
  const totalPages = Math.max(1, Math.ceil(logs.length / pageSize));
  const page = Math.min(Math.max(Number(state.lifeProjectLogsPage) || 1, 1), totalPages);
  state.lifeProjectLogsPage = page;
  const pageLogs = logs.slice((page - 1) * pageSize, page * pageSize);
  return el("section", { class: `life-project-logs ${state.lifeProjectLogsOpen ? "open" : ""}`.trim() }, [
    el("button", {
      class: "secondary-button life-project-logs-toggle",
      type: "button",
      onclick: () => {
        state.lifeProjectLogsOpen = !state.lifeProjectLogsOpen;
        state.lifeProjectLogsPage = 1;
        openLifeObjectiveDetail(item.id);
      }
    }, [
      el("span", {}, ["Logs do Projeto"]),
      el("small", {}, [logs.length ? `${logs.length} andamento(s)` : "Sem logs"]),
      el("b", {}, [state.lifeProjectLogsOpen ? "-" : "+"])
    ]),
    state.lifeProjectLogsOpen ? el("div", { class: "life-history" }, [
      pageLogs.length ? el("div", { class: "life-history-list" }, pageLogs.map((entry) => el("article", {}, [
        el("strong", {}, [entry.action || "andamento"]),
        el("span", {}, [entry.description || `${entry.previous_status || ""} -> ${entry.new_status || ""}`]),
        el("small", { class: "muted" }, [formatBRDateTime(entry.created_at)])
      ]))) : el("div", { class: "empty" }, ["Nenhum andamento registrado ainda."]),
      lifeProjectLogsPagination(logs.length, pageSize, page, totalPages, item.id)
    ]) : el("span")
  ]);
}

function lifeProjectLogsPagination(totalItems, pageSize, page, totalPages, itemId) {
  if (totalPages <= 1) return el("span", { class: "steam-inventory-page-info" }, [totalItems ? `Mostrando ${totalItems} andamento(s).` : ""]);
  const start = ((page - 1) * pageSize) + 1;
  const end = Math.min(totalItems, page * pageSize);
  return el("div", { class: "steam-inventory-pagination life-logs-pagination" }, [
    el("span", { class: "steam-inventory-page-info" }, [`Mostrando ${start}-${end} de ${totalItems}`]),
    el("div", { class: "pagination-buttons" }, [
      el("button", { class: "pagination-button", type: "button", disabled: page <= 1 ? "disabled" : undefined, onclick: () => { state.lifeProjectLogsPage = page - 1; openLifeObjectiveDetail(itemId); } }, ["<"]),
      el("span", { class: "pagination-gap" }, [`Pagina ${page} de ${totalPages}`]),
      el("button", { class: "pagination-button", type: "button", disabled: page >= totalPages ? "disabled" : undefined, onclick: () => { state.lifeProjectLogsPage = page + 1; openLifeObjectiveDetail(itemId); } }, [">"])
    ])
  ]);
}

async function openLifeObjectiveDetail(id) {
  const item = await api(`/api/life-kanban/${id}`);
  const addStepForm = el("form", { class: "life-step-form" }, [
    el("input", { name: "title", placeholder: "Adicionar subobjetivo..." }),
    el("button", { class: "secondary-button" }, ["Adicionar"])
  ]);
  addStepForm.addEventListener("submit", async (event) => {
    event.preventDefault();
    const title = addStepForm.elements.title.value.trim();
    if (!title) return;
    await api(`/api/life-kanban/${item.id}/steps`, { method: "POST", body: JSON.stringify({ title }) });
    state.lifeProjectLogsPage = 1;
    openLifeObjectiveDetail(item.id);
  });
  const overlay = el("div", { class: "confirm-modal-backdrop life-modal-backdrop", onclick: closeLifeModal }, [
    el("article", { class: "confirm-modal life-modal life-detail-modal", onclick: (event) => event.stopPropagation() }, [
      el("div", { class: "life-modal-head" }, [
        el("div", {}, [el("span", { class: "mini-badge" }, [lifeStatusLabel(item.status)]), el("h2", {}, [item.title])]),
        el("button", { class: "icon-button", type: "button", onclick: closeLifeModal }, ["x"])
      ]),
      el("div", { class: "life-detail-grid" }, [
        lifeObjectiveOverview(item),
        el("section", { class: "life-subgoals-panel" }, [
          el("div", { class: "life-panel-head" }, [
            el("div", {}, [el("h3", {}, ["Subobjetivos"]), el("p", { class: "muted" }, ["Marque os passos pequenos que voce ja realizou."])]),
            el("span", { class: "mini-badge" }, [`${(item.steps || []).filter((step) => step.completed).length}/${(item.steps || []).length || 0}`])
          ]),
          lifeStepList(item),
          addStepForm,
          lifeProjectLogs(item)
        ])
      ]),
      el("div", { class: "form-actions" }, [el("button", { class: "secondary-button", type: "button", onclick: () => openLifeObjectiveModal(item) }, ["Editar"])])
    ])
  ]);
  closeLifeModal();
  document.body.append(overlay);
  document.body.classList.add("modal-open");
}

async function renderLifeKanban() {
  const data = await api("/api/life-kanban");
  const view = document.querySelector("#view");
  const filtered = filteredLifeObjectives(data.items || []);
  view.replaceChildren(
    el("section", { class: "life-hero premium-panel" }, [
      el("div", {}, [el("span", { class: "mini-badge" }, ["Central de Objetivos"]), el("h2", {}, ["Kanban da Vida"]), el("p", { class: "muted" }, ["Organize objetivos, sonhos, projetos e conquistas com movimento real."])]),
      el("button", { class: "primary-button", type: "button", onclick: () => openLifeObjectiveModal() }, ["Novo objetivo"])
    ]),
    lifeSummaryPanel(data.summary || {}),
    lifeFiltersBar(),
    el("section", { class: "life-board" }, LIFE_STATUS.map((column) => lifeColumn(column, filtered.filter((item) => item.status === column.id))))
  );
  bindLifeFilters(view);
}

function greeting() {
  const hour = new Date().getHours();
  if (hour < 6) return "Boa madrugada";
  if (hour < 12) return "Bom dia";
  if (hour < 18) return "Boa tarde";
  return "Boa noite";
}

function dashboardUserName() {
  const name = displayUserName();
  return name.split(/\s+/)[0] || "Dauan";
}

function quickAction(title, description, section, icon) {
  return el("button", { class: "quick-action", onclick: () => setSection(section) }, [
    el("span", { class: "quick-action-icon", "aria-hidden": "true" }, [icon]),
    el("strong", {}, [title]),
    el("span", {}, [description])
  ]);
}

function listCard(title, items, mapper) {
  return el("div", { class: "card" }, [el("div", { class: "card-body" }, [
    el("h2", {}, [title]),
    items.length ? el("div", { class: "stack" }, items.map((item) => el("div", { class: "pill" }, [mapper(item)]))) : el("p", { class: "muted" }, ["Nada cadastrado ainda."])
  ])]);
}

function inputFor(field, value = "", id = field.name) {
  const fieldValue = field.type === "datetime-local" ? toDateTimeLocalValue(value) : value;
  const attrs = { id, name: field.name, value: fieldValue ?? "", required: field.required ? "required" : undefined };
  if (field.type === "file") delete attrs.value;
  if (field.readonly) attrs.readonly = "readonly";
  Object.keys(attrs).forEach((key) => attrs[key] === undefined && delete attrs[key]);
  if (field.type === "select") {
    return el("select", attrs, field.options.map((option) => {
      const value = typeof option === "object" ? option.value : option;
      const label = typeof option === "object" ? option.label : option;
      return el("option", { value, selected: String(value) === String(attrs.value) ? "selected" : undefined }, [label]);
    }));
  }
  if (field.type === "textarea") return el("textarea", attrs, [value ?? ""]);
  const input = el("input", { ...attrs, type: field.type || "text", step: field.step || undefined, inputmode: field.inputMode || undefined });
  if (field.signedMoney) attachSignedBRLMask(input, value ?? 0);
  else if (moneyFieldNames.has(field.name)) attachBRLMask(input, value ?? 0);
  return input;
}

function validateFinancePayload(payload) {
  if (!payload.date) throw new Error("Informe a data e hora do lancamento.");
  if (!payload.account_id) throw new Error("Selecione a conta origem.");
  if (!String(payload.description || "").trim()) throw new Error("Informe o motivo da transacao.");
  if (!String(payload.category || "").trim()) throw new Error("Selecione uma categoria.");
  if (Number(payload.amount || 0) <= 0) throw new Error("Informe um valor maior que zero.");
  if (payload.type === "transferencia") {
    if (!payload.destination_account_id) throw new Error("Selecione a conta destino.");
    if (Number(payload.destination_account_id) === Number(payload.account_id)) {
      throw new Error("A conta destino precisa ser diferente da conta origem.");
    }
  }
}

function formFor(config, record = {}) {
  const form = el("form", { class: "card planning-panel-card" });
  const fieldsBox = el("div", { class: "card-body form-grid" });
  const transferFields = [];
  const financeTransferMode = config.endpoint === "/api/finance";
  const financeFieldWrappers = {};
  if (config.title) {
    fieldsBox.append(el("div", { class: "field full" }, [
      el("h2", {}, [config.title]),
      el("p", { class: "muted" }, [config.description || "Registre gastos, entradas e outros movimentos escolhendo em qual conta o valor deve cair."])
    ]));
  }
  if (config.endpoint === "/api/notes") {
    fieldsBox.append(el("div", { class: "field full" }, [
      el("span", { class: "pill" }, [record.id ? `ID #${record.id}` : "ID automatico ao cadastrar"])
    ]));
  }
  config.fields.forEach((field) => {
    const value = record[field.name] ?? (typeof field.value === "function" ? field.value() : field.value || "");
    const wrapper = el("div", { class: `field ${field.full ? "full" : ""}` });
    wrapper.dataset.field = field.name;
    if (financeTransferMode) financeFieldWrappers[field.name] = wrapper;
    if (field.name === "destination_account_id") transferFields.push(wrapper);
    wrapper.append(
      el("label", { for: `${state.section}-${field.name}` }, [field.label]),
      inputFor(field, value, `${state.section}-${field.name}`)
    );
    fieldsBox.append(wrapper);
  });
  fieldsBox.append(el("div", { class: "form-actions full" }, [
    el("button", { class: "primary-button", type: "submit" }, [record.id ? "Salvar edicao" : "Cadastrar"]),
    record.id ? el("button", { class: "secondary-button", type: "button", onclick: () => { state.editing = null; renderCurrentCrud(); } }, ["Cancelar"]) : el("span")
  ]));
  form.append(fieldsBox);
  const typeField = fieldsBox.querySelector('[name="type"]');
  const originLabel = financeFieldWrappers.account_id?.querySelector("label");
  const destinationField = fieldsBox.querySelector('[name="destination_account_id"]');
  const pocketField = fieldsBox.querySelector('[name="pocket_id"]');
  const transferHint = financeTransferMode ? el("div", { class: "finance-transfer-hint hidden full" }, [
    el("strong", {}, ["Transferencia entre bancos"]),
    el("span", {}, ["Escolha a conta de onde o dinheiro saiu e a conta que recebeu. O saldo sai da origem e entra no destino automaticamente."])
  ]) : null;
  if (transferHint) fieldsBox.insertBefore(transferHint, fieldsBox.querySelector(".form-actions"));
  const toggleTransfer = () => {
    const visible = !typeField || typeField.value === "transferencia";
    transferFields.forEach((field) => field.classList.toggle("hidden", !visible));
    if (financeTransferMode) {
      if (originLabel) originLabel.textContent = visible ? "Conta origem" : "Conta";
      if (transferHint) transferHint.classList.toggle("hidden", !visible);
      if (destinationField) {
        destinationField.required = visible;
        destinationField.disabled = !visible;
      }
      if (pocketField) {
        pocketField.disabled = visible;
        pocketField.required = false;
        financeFieldWrappers.pocket_id?.classList.toggle("hidden", visible);
      }
      if (visible && destinationField && !destinationField.value) {
        const origin = fieldsBox.querySelector('[name="account_id"]')?.value;
        const firstDifferent = Array.from(destinationField.options).find((option) => option.value && option.value !== origin);
        if (firstDifferent) destinationField.value = firstDifferent.value;
      }
    }
  };
  if (typeField && transferFields.length) {
    typeField.addEventListener("change", toggleTransfer);
    toggleTransfer();
  }
  if (financeTransferMode) {
    const accountField = fieldsBox.querySelector('[name="account_id"]');
    accountField?.addEventListener("change", () => {
      if (!destinationField || typeField?.value !== "transferencia") return;
      if (destinationField.value && destinationField.value !== accountField.value) return;
      const firstDifferent = Array.from(destinationField.options).find((option) => option.value && option.value !== accountField.value);
      if (firstDifferent) destinationField.value = firstDifferent.value;
    });
  }
  if (config.endpoint === "/api/documents") {
    const pathField = fieldsBox.querySelector('[name="file_path"]');
    const categoryField = fieldsBox.querySelector('[name="category"]');
    const nameField = fieldsBox.querySelector('[name="name"]');
    const fileField = fieldsBox.querySelector('[name="document_file"]');
    const detectDocumentFormat = () => {
      categoryField.value = documentFormatLabel(documentFormatGroup({ file_path: pathField.value }));
    };
    pathField?.addEventListener("input", detectDocumentFormat);
    pathField?.addEventListener("change", detectDocumentFormat);
    fileField?.addEventListener("change", () => {
      const file = fileField.files?.[0];
      if (!file) return;
      pathField.value = file.name;
      if (!nameField.value.trim()) nameField.value = file.name.replace(/\.[^.]+$/, "");
      detectDocumentFormat();
    });
  }
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    try {
      if (config.endpoint === "/api/notes") {
        const ok = await confirmAction({
          title: record.id ? "Salvar alteracoes?" : "Cadastrar anotacao?",
          message: record.id
            ? `As informacoes da anotacao #${record.id} serao atualizadas.`
            : "Uma nova anotacao sera criada com estas informacoes.",
          confirmText: record.id ? "Salvar" : "Cadastrar"
        });
        if (!ok) return;
      }
      const payload = Object.fromEntries(new FormData(form).entries());
      if (config.endpoint === "/api/documents") {
        const file = form.querySelector('[name="document_file"]')?.files?.[0];
        delete payload.document_file;
        if (!record.id && !file) {
          toast("Selecione um arquivo para cadastrar.");
          return;
        }
        if (file) {
          const data = await new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onload = () => resolve(reader.result);
            reader.onerror = () => reject(new Error("Nao foi possivel ler o arquivo."));
            reader.readAsDataURL(file);
          });
          const uploaded = await api("/api/documents/upload", {
            method: "POST",
            body: JSON.stringify({
              name: file.name,
              data,
              mime_type: file.type,
              source_modified_at: file.lastModified ? localDateTimeFromMilliseconds(file.lastModified) : ""
            })
          });
          payload.file_path = uploaded.file_path;
          payload.original_name = uploaded.name || file.name;
          payload.mime_type = uploaded.mime_type || file.type || "application/octet-stream";
          payload.file_size = uploaded.size || file.size || 0;
          payload.source_modified_at = uploaded.source_modified_at || (file.lastModified ? localDateTimeFromMilliseconds(file.lastModified) : "");
          payload.uploaded_at = uploaded.uploaded_at || nowDateTime().replace("T", " ");
          payload.category = documentFormatLabel(documentFormatGroup({ file_path: file.name }));
          if (!payload.name) payload.name = file.name.replace(/\.[^.]+$/, "");
          form.querySelector('[name="file_path"]').value = uploaded.storage_label || "Arquivo protegido no sistema";
        }
      }
      ["account_id", "destination_account_id", "pocket_id", "odd", "stake", "profit_loss", "amount", "entry", "initial_balance", "monthly_goal", "monthly_loss_limit", "converted_value", "paid_amount", "return_amount", "cashout_value"].forEach((key) => {
        if (payload[key] !== undefined) payload[key] = parseBRL(payload[key]);
      });
      if (payload.type !== "transferencia") delete payload.destination_account_id;
      if (!payload.pocket_id || payload.type === "transferencia") delete payload.pocket_id;
      if (config.endpoint === "/api/finance") validateFinancePayload(payload);
      const saved = record.id
        ? await api(`${config.endpoint}/${record.id}`, { method: "PUT", body: JSON.stringify(payload) })
        : await api(config.endpoint, { method: "POST", body: JSON.stringify(payload) });
      toast(config.endpoint === "/api/notes" && !record.id ? `Anotacao #${saved.id} cadastrada.` : record.id ? "Registro atualizado." : "Registro cadastrado.");
      state.editing = null;
      renderCurrentCrud();
    } catch (error) {
      toast(error.message || "Nao foi possivel salvar este registro.");
    }
  });
  return form;
}

function renderCurrentCrud() {
  if (state.section === "finance") return renderFinance();
  if (state.section === "agenda") return renderAgenda();
  if (state.section === "notes") return renderNotes();
  if (state.section === "documents") return renderDocuments();
  if (state.section === "passwords") return renderPasswords();
  if (state.section === "timeline") return renderTimeline();
  return renderCrud();
}

function formatCell(key, value) {
  if (key === "file_path" && String(value || "").startsWith("drso-secure://")) return `<span class="pill green">Arquivo protegido</span>`;
  if (["amount", "entry", "stake", "profit_loss", "return_amount", "possible_return", "cashout_value", "converted_value", "initial_balance", "monthly_goal", "monthly_loss_limit", "betting_profit", "bonus_total", "deposits", "withdrawals", "adjustments", "real_result", "estimated_bankroll", "profit", "used_value", "unused_value", "paid_amount", "remaining_amount", "overdue_amount", "total_amount", "pending_amount", "partial_amount", "estimated_price", "inventory_value", "value_brl", "balance_brl", "sale_value_brl", "price_brl", "original_price_brl", "entries_brl", "exits_brl", "estimated_profit_brl", "inventory_value_brl", "amount_brl"].includes(key)) return money(value);
  if (["playtime_forever", "playtime_2weeks", "top_game_hours", "total_hours"].includes(key)) {
    if (typeof value === "string" && value.toLowerCase().includes("h")) return value;
    const number = Number(value || 0);
    return `${(Number.isFinite(number) ? number / 60 : 0).toFixed(1).replace(".", ",")}h`;
  }
  if (["is_primary", "is_active", "is_favorite", "unlocked", "tradable", "marketable", "is_locked", "has_token"].includes(key)) return Number(value || 0) || value === true ? `<span class="pill green">Sim</span>` : `<span class="pill">Nao</span>`;
  if (["avatar_url", "img_icon_url", "img_logo_url", "image_url", "image"].includes(key)) {
    if (!value) return "";
    const raw = String(value).trim();
    const src = raw.startsWith("//") ? `https:${raw}` : raw;
    const fallback = key === "image" || key === "image_url" ? "🖼" : "•";
    return `<span class="table-thumb-wrap"><img class="table-thumb" src="${src.replace(/"/g, "&quot;")}" alt="" onerror="this.style.display='none'; this.nextElementSibling.style.display='grid';"><span class="table-thumb-fallback" style="display:none;">${fallback}</span></span>`;
  }
  if (key === "profile_url") return value ? `<a href="${String(value).replace(/"/g, "&quot;")}" target="_blank" rel="noreferrer">Abrir perfil</a>` : "";
  if (key === "person_state") {
    const states = ["Offline", "Online", "Ocupado", "Ausente", "Soneca", "Quer trocar", "Quer jogar"];
    const tone = Number(value || 0) ? "green" : "";
    return `<span class="pill ${tone}">${states[Number(value || 0)] || "Desconhecido"}</span>`;
  }
  if (["roi"].includes(key)) return percent(Number(value || 0) * 100);
  if (["units"].includes(key)) return `${Number(value || 0).toFixed(2)}u`;
  if (dateTimeFieldNames.has(key)) return formatBRDateTime(value);
  if (key === "status") {
    if (value === "pending") return `<span class="pill warn">Pendente</span>`;
    if (value === "settled") return `<span class="pill green">Liquidada</span>`;
    if (value === "paid") return `<span class="pill green">Pago</span>`;
    if (value === "Paga") return `<span class="pill green">Paga</span>`;
    if (value === "Aberta") return `<span class="pill warn">Aberta</span>`;
    if (value === "Parcialmente paga") return `<span class="pill saved">Parcialmente paga</span>`;
    if (value === "Sem gastos") return `<span class="pill">Sem gastos</span>`;
    if (value === "partial") return `<span class="pill saved">Guardado</span>`;
    if (value === "canceled") return `<span class="pill red">Cancelado</span>`;
    if (value === "Ativa" || value === "ativa" || value === "ativo") return `<span class="pill green">${value}</span>`;
    if (value === "Pausada" || value === "pausada") return `<span class="pill warn">${value}</span>`;
    return value || "";
  }
  if (key === "status_label") {
    const text = String(value || "");
    const tone = text === "Cash Out realizado" || text === "Ativa" ? "green" : text === "Pendente" ? "warn" : text === "Perdida" ? "red" : "saved";
    return text ? `<span class="pill ${tone}">${text}</span>` : "";
  }
  if (key === "connection_status") {
    const tone = value === "conectado" ? "green" : value === "expirado" || value === "erro" ? "red" : "warn";
    return `<span class="pill ${tone}">${value || "precisa reconectar"}</span>`;
  }
  if (key === "direction") {
    const tone = value === "entrada" ? "green" : value === "saida" ? "red" : "warn";
    return `<span class="pill ${tone}">${value || "neutro"}</span>`;
  }
  if (key === "result") return value === "cashout" ? `<span class="pill green">Cash Out realizado</span>` : value === "void" ? `<span class="pill warn">Anulada</span>` : value === "green" ? `<span class="pill green">Ganhada</span>` : value === "red" ? `<span class="pill red">Perdida</span>` : `<span class="pill warn">Pendente</span>`;
  if (key === "cashout_display") {
    if (!value) return "";
    const tone = String(value).includes("indisponivel") ? "warn" : String(value).includes("Informe") ? "saved" : "green";
    return `<span class="pill ${tone}">${String(value).replace(/</g, "&lt;").replace(/>/g, "&gt;")}</span>`;
  }
  if (key === "priority") {
    const tone = value === "Urgente" ? "red" : value === "Alta" ? "warn" : value === "Baixa" ? "green" : "saved";
    return `<span class="pill ${tone}">${value || "Media"}</span>`;
  }
  if (key === "attachment_count") return `${Number(value || 0)} anexo${Number(value || 0) === 1 ? "" : "s"}`;
  if (key === "recurrence_type") {
    const map = { monthly: "Mensal", weekly: "Semanal", annual: "Anual", installment: "Parcelado" };
    return value ? `<span class="pill">${map[value] || value}</span>` : "";
  }
  if (key === "type") {
    const text = String(value || "");
    const normalized = text.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
    const positiveTypes = ["entrada", "deposito", "freebet", "cashback", "bonus", "missao", "missoes", "indicacao", "credito", "creditos"];
    const negativeTypes = ["saida", "saque"];
    const tone = positiveTypes.some((item) => normalized.includes(item))
      ? "green"
      : negativeTypes.some((item) => normalized.includes(item))
        ? "red"
        : "warn";
    return `<span class="pill ${tone}">${value}</span>`;
  }
  return value || "";
}

function plainCellText(value) {
  const box = document.createElement("div");
  box.innerHTML = value ?? "";
  return box.textContent || box.innerText || "";
}

function tableCell(key, value) {
  const html = String(formatCell(key, value) ?? "");
  const text = plainCellText(html).trim();
  const moneyKeys = new Set(["amount", "entry", "stake", "profit_loss", "return_amount", "possible_return", "cashout_value", "converted_value", "initial_balance", "monthly_goal", "monthly_loss_limit", "betting_profit", "bonus_total", "deposits", "withdrawals", "adjustments", "real_result", "estimated_bankroll", "profit", "used_value", "unused_value", "paid_amount", "remaining_amount", "overdue_amount", "total_amount", "pending_amount", "partial_amount", "estimated_price", "inventory_value", "value_brl", "balance_brl", "sale_value_brl", "price_brl", "original_price_brl", "entries_brl", "exits_brl", "estimated_profit_brl", "inventory_value_brl", "amount_brl", "earned_amount", "total_earned", "avg_per_day", "total_withdrawn", "remaining_to_withdraw", "inventory_estimated_value"]);
  const statusKeys = new Set(["status", "status_label", "result", "type", "direction", "connection_status", "priority", "cashout_display", "recurrence_type", "payment_method", "category"]);
  const classes = [];
  if (moneyKeys.has(key) || /^-?\s*R\$\s*/.test(text)) {
    classes.push("table-money-cell");
    if (/^-\s*R\$|^-R\$/.test(text) || Number(value) < 0) classes.push("negative");
    else if (Number(value) > 0 || /^R\$\s*(?!0[,\.]00)/.test(text)) classes.push("positive");
  }
  if (statusKeys.has(key) || html.includes("class=\"pill")) classes.push("table-chip-cell");
  if (String(key).includes("date") || String(key).includes("_at") || String(key).includes("month")) classes.push("table-date-cell");
  return el("td", { class: classes.join(" "), html, title: text });
}

async function databaseApi(path, options = {}) {
  const response = await fetch(path, {
    credentials: "same-origin",
    headers: {
      "Content-Type": "application/json",
      "X-Database-Token": state.databaseToken || "",
      ...(options.headers || {})
    },
    ...options
  });
  const payload = await response.json().catch(() => ({}));
  if (response.status === 401) {
    state.databaseToken = "";
    state.databaseOverview = null;
    throw new Error(payload.error || "Confirme usuario e senha para consultar o banco.");
  }
  if (!response.ok) throw new Error(payload.error || "Erro ao consultar o banco.");
  return payload;
}

function databaseCell(value) {
  const text = value === null || value === undefined ? "" : String(value);
  return el("td", { title: text }, [text.length > 220 ? `${text.slice(0, 220)}...` : text]);
}

async function loadDatabaseOverview() {
  const overview = await databaseApi("/api/database/overview");
  state.databaseOverview = overview;
  if (!state.databaseSelectedTable && overview.tables?.length) state.databaseSelectedTable = overview.tables[0].name;
  return overview;
}

function openDatabaseAuthModal() {
  return new Promise((resolve) => {
    document.body.classList.add("modal-open");
    const close = (ok = false) => {
      document.body.classList.remove("modal-open");
      overlay.remove();
      resolve(ok);
    };
    const username = el("input", { name: "username", type: "password", autocomplete: "off", value: "", required: "required" });
    const password = el("input", { name: "password", type: "password", autocomplete: "off", required: "required" });
    const form = el("form", { class: "database-auth-form" }, [
      el("div", { class: "settings-card-head" }, [
        el("div", {}, [
          el("span", { class: "pill saved" }, ["Somente leitura"]),
          el("h2", {}, ["Acesso ao Banco de Dados"]),
          el("p", { class: "muted" }, ["Confirme seu usuario e senha para liberar consultas SELECT por alguns minutos."])
        ]),
        el("button", { class: "icon-button", type: "button", onclick: () => close(false), title: "Fechar" }, ["x"])
      ]),
      el("div", { class: "form-grid" }, [
        el("div", { class: "field" }, [el("label", {}, ["Usuario"]), username]),
        el("div", { class: "field" }, [el("label", {}, ["Senha"]), password])
      ]),
      el("div", { class: "confirm-actions" }, [
        el("button", { class: "secondary-button", type: "button", onclick: () => close(false) }, ["Cancelar"]),
        el("button", { class: "primary-button", type: "submit" }, ["Liberar consulta"])
      ])
    ]);
    form.addEventListener("submit", async (event) => {
      event.preventDefault();
      try {
        const response = await fetch("/api/database/auth", {
          method: "POST",
          credentials: "same-origin",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(Object.fromEntries(new FormData(form).entries()))
        });
        const payload = await response.json().catch(() => ({}));
        if (!response.ok) throw new Error(payload.error || "Nao foi possivel liberar o acesso.");
        state.databaseToken = payload.token;
        state.databaseOverview = null;
        toast("Consulta do banco liberada.");
        close(true);
      } catch (error) {
        toast(error.message);
      }
    });
    const overlay = el("div", { class: "confirm-modal-backdrop", onclick: () => close(false) }, [
      el("article", { class: "confirm-modal database-auth-modal", onclick: (event) => event.stopPropagation() }, [form])
    ]);
    document.body.append(overlay);
    setTimeout(() => username.focus(), 50);
  });
}

