async function renderDatabaseTableRows(tableName) {
  const searchParam = encodeURIComponent(state.databaseSearch || "");
  const data = await databaseApi(`/api/database/tables/${encodeURIComponent(tableName)}?limit=80&search=${searchParam}`);
  const columns = data.table.columns.map((column) => column.name);
  const headers = columns.map((name) => tableHeaderCell(name, name));
  const rows = data.rows.map((row) => el("tr", {}, columns.map((column) => databaseCell(row[column]))));
  return {
    tableInfo: data.table,
    filteredCount: data.filtered_count,
    table: systemTable(columns, headers, rows, { columnKey: `database:${tableName}`, wrapClass: "database-table-wrap" })
  };
}

function databaseLockedView() {
  const view = document.querySelector("#view");
  view.replaceChildren(el("section", { class: "database-locked card" }, [
    el("div", { class: "card-body" }, [
      el("span", { class: "pill saved" }, ["Protegido"]),
      el("h2", {}, ["Banco de Dados somente leitura"]),
      el("p", { class: "muted" }, ["Entre novamente com seu usuario e senha para consultar tabelas e executar apenas SELECT. Nao existe exclusao nem edicao nesta tela."]),
      el("button", {
        class: "primary-button",
        type: "button",
        onclick: async () => {
          const ok = await openDatabaseAuthModal();
          if (ok) renderDatabase();
        }
      }, ["Liberar consulta"])
    ])
  ]));
}

async function renderDatabase() {
  const view = document.querySelector("#view");
  if (!state.databaseToken) {
    databaseLockedView();
    setTimeout(async () => {
      if (state.section !== "database" || state.databaseToken) return;
      const ok = await openDatabaseAuthModal();
      if (ok) renderDatabase();
    }, 80);
    return;
  }

  try {
    const overview = state.databaseOverview || await loadDatabaseOverview();
    const selectedTable = state.databaseSelectedTable || overview.tables?.[0]?.name || "";
    const selected = selectedTable ? await renderDatabaseTableRows(selectedTable) : null;
    const queryColumns = state.databaseQueryResult?.columns || [];
    const queryRows = state.databaseQueryResult?.rows || [];
    view.replaceChildren(
      el("div", { class: "database-summary-grid" }, [
        stat("Tabelas liberadas", String(overview.totals?.table_count || 0), "saved"),
        stat("Registros visiveis", String(overview.totals?.record_count || 0), "positive"),
        stat("Modo", "Somente SELECT", "warn")
      ]),
      el("section", { class: "database-layout" }, [
        el("aside", { class: "card database-sidebar" }, [
          el("div", { class: "card-body" }, [
            el("h2", {}, ["Tabelas"]),
            el("p", { class: "muted" }, ["Clique para visualizar os registros."])
          ]),
          el("div", { class: "database-table-list" }, overview.tables.map((table) => el("button", {
            class: `database-table-button ${table.name === selectedTable ? "active" : ""}`,
            type: "button",
            onclick: () => {
              state.databaseSelectedTable = table.name;
              state.databaseSearch = "";
              renderDatabase();
            }
          }, [
            el("strong", {}, [table.name]),
            el("span", {}, [`${table.count} registros`])
          ])))
        ]),
        el("div", { class: "database-main" }, [
          el("section", { class: "card database-panel" }, [
            el("div", { class: "card-body database-panel-head" }, [
              el("div", {}, [
                el("span", { class: "pill saved" }, ["SELECT"]),
                el("h2", {}, [selectedTable || "Nenhuma tabela"]),
                el("p", { class: "muted" }, [selected ? `${selected.filteredCount} registros encontrados.` : ""])
              ]),
              el("form", {
                class: "database-search",
                onsubmit: (event) => {
                  event.preventDefault();
                  state.databaseSearch = event.currentTarget.elements.search.value;
                  renderDatabase();
                }
              }, [
                el("input", { name: "search", placeholder: "Buscar nesta tabela", value: state.databaseSearch || "" }),
                el("button", { class: "secondary-button", type: "submit" }, ["Buscar"])
              ])
            ]),
            selected ? selected.table : el("p", { class: "muted card-body" }, ["Nenhuma tabela encontrada."])
          ]),
          el("section", { class: "card database-query-panel" }, [
            el("div", { class: "card-body" }, [
              el("h2", {}, ["Consulta SELECT"]),
              el("p", { class: "muted" }, ["Use apenas SELECT. O sistema bloqueia comandos de alteracao e aplica limite automatico quando faltar LIMIT."]),
              el("textarea", {
                class: "database-query-input",
                spellcheck: "false",
                oninput: (event) => { state.databaseQuery = event.currentTarget.value; }
              }, [state.databaseQuery || ""]),
              el("div", { class: "confirm-actions" }, [
                el("button", {
                  class: "secondary-button",
                  type: "button",
                  onclick: () => {
                    state.databaseQuery = selectedTable ? `SELECT * FROM ${selectedTable}` : "SELECT name FROM sqlite_master WHERE type = 'table'";
                    renderDatabase();
                  }
                }, ["Usar tabela atual"]),
                el("button", {
                  class: "primary-button",
                  type: "button",
                  onclick: async () => {
                    try {
                      state.databaseQueryResult = await databaseApi("/api/database/query", { method: "POST", body: JSON.stringify({ sql: state.databaseQuery }) });
                      renderDatabase();
                    } catch (error) {
                      toast(error.message);
                    }
                  }
                }, ["Executar SELECT"])
              ])
            ]),
            state.databaseQueryResult ? systemTable(
              queryColumns,
              queryColumns.map((column) => tableHeaderCell(column, column)),
              queryRows.map((row) => el("tr", {}, queryColumns.map((column) => databaseCell(row[column])))),
              { columnKey: "database:query", wrapClass: "database-table-wrap" }
            ) : el("p", { class: "muted database-query-empty" }, ["Resultado da consulta aparece aqui."])
          ])
        ])
      ])
    );
  } catch (error) {
    toast(error.message);
    databaseLockedView();
  }
}

