function steamAccountForm(accounts = []) {
  const record = state.editing || {};
  const form = el("form", { class: "card steam-account-form" });
  form.append(el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field full" }, [
      el("h2", {}, [record.id ? "Editar conta Steam" : "Cadastrar conta Steam"]),
      el("p", { class: "muted" }, ["Cadastre uma ou mais contas usando o SteamID64. A API key fica somente no backend."])
    ]),
    el("div", { class: "field" }, [el("label", {}, ["Apelido da conta"]), el("input", { name: "nickname", value: record.nickname || "", required: "required", placeholder: "ex: Dauan principal" })]),
    el("div", { class: "field" }, [el("label", {}, ["SteamID64"]), el("input", { name: "steam_id", value: record.steam_id || "", required: "required", inputmode: "numeric", placeholder: "7656119..." })]),
    el("div", { class: "field" }, [el("label", {}, ["URL do perfil"]), el("input", { name: "profile_url", value: record.profile_url || "", placeholder: "https://steamcommunity.com/profiles/..." })]),
    el("div", { class: "field" }, [el("label", {}, ["Avatar"]), el("input", { name: "avatar_url", value: record.avatar_url || "", placeholder: "Preenchido pela sincronizacao" })]),
    el("div", { class: "field" }, [el("label", {}, ["Nome Steam"]), el("input", { name: "persona_name", value: record.persona_name || "", placeholder: "Preenchido pela sincronizacao" })]),
    el("label", { class: "check-field" }, [el("input", { name: "is_primary", type: "checkbox", checked: record.is_primary ? "checked" : undefined }), el("span", {}, ["Conta principal"])]),
    el("label", { class: "check-field" }, [el("input", { name: "is_active", type: "checkbox", checked: record.id ? (record.is_active ? "checked" : undefined) : "checked" }), el("span", {}, ["Conta ativa"])]),
    el("div", { class: "form-actions full" }, [
      el("button", { class: "primary-button" }, [record.id ? "Salvar conta" : "Cadastrar conta"]),
      record.id ? el("button", { class: "secondary-button", type: "button", onclick: () => { state.editing = null; renderSteam(); } }, ["Cancelar"]) : el("span"),
      record.id ? el("button", { class: "danger-button", type: "button", onclick: async () => {
        const ok = await confirmAction({ title: "Excluir conta Steam?", message: "Isso remove a conta e os dados Steam sincronizados dela.", confirmText: "Excluir", danger: true });
        if (!ok) return;
        await api(`/api/steam/accounts/${record.id}`, { method: "DELETE" });
        state.editing = null;
        toast("Conta Steam removida.");
        renderSteam();
      } }, ["Excluir"]) : el("span")
    ])
  ]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = Object.fromEntries(new FormData(form).entries());
    payload.is_primary = form.elements.is_primary.checked;
    payload.is_active = form.elements.is_active.checked;
    try {
      const method = record.id ? "PUT" : "POST";
      const url = record.id ? `/api/steam/accounts/${record.id}` : "/api/steam/accounts";
      await api(url, { method, body: JSON.stringify(payload) });
      state.editing = null;
      toast(record.id ? "Conta Steam atualizada." : "Conta Steam cadastrada.");
      renderSteam();
    } catch (error) {
      toast(error.message);
    }
  });
  return el("div", { class: "steam-account-layout" }, [
    form,
    steamAccountsView(accounts)
  ]);
}

async function syncSteamAccount(id = null) {
  const loading = openLoadingModal("Sincronizando Steam", "Buscando perfil, biblioteca, conquistas e amigos. Inventario fica em botao separado para evitar bloqueio da Steam.", {
    successTitle: "Steam Hub sincronizado",
    successMessage: "Os dados disponiveis da Steam foram atualizados no sistema.",
    errorTitle: "Nao foi possivel sincronizar a Steam"
  });
  try {
    const endpoint = id ? `/api/steam/accounts/${id}/sync` : "/api/steam/sync";
    await api(endpoint, { method: "POST" });
    loading.success({ fileName: "Steam Hub atualizado", filePath: "Dados sincronizados com sucesso quando a Steam permitiu acesso." });
    toast("Sincronizacao finalizada.");
    renderSteam();
  } catch (error) {
    loading.error(error);
  }
}

async function syncSteamInventoryForAccount(id) {
  if (!id) {
    toast("Escolha uma conta para puxar o inventario.");
    return;
  }
  const loading = openLoadingModal("Sincronizando inventario", "Consultando somente o inventario dessa conta. Se a Steam responder limite temporario, aguarde e tente mais tarde.", {
    successTitle: "Inventario sincronizado",
    successMessage: "A consulta do inventario terminou.",
    errorTitle: "Nao foi possivel puxar o inventario"
  });
  try {
    const result = await api(`/api/steam/accounts/${id}/inventory-sync`, { method: "POST" });
    const total = Number(result.inventory?.total || 0);
    const warnings = result.inventory?.warnings || [];
    loading.success({
      fileName: total ? `${total} item(ns) sincronizado(s)` : "Nenhum item novo salvo",
      filePath: warnings.length ? warnings.slice(0, 2).join(" | ") : "Dados salvos no Steam Hub."
    });
    toast(total ? `Inventario sincronizado: ${total} item(ns).` : "A Steam nao liberou itens agora. Veja os avisos/logs.");
    renderSteam();
  } catch (error) {
    loading.error(error);
  }
}

