function scheduleSteamInventoryRender(focusKey) {
  clearTimeout(steamInventoryFilterTimer);
  const active = document.activeElement;
  const selectionStart = active?.selectionStart ?? null;
  const selectionEnd = active?.selectionEnd ?? null;
  steamInventoryFilterTimer = setTimeout(async () => {
    await renderSteam();
    requestAnimationFrame(() => {
      const input = document.querySelector(`[data-steam-inventory-filter="${focusKey}"]`);
      if (!input) return;
      input.focus();
      if (selectionStart !== null && typeof input.setSelectionRange === "function") {
        const end = Math.min(selectionEnd ?? selectionStart, input.value.length);
        input.setSelectionRange(Math.min(selectionStart, input.value.length), end);
      }
    });
  }, 320);
}

function setSteamInventoryFilter(key, value, options = {}) {
  state.steamInventoryFilters = { ...state.steamInventoryFilters, [key]: value };
  state.steamInventoryPage = 1;
  if (options.debounce) {
    scheduleSteamInventoryRender(key);
    return;
  }
  renderSteam();
}

function setSteamInventoryView(view) {
  state.steamInventoryView = view;
  state.steamInventoryPage = 1;
  renderSteam();
}

function uniqueSteamInventoryOptions(rows, key, labeler = (value) => value) {
  const seen = new Map();
  rows.forEach((row) => {
    const value = String(row[key] || "");
    if (value && !seen.has(value)) seen.set(value, labeler(value, row));
  });
  return [...seen.entries()].sort((a, b) => String(a[1]).localeCompare(String(b[1]), "pt-BR", { numeric: true }));
}

function steamInventoryAccountCards(rows, accounts = []) {
  const counts = new Map();
  rows.forEach((row) => {
    const accountId = String(row.steam_account_id || "");
    if (accountId) counts.set(accountId, (counts.get(accountId) || 0) + 1);
  });
  const entries = accounts.length
    ? accounts.map((account) => [String(account.id), account.nickname || account.persona_name || account.steam_id, counts.get(String(account.id)) || Number(account.inventory_count || 0)])
    : [...counts.entries()].map(([accountId, total]) => [accountId, rows.find((row) => String(row.steam_account_id || "") === accountId)?.account_nickname || "Conta Steam", total]);
  entries.sort((a, b) => String(a[1]).localeCompare(String(b[1]), "pt-BR", { numeric: true }));
  if (state.steamInventoryView !== "accounts" || !entries.length) return "";
  return el("div", { class: "steam-inventory-account-cards" }, entries.map(([accountId, label, total]) => el("button", {
    class: `steam-inventory-account-card ${String(state.steamInventoryFilters.account || "") === accountId ? "active" : ""}`,
    type: "button",
    onclick: () => setSteamInventoryFilter("account", String(state.steamInventoryFilters.account || "") === accountId ? "" : accountId)
  }, [
    el("span", {}, ["Conta Steam"]),
    el("strong", {}, [label]),
    el("small", {}, [`${total} item(ns)`])
  ])));
}

