async function renderSteam() {
  const view = document.querySelector("#view");
  const overview = await api("/api/steam/overview");
  const accounts = overview.accounts || [];
  let content = null;
  if (state.steamTab === "overview") content = steamOverviewPanel(overview);
  if (state.steamTab === "accounts") content = steamAccountForm(accounts);
  if (state.steamTab === "games") {
    const query = new URLSearchParams(state.steamFilters);
    const games = await api(`/api/steam/games?${query.toString()}`);
    content = el("div", { class: "stack" }, [steamGamesFilters(accounts), games.length ? steamGamesTable(games) : el("div", { class: "empty" }, ["Nenhum jogo sincronizado."])]);
  }
  if (state.steamTab === "recent") {
    const recent = overview.recentGames || [];
    content = recent.length ? simpleTable("Jogos recentes", ["account_nickname", "name", "appid", "playtime_2weeks", "playtime_forever", "last_played_at"], recent, "wide") : el("div", { class: "empty" }, ["Nenhum jogo recente sincronizado."]);
  }
  if (state.steamTab === "achievements") {
    const rows = await api("/api/steam/achievements");
    content = rows.length ? simpleTable("Conquistas", ["account_nickname", "appid", "display_name", "description", "unlocked", "unlock_time"], rows, "wide") : el("div", { class: "empty" }, ["Nenhuma conquista sincronizada ou disponivel publicamente."]);
  }
  if (state.steamTab === "friends") {
    const rows = await api("/api/steam/friends");
    content = rows.length ? simpleTable("Amigos", ["account_nickname", "avatar_url", "persona_name", "friend_steam_id", "person_state", "game_extra_info", "last_logoff_at"], rows, "wide") : el("div", { class: "empty" }, ["Nenhum amigo sincronizado. Perfis privados podem bloquear estes dados."]);
  }
  if (state.steamTab === "inventory") {
    const rows = await api("/api/steam/inventory");
    content = rows.length ? steamInventoryView(rows, accounts) : steamInventoryEmptyState(overview.logs || [], accounts);
  }
  if (state.steamTab === "stats") {
    const stats = overview.stats || {};
    content = el("div", { class: "stack" }, [
      el("div", { class: "stats-grid" }, [
        stat("Contas Steam", String(stats.total_accounts || 0), "saved"),
        stat("Jogos nunca jogados", String(stats.never_played || 0), "warn"),
        stat("Jogados recentemente", String(stats.recently_played || 0), "positive"),
        stat("Progresso conquistas", `${stats.achievement_progress || 0}%`, "positive"),
        stat("Itens no inventario", String(stats.inventory_items || 0), "saved"),
        stat("Valor das skins", money(stats.inventory_value || 0), "positive")
      ]),
      simpleTable("Top 10 jogos", ["account_nickname", "name", "playtime_forever", "playtime_2weeks"], overview.topGames || [], "wide")
    ]);
  }
  if (state.steamTab === "settings") {
    const logs = await api("/api/steam/logs");
    content = el("div", { class: "stack" }, [
      el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [
        el("h2", {}, ["Configuracoes de Sincronizacao"]),
        el("p", { class: "muted" }, ["Configure a STEAM_API_KEY no Windows ou no arquivo C:\\DRSOStorage\\data\\.env. A chave nunca e enviada ao frontend."]),
        el("div", { class: "steam-manual-sync-note" }, [
          el("strong", {}, ["Nada automatico"]),
          el("span", {}, ["Contas, jogos, amigos e conquistas so atualizam quando voce mandar. Inventario tem sincronizacao separada por conta."])
        ]),
        el("div", { class: "steam-config-box" }, [
          el("strong", {}, ["Arquivo de configuracao permanente:"]),
          el("code", {}, ["STEAM_API_KEY=sua_chave_aqui"])
        ]),
        dataSteamApiStatus(overview.apiKeyConfigured),
        el("button", { class: "primary-button", type: "button", onclick: () => syncSteamAccount() }, ["Sincronizar todas as contas ativas"])
      ])]),
      logs.length ? simpleTable("Logs de sincronizacao", ["account_nickname", "sync_type", "status", "message", "started_at", "finished_at"], logs, "wide") : el("div", { class: "empty" }, ["Nenhum log de sincronizacao ainda."])
    ]);
  }
  view.replaceChildren(steamSubnav(), content || el("div", { class: "empty" }, ["Aba Steam nao encontrada."]));
}

function dataSteamApiStatus(configured) {
  return el("div", { class: "steam-api-status" }, [
    configured ? steamBadge("STEAM_API_KEY configurada", "green") : steamBadge("STEAM_API_KEY ausente", "warn"),
    el("p", { class: "muted" }, [configured ? "O backend esta pronto para chamar a Steam Web API." : "Sem a chave, voce consegue cadastrar contas e ver dados ja salvos, mas a sincronizacao online fica bloqueada."])
  ]);
}

