async function csgoSkinsAction(path, title, message) {
  const loading = openLoadingModal(title, message, {
    successTitle: "CSGO-SKINS atualizado",
    successMessage: "A sincronizacao terminou.",
    errorTitle: "Nao foi possivel sincronizar"
  });
  try {
    await api(path, { method: "POST", body: JSON.stringify({ account_id: state.csgoSkinsFilters.account || "" }) });
    loading.success({ fileName: "Dados atualizados", filePath: "Tudo que o site retornou foi salvo no sistema." });
    renderCsgoSkins();
  } catch (error) {
    loading.error(error);
  }
}

async function setCsgoManualInventory(account) {
  const current = account.manual_inventory_enabled ? account.manual_inventory_value_brl : account.inventory_value_brl;
  const raw = window.prompt(
    `Saldo manual de ${account.nickname} em R$.\nDeixe vazio para voltar ao valor sincronizado.`,
    current ? money(current).replace("R$", "").trim() : ""
  );
  if (raw === null) return;
  const trimmed = raw.trim();
  try {
    await api(`/api/csgo-skins/accounts/${account.id}/manual-inventory`, {
      method: "POST",
      body: JSON.stringify(trimmed ? { enabled: true, value: parseLooseMoney(trimmed) } : { enabled: false })
    });
    toast(trimmed ? "Saldo manual salvo." : "Saldo manual removido.");
    renderCsgoSkins();
  } catch (error) {
    toast(error.message || "Nao foi possivel salvar o saldo manual.");
  }
}

