function csgoSkinsAccountForm(accounts = []) {
  const record = state.editing || {};
  const form = el("form", { class: "card csgo-account-form", autocomplete: "off" });
  form.append(el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field full" }, [
      el("h2", {}, [record.id ? "Editar conta CSGO-SKINS" : "Cadastrar conta CSGO-SKINS"]),
      el("p", { class: "muted" }, ["Preferencialmente cole o Copy as cURL completo da requisicao /api. Assim o sistema salva Cookie + User-Agent sem mostrar segredo na tela."])
    ]),
    el("div", { class: "field" }, [el("label", {}, ["Apelido"]), el("input", { name: "nickname", value: record.nickname || "", required: "required", placeholder: "ex: conta principal" })]),
    el("label", { class: "check-field" }, [el("input", { name: "is_active", type: "checkbox", checked: record.id ? (record.is_active ? "checked" : undefined) : "checked" }), el("span", {}, ["Conta ativa"])]),
    el("div", { class: "field full" }, [el("label", {}, [record.has_token ? "Atualizar Cookie/cURL completo" : "Cookie ou cURL completo"]), el("textarea", { name: "token", rows: 5, autocomplete: "off", spellcheck: "false", placeholder: record.has_token ? "Credencial ja salva. Preencha aqui apenas para trocar." : "Cole aqui o Copy as cURL da requisicao /api ou o header Cookie completo" })]),
    el("div", { class: "field full" }, [el("div", { class: "steam-config-box" }, [
      el("strong", {}, ["Como pegar:"]),
      el("span", {}, ["Abra o CSGO-SKINS logado, DevTools > Network, clique com o botao direito em available-with-withdrawing ou transactions e use Copy > Copy as cURL."]),
      el("span", {}, ["Cole o cURL inteiro aqui. O backend extrai Cookie, User-Agent e idioma automaticamente."])
    ])]),
    el("div", { class: "field full" }, [el("label", {}, ["Observacoes"]), el("textarea", { name: "notes", rows: 3 }, [record.notes || ""])]),
    el("div", { class: "form-actions full" }, [
      el("button", { class: "primary-button" }, [record.id ? "Salvar conta" : "Cadastrar conta"]),
      record.id ? el("button", { class: "secondary-button", type: "button", onclick: () => { state.editing = null; renderCsgoSkins(); } }, ["Cancelar"]) : el("span"),
      record.id ? el("button", { class: "danger-button", type: "button", onclick: async () => {
        const ok = await confirmAction({ title: "Excluir conta CSGO-SKINS?", message: "Isso remove a conta e os dados sincronizados dela.", confirmText: "Excluir", danger: true });
        if (!ok) return;
        await api(`/api/csgo-skins/accounts/${record.id}`, { method: "DELETE" });
        state.editing = null;
        renderCsgoSkins();
      } }, ["Excluir"]) : el("span")
    ])
  ]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = Object.fromEntries(new FormData(form).entries());
    payload.is_active = form.elements.is_active.checked;
    try {
      await api(record.id ? `/api/csgo-skins/accounts/${record.id}` : "/api/csgo-skins/accounts", {
        method: record.id ? "PUT" : "POST",
        body: JSON.stringify(payload)
      });
      state.editing = null;
      toast(record.id ? "Conta CSGO-SKINS atualizada." : "Conta CSGO-SKINS cadastrada.");
      renderCsgoSkins();
    } catch (error) {
      toast(error.message);
    }
  });
  return el("div", { class: "steam-account-layout" }, [
    form,
    el("div", { class: "stack" }, [
      el("div", { class: "steam-view-toolbar" }, [el("div", {}, [el("strong", {}, ["Contas cadastradas"]), el("span", { class: "muted" }, [`${accounts.length} contas no modulo.`])])]),
      el("div", { class: "steam-account-grid" }, accounts.length ? accounts.map(csgoSkinsAccountCard) : [el("div", { class: "card empty" }, ["Nenhuma conta cadastrada."])])
    ])
  ]);
}

