function creditInvoicePayForm(invoice) {
  const input = el("input", { name: "amount" });
  attachBRLMask(input, invoice.remaining_value || 0);
  const form = el("form", { class: "credit-pay-inline" }, [
    el("select", { name: "payment_type" }, ["Total", "Parcial"].map((item) => el("option", { value: item }, [item]))),
    input,
    el("button", { class: "primary-button" }, ["Pagar"])
  ]);
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = Object.fromEntries(new FormData(form).entries());
    payload.amount = parseBRL(payload.amount);
    payload.payment_date = nowDateTime();
    const ok = await confirmAction({ title: "Pagar fatura?", message: `${invoice.card_name} - ${creditMonthLabel(invoice.billing_month)}`, confirmText: "Pagar" });
    if (!ok) return;
    await api(`/api/finance/credit-cards/invoices/${invoice.id}/pay`, { method: "POST", body: JSON.stringify(payload) });
    toast("Pagamento registrado.");
    renderFinance();
  });
  return form;
}

function creditInvoiceRevertButton(invoice) {
  return el("button", {
    class: "secondary-button",
    type: "button",
    onclick: async () => {
      const ok = await confirmAction({
        title: "Reverter pagamento da fatura?",
        message: `${invoice.card_name} - ${creditMonthLabel(invoice.billing_month)} vai voltar para em aberto e o valor pago sera removido do historico.`,
        confirmText: "Reverter"
      });
      if (!ok) return;
      try {
        await api(`/api/finance/credit-cards/invoices/${invoice.id}/revert-payment`, { method: "POST" });
        toast("Pagamento da fatura revertido.");
        renderFinance();
      } catch (error) {
        toast(error.message || "Nao foi possivel reverter o pagamento.");
      }
    }
  }, ["Reverter pagamento"]);
}

