async function renderFinance() {
  const view = document.querySelector("#view");
  try {
    const [accounts, catalog] = await Promise.all([
      api("/api/finance/accounts"),
      api("/api/finance/catalog")
    ]);
    const params = new URLSearchParams();
    document.querySelectorAll("[data-filter]").forEach((field) => field.value && params.set(field.name, field.value));
    const records = await api(`/api/finance${params.toString() ? `?${params}` : ""}`);
    const accountOptions = accounts.map((account) => ({ value: account.id, label: `${account.bank} - ${account.name}` }));
    const pocketOptions = [
      { value: "", label: "Nao usar caixinha" },
      ...accounts.flatMap((account) => (account.pockets || []).map((pocket) => ({
        value: pocket.id,
        accountId: String(account.id),
        label: `${account.bank} - ${pocket.name} (${pocketKindLabel(pocket.kind)} · ${money(pocket.balance)})`
      })))
    ];
    const financeConfig = {
      ...configs.finance,
      title: state.editing ? "Editar lancamento" : "Novo lancamento",
      fields: configs.finance.fields.map((field) => {
        if (field.name === "account_id") return { ...field, options: accountOptions };
        if (field.name === "destination_account_id") return { ...field, options: accountOptions };
        if (field.name === "pocket_id") return { ...field, options: pocketOptions };
        if (field.name === "category") return { ...field, options: catalog.category.map((item) => ({ value: item.name, label: item.name })) };
        if (field.name === "payment_method") return { ...field, options: catalog.payment_method.map((item) => ({ value: item.name, label: item.name })) };
        return field;
      })
    };
    const tab = state.financeTab === "balances" ? "dashboard" : state.financeTab || "dashboard";
    state.financeTab = tab;
    if (tab === "creditCards") {
      view.replaceChildren(await financeCreditCardsTab());
      return;
    }
    const content = {
      dashboard: financeDashboardTab(accounts, records, financeConfig, accountOptions),
      transactions: financeTransactionsTab(accounts, records, financeConfig, accountOptions),
      accounts: financeAccountsTab(accounts),
      catalog: financeCatalogTab(catalog)
    }[tab];
    view.replaceChildren(financeSubnav(), content);
  } catch (error) {
    view.replaceChildren(el("div", { class: "card" }, [el("div", { class: "card-body stack" }, [
      el("h2", {}, ["Financeiro indisponivel"]),
      el("p", { class: "muted" }, [String(error.message || error)])
    ])]));
  }
}

function financeSubnav() {
  const tabs = [
    ["dashboard", "Dashboard"],
    ["transactions", "Lancamentos"],
    ["accounts", "Cadastro de contas"],
    ["catalog", "Cadastros"]
  ];
  return el("div", { class: "subnav" }, tabs.map(([id, label]) => el("button", {
    class: `subnav-button ${state.financeTab === id ? "active" : ""}`,
    onclick: () => {
      state.financeTab = id;
      state.editing = null;
      renderFinance();
    }
  }, [label])));
}

