function bettingHouseLogo(name) {
  const normalized = String(name || "").toLowerCase();
  const domains = [
    ["7k", "/assets/betting/7k.png"],
    ["bet365", "bet365.com"],
    ["betano", "betano.com"],
    ["betboom", "/assets/betting/betboom.webp"],
    ["betfair", "betfair.com"],
    ["betnacional", "/assets/betting/betnacional.png"],
    ["estrelabet", "/assets/betting/estrelabet.png"],
    ["estrela bet", "/assets/betting/estrelabet.png"],
    ["kto", "/assets/betting/kto.png"],
    ["novibet", "/assets/betting/novibet.png"],
    ["pixbet", "pixbet.com"],
    ["sportingbet", "sportingbet.com"],
    ["stake", "stake.com"],
    ["superbet", "/assets/betting/superbet.png"]
  ];
  const domain = domains.find(([key]) => normalized.includes(key))?.[1];
  if (domain?.startsWith("/")) return domain;
  return domain ? `https://www.google.com/s2/favicons?domain=${domain}&sz=128` : "";
}

