function planningFilterBar(refresh) {
  const chips = [];
  const statusNames = { pending: "Pendentes", partial: "Guardados", paid: "Pagos" };
  const addChip = (key, label, value) => {
    if (!value) return;
    const displayValue = value === "__week" ? "Esta semana" : value === "__overdue" ? "Atrasados" : statusNames[value] || value;
    chips.push(el("button", {
      class: "pill filter-chip",
      type: "button",
      onclick: async () => {
        state.planningFilters = { ...state.planningFilters, [key]: "" };
        await refresh();
      }
    }, [`${label}: ${displayValue} x`]));
  };
  addChip("title", "Titulo", state.planningFilters.title);
  addChip("category", "Categoria", state.planningFilters.category);
  addChip("due_date", "Venc.", state.planningFilters.due_date);
  addChip("status", "Status", state.planningFilters.status);
  if (!chips.length) return el("div", { class: "muted planning-filters-empty" }, ["Clique em mes, pessoa, titulo ou categoria para filtrar."]);
  return el("div", { class: "planning-chip-row" }, [
    ...chips,
    el("button", {
      class: "secondary-button",
      type: "button",
      onclick: async () => {
        state.planningFilters = { title: "", category: "", due_date: "", status: "" };
        await refresh();
      }
    }, ["Limpar filtros"])
  ]);
}

function applyPlanningClientFilters(entries, todayValue = today()) {
  return entries.filter((record) => {
    if (state.planningFilters.due_date === "__week") {
      if (!record.due_date) return false;
      const diff = daysBetween(todayValue, record.due_date);
      return diff >= 0 && diff <= 7;
    }
    if (state.planningFilters.due_date === "__overdue") {
      return record.due_date && daysBetween(todayValue, record.due_date) < 0 && record.status !== "paid";
    }
    return true;
  });
}

