function planningEditableTable(records, refresh) {
  if (!records.length) return el("div", { class: "empty" }, ["Nenhum registro encontrado."]);
  const columns = ["month", "person", "title", "category", "due_date", "amount", "status", "paid_amount", "recurrence_type", "installment_current", "installment_total"];
  const tableColumns = [...columns, "actions"];
  const sortKey = state.planningSort.key || "month";
  const sortDir = state.planningSort.dir || "asc";
  const sortedRecords = [...records].sort((a, b) => {
    const av = a?.[sortKey];
    const bv = b?.[sortKey];
    const isNumeric = ["amount", "paid_amount"].includes(sortKey);
    const isDate = ["due_date", "paid_date", "created_at", "updated_at", "month"].includes(sortKey);
    let result = 0;
    if (isNumeric) result = Number(av || 0) - Number(bv || 0);
    else if (isDate) result = String(av || "").localeCompare(String(bv || ""));
    else result = String(av || "").localeCompare(String(bv || ""), "pt-BR", { sensitivity: "base" });
    return sortDir === "asc" ? result : -result;
  });
  const toggleSort = (key) => {
    state.planningSort = {
      key,
      dir: state.planningSort.key === key && state.planningSort.dir === "asc" ? "desc" : "asc"
    };
    refresh();
  };
  const sortLabel = (key, label) => {
    const active = state.planningSort.key === key;
    const arrow = active ? (state.planningSort.dir === "asc" ? " \u25b2" : " \u25bc") : "";
    return el("button", { class: "sort-header", type: "button", onclick: () => toggleSort(key) }, [label + arrow]);
  };
  const headerCell = (key) => el("th", { class: "resizable-th", oncontextmenu: openTableColumnsModalFromEvent }, [
    el("div", { class: "resizable-th-content" }, [sortLabel(key, labels[key] || key)]),
    planningColumnResizeHandle(key)
  ]);
  return systemTable(tableColumns, [...columns.map((key) => headerCell(key)), tableHeaderCell("actions", "Acoes")], sortedRecords.map((record) => {
      const settle = async () => {
        const ok = await confirmAction({
          title: "Marcar como pago?",
          message: `Isso vai registrar o pagamento de ${record.title} no valor de ${money(record.amount)}.`,
          confirmText: "Sim, pagar"
        });
        if (!ok) return;
        const payload = { ...record, status: "paid", paid_amount: Number(record.amount || 0), paid_date: today() };
        await api(`/api/planning/${record.id}`, { method: "PUT", body: JSON.stringify(payload) });
        toast("Compromisso marcado como pago.");
        state.editing = null;
        await refresh();
      };
      const saveMoney = async () => {
        const ok = await confirmAction({
          title: "Marcar como guardado?",
          message: `Vou separar ${money(record.amount)} como dinheiro reservado para ${record.title}, sem marcar como pago ainda.`,
          confirmText: "Guardar"
        });
        if (!ok) return;
        const payload = { ...record, status: "partial", paid_amount: 0, paid_date: "" };
        await api(`/api/planning/${record.id}`, { method: "PUT", body: JSON.stringify(payload) });
        toast("Valor marcado como guardado.");
        state.editing = null;
        await refresh();
      };
      const revert = async () => {
        const isSaved = record.status === "partial";
        const ok = await confirmAction({
          title: isSaved ? "Desguardar valor?" : "Reverter pagamento?",
          message: isSaved
            ? `Isso volta ${record.title} para pendente.`
            : `Isso remove o pagamento registrado de ${record.title} e volta para pendente.`,
          confirmText: isSaved ? "Desguardar" : "Reverter"
        });
        if (!ok) return;
        const payload = { ...record, status: "pending", paid_amount: 0, paid_date: "" };
        await api(`/api/planning/${record.id}`, { method: "PUT", body: JSON.stringify(payload) });
        toast(isSaved ? "Valor desguardado." : "Pagamento revertido.");
        state.editing = null;
        await refresh();
      };
      const partialPay = async () => {
        const amount = promptBRL(`Valor pago parcialmente em ${record.title}`, Number(record.amount || 0) - Number(record.paid_amount || 0));
        if (amount === null || amount <= 0) return;
        await api(`/api/planning/${record.id}/partial`, { method: "POST", body: JSON.stringify({ amount_paid: amount, payment_date: today() }) });
        toast("Pagamento parcial registrado.");
        await refresh();
      };
      const postpone = async () => {
        const dueDate = window.prompt("Nova data de vencimento (AAAA-MM-DD)", addDays(record.due_date || today(), 7));
        if (!dueDate) return;
        await api(`/api/planning/${record.id}/postpone`, { method: "POST", body: JSON.stringify({ due_date: dueDate }) });
        toast("Vencimento adiado.");
        await refresh();
      };
      const duplicate = async () => {
        await api(`/api/planning/${record.id}/duplicate`, { method: "POST", body: JSON.stringify({}) });
        toast("Compromisso duplicado para o proximo mes.");
        await refresh();
      };
      const markRecurring = async () => {
        const recurrenceType = window.prompt("Tipo de recorrencia: monthly, weekly ou annual", record.recurrence_type || "monthly");
        if (!recurrenceType) return;
        await api(`/api/planning/${record.id}/recurring`, { method: "POST", body: JSON.stringify({ recurrence_type: recurrenceType }) });
        toast("Recorrencia ativada.");
        await refresh();
      };
      const split = async () => {
        const half = Number(record.amount || 0) / 2;
        const dauan = promptBRL("Valor para Dauan", half);
        if (dauan === null) return;
        const geovana = promptBRL("Valor para Geovana", Number(record.amount || 0) - dauan);
        if (geovana === null) return;
        await api(`/api/planning/${record.id}/split`, { method: "POST", body: JSON.stringify({ splits: [{ person: "Dauan", amount: dauan }, { person: "Geovana", amount: geovana }] }) });
        toast("Compromisso dividido.");
        await refresh();
      };
      const actions = [];
      if (record.status === "pending") {
        actions.push(el("button", { class: "saved-button", onclick: () => saveMoney() }, ["Guardado"]));
      }
      if (record.status !== "paid" && record.status !== "canceled") {
        actions.push(
          el("button", { class: "primary-button", onclick: () => settle() }, ["Pago"]),
          el("button", { class: "secondary-button", onclick: () => partialPay() }, ["Parcial"]),
          el("button", { class: "secondary-button", onclick: () => postpone() }, ["Adiar"])
        );
      }
      if (record.status === "paid") {
        actions.push(el("button", { class: "secondary-button", onclick: () => revert() }, ["Reverter"]));
      }
      if (record.status === "partial") {
        actions.push(el("button", { class: "secondary-button", onclick: () => revert() }, ["Desguardar"]));
      }
      actions.push(
        el("button", { class: "secondary-button", onclick: () => duplicate() }, ["Duplicar"]),
        el("button", { class: "secondary-button", onclick: () => markRecurring() }, ["Recorrente"]),
        el("button", { class: "secondary-button", onclick: () => split() }, ["Dividir"]),
        el("button", { class: "secondary-button", onclick: () => { state.editing = record; refresh(); } }, ["Editar"]),
        el("button", { class: "danger-button", onclick: async () => {
          const ok = await confirmAction({
            title: "Excluir compromisso?",
            message: `Essa acao vai excluir ${record.title}.`,
            confirmText: "Excluir",
            danger: true
          });
          if (!ok) return;
          await api(`/api/planning/${record.id}`, { method: "DELETE" });
          toast("Compromisso excluido.");
          state.editing = null;
          await refresh();
        } }, ["Excluir"])
      );
      return el("tr", { class: planningRowClass(record) }, [
        el("td", {}, [record.month]),
        el("td", {}, [record.person]),
        el("td", {}, [record.title]),
        el("td", {}, [record.category || "Sem categoria"]),
        tableCell("due_date", record.due_date),
        tableCell("amount", record.amount),
        tableCell("status", record.status),
        tableCell("paid_amount", record.paid_amount),
        tableCell("recurrence_type", record.recurrence_type),
        tableCell("installment_current", record.installment_current),
        tableCell("installment_total", record.installment_total),
        el("td", { class: "action-column" }, [el("div", { class: "actions" }, actions)])
      ]);
    }));
}

function planningGroupKey(record) {
  const key = state.planningGroupBy || "due_date";
  if (key === "due_date") return record.due_date || "Sem vencimento";
  if (key === "category") return record.category || "Sem categoria";
  if (key === "status") return plainCellText(formatCell("status", record.status)) || "Sem status";
  return record.person || "Sem pessoa";
}

function planningGroupedView(records, refresh) {
  if (!records.length) return el("div", { class: "empty" }, ["Nenhum registro encontrado."]);
  const groups = new Map();
  records.forEach((record) => {
    const key = planningGroupKey(record);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(record);
  });
  return el("div", { class: "planning-groups" }, [...groups.entries()].map(([key, items]) => {
    const collapsed = Boolean(state.planningCollapsedGroups[key]);
    const total = items.reduce((sum, item) => sum + Number(item.amount || 0), 0);
    return el("section", { class: "card planning-group" }, [
      el("button", {
        class: "planning-group-head",
        type: "button",
        onclick: async () => {
          state.planningCollapsedGroups = { ...state.planningCollapsedGroups, [key]: !collapsed };
          await refresh();
        }
      }, [
        el("strong", {}, [key]),
        el("span", {}, [`${items.length} itens`]),
        el("span", {}, [money(total)]),
        el("span", {}, [collapsed ? "+" : "-"])
      ]),
      collapsed ? el("span") : planningEditableTable(items, refresh)
    ]);
  }));
}

function planningCalendarView(records, refresh) {
  const [year, month] = (state.planningMonth || currentMonth()).split("-").map(Number);
  const first = new Date(year, month - 1, 1);
  const daysInMonth = new Date(year, month, 0).getDate();
  const offset = first.getDay();
  const byDay = new Map();
  records.forEach((record) => {
    if (!record.due_date) return;
    const day = Number(record.due_date.slice(8, 10));
    if (!byDay.has(day)) byDay.set(day, []);
    byDay.get(day).push(record);
  });
  const cells = [];
  for (let i = 0; i < offset; i += 1) cells.push(el("div", { class: "calendar-cell calendar-cell-empty" }));
  for (let day = 1; day <= daysInMonth; day += 1) {
    const items = byDay.get(day) || [];
    const total = items.reduce((sum, item) => sum + Number(item.amount || 0), 0);
    cells.push(el("button", {
      class: `calendar-cell ${items.some((item) => planningRowClass(item) === "planning-row-overdue") ? "calendar-overdue" : ""}`,
      type: "button",
      onclick: async () => {
        state.planningFilters = { ...state.planningFilters, due_date: `${state.planningMonth}-${String(day).padStart(2, "0")}` };
        state.planningView = "table";
        await refresh();
      }
    }, [
      el("strong", {}, [String(day)]),
      items.length ? el("span", {}, [`${items.length} contas`]) : el("span", { class: "muted" }, [""]),
      items.length ? el("b", {}, [money(total)]) : el("span")
    ]));
  }
  return el("div", { class: "card planning-calendar" }, [
    el("div", { class: "calendar-weekdays" }, ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sab"].map((day) => el("span", {}, [day]))),
    el("div", { class: "calendar-grid" }, cells)
  ]);
}

function planningCategoryForm(record, refresh) {
  const form = el("form", { class: "card" });
  form.append(el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field full" }, [
      el("h2", {}, [record.id ? "Editar categoria" : "Nova categoria"]),
      el("p", { class: "muted" }, ["Essas categorias aparecem no lancamento dos compromissos."])
    ]),
    el("div", { class: "field full" }, [el("label", { for: "planning-category-name" }, ["Nome"]), el("input", { id: "planning-category-name", name: "name", required: "required", value: record.name || "", placeholder: "ex: Moradia" })]),
    el("div", { class: "field full" }, [el("label", { for: "planning-category-notes" }, ["Observacoes"]), el("textarea", { id: "planning-category-notes", name: "notes" }, [record.notes || ""]) ]),
    el("div", { class: "form-actions full" }, [
      el("button", { class: "primary-button", type: "submit" }, [record.id ? "Salvar edicao" : "Cadastrar"]),
      record.id ? el("button", { class: "secondary-button", type: "button", onclick: () => { state.editing = null; refresh(); } }, ["Cancelar"]) : el("span")
    ])
  ]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = Object.fromEntries(new FormData(form).entries());
    const url = record.id ? `/api/planning/categories/${record.id}` : "/api/planning/categories";
    await api(url, { method: record.id ? "PUT" : "POST", body: JSON.stringify(payload) });
    toast(record.id ? "Categoria atualizada." : "Categoria cadastrada.");
    state.editing = null;
    await refresh();
  });
  return form;
}

function planningCategoriesTab(categories, refresh) {
  return el("div", { class: "grid two-col finance-layout" }, [
    planningCategoryForm(state.editing || {}, refresh),
    el("div", { class: "stack" }, [
      categories.length ? tableActions(["name", "notes"], categories, (record) => [
        el("button", { class: "secondary-button", onclick: () => { state.editing = record; refresh(); } }, ["Editar"]),
        el("button", { class: "danger-button", onclick: async () => {
          const ok = await confirmAction({
            title: "Excluir categoria?",
            message: `Essa acao vai excluir ${record.name}.`,
            confirmText: "Excluir",
            danger: true
          });
          if (!ok) return;
          await api(`/api/planning/categories/${record.id}`, { method: "DELETE" });
          toast("Categoria excluida.");
          state.editing = null;
          await refresh();
        } }, ["Excluir"])
      ]) : el("div", { class: "empty" }, ["Nenhuma categoria cadastrada."])
    ])
  ]);
}

function planningSummary(data) {
  const stats = data.stats || {};
  const resolvedPercent = Math.min(100, Number(stats.resolved_percent || 0));
  return el("div", { class: "planning-dashboard" }, [
    el("div", { class: "planning-progress-card" }, [
      el("div", {}, [
        el("span", { class: "muted" }, ["Progresso do mes"]),
        el("h2", {}, [`${money(stats.resolved_amount)} de ${money(stats.total_amount)} resolvidos`])
      ]),
      el("strong", {}, [`${resolvedPercent}%`]),
      el("div", { class: "planning-progress-track" }, [
        el("div", { class: "planning-progress-fill", style: `width:${resolvedPercent}%` })
      ])
    ]),
    el("div", { class: "grid stats-grid planning-stats-grid" }, [
      stat("Total do mes", money(stats.total_amount)),
      stat("Total pago", money(stats.paid_amount), "positive"),
      stat("Total guardado", money(stats.partial_amount), "saved"),
      stat("Total pendente", money(stats.pending_amount), "warn"),
      stat("Total atrasado", money(stats.overdue_amount), "negative"),
      stat("Sobra estimada", money(stats.estimated_leftover), "positive"),
      stat("Resolvido", `${resolvedPercent}%`, "saved"),
      stat("Itens", stats.total_items || 0)
    ])
  ]);
}

async function renderPlanning() {
  const view = document.querySelector("#view");
  const params = new URLSearchParams();
  params.set("month", state.planningMonth || currentMonth());
  if (state.planningPerson) params.set("person", state.planningPerson);
  if (state.planningFilters.title) params.set("title", state.planningFilters.title);
  if (state.planningFilters.category) params.set("category", state.planningFilters.category);
  if (state.planningFilters.due_date && !String(state.planningFilters.due_date).startsWith("__")) params.set("due_date", state.planningFilters.due_date);
  if (state.planningFilters.status) params.set("status", state.planningFilters.status);
  const [data, categories] = await Promise.all([
    api(`/api/planning?${params.toString()}`),
    api("/api/planning/categories")
  ]);
  const visibleEntries = applyPlanningClientFilters(data.entries, data.today || today());
  const mainView = state.planningView === "calendar"
    ? planningCalendarView(visibleEntries, renderPlanning)
    : planningEditableTable(visibleEntries, renderPlanning);
  const tabContent = {
    items: el("div", { class: "grid planning-layout", style: "margin-top:14px" }, [
      planningForm(state.editing || { month: data.month, person: state.planningPerson || "Dauan" }, categories, renderPlanning),
      el("div", { class: "stack" }, [
        planningControls(renderPlanning, categories),
        planningFilterBar(renderPlanning),
        simpleTable("Resumo por pessoa", ["person", "total_items", "total_amount", "paid_amount", "remaining_amount"], data.byPerson, "wide"),
        simpleTable("Resumo por categoria", ["category", "total_items", "total_amount", "paid_amount", "remaining_amount"], data.byCategory, "wide"),
        mainView
      ])
    ]),
    categories: planningCategoriesTab(categories, renderPlanning)
  }[state.planningTab || "items"];
  view.replaceChildren(
    el("div", { class: "stack" }, [
      planningSummary(data),
      planningSubnav(),
      tabContent
    ])
  );
}

function tableActions(columns, records, actionsFor, rowAttrsFor = null) {
  if (!records.length) return el("div", { class: "empty" }, ["Nenhum registro encontrado."]);
  const tableColumns = [...columns, "actions"];
  return systemTable(tableColumns, [...columns.map((key) => tableHeaderCell(key)), tableHeaderCell("actions", "Acoes")], records.map((record) => el("tr", rowAttrsFor ? rowAttrsFor(record) : {}, [
      ...columns.map((key) => tableCell(key, record[key])),
      el("td", { class: "action-column" }, [el("div", { class: "actions" }, actionsFor(record))])
    ])));
}

function simpleTable(title, columns, records, size = "") {
  if (!records.length) {
    return el("div", { class: `card table-wrap system-table-wrap ${size === "wide" ? "wide-table" : ""}` }, [
      el("div", { class: "card-body" }, [el("h2", {}, [title])]),
      el("div", { class: "empty" }, ["Nenhum registro encontrado."])
    ]);
  }
  return systemTable(
    columns,
    columns.map((key) => tableHeaderCell(key)),
    records.map((record) => el("tr", {}, columns.map((key) => tableCell(key, record[key])))),
    { title, wrapClass: size === "wide" ? "wide-table" : "" }
  );
}

function financeSummary(records) {
  const income = records.filter((item) => item.type === "entrada").reduce((sum, item) => sum + Number(item.amount), 0);
  const expense = records.filter((item) => item.type === "saida").reduce((sum, item) => sum + Number(item.amount), 0);
  return el("div", { class: "grid stats-grid" }, [
    stat("Entradas filtradas", money(income), "positive"),
    stat("Saidas filtradas", money(expense), "negative"),
    stat("Saldo filtrado", money(income - expense), income - expense >= 0 ? "positive" : "negative"),
    stat("Registros", records.length)
  ]);
}

function betsSummary(records) {
  const settled = records.filter((item) => item.status !== "pending");
  const profit = settled.reduce((sum, item) => sum + Number(item.profit_loss), 0);
  const stake = settled.reduce((sum, item) => sum + Number(item.stake), 0);
  const wins = settled.filter((item) => item.result === "green").length;
  return el("div", { class: "grid stats-grid betting-summary-grid" }, [
    stat("Lucro filtrado", money(profit), profit >= 0 ? "positive" : "negative"),
    stat("ROI filtrado", percent(stake ? (profit / stake) * 100 : 0)),
    stat("Taxa de acerto", percent(settled.length ? (wins / settled.length) * 100 : 0)),
    stat("Apostas", records.length)
  ]);
}

async function renderModules() {
  const modules = await api("/api/modules");
  const view = document.querySelector("#view");
  view.replaceChildren(
    moduleCreator(),
    el("div", { class: "stack", style: "margin-top:14px" }, modules.map(moduleView))
  );
}

function moduleCreator() {
  const form = el("form", { class: "card" });
  form.append(el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field" }, [el("label", {}, ["Nome do modulo"]), el("input", { name: "name", required: "required", placeholder: "Manutencao da Moto" })]),
    el("div", { class: "field" }, [el("label", {}, ["Campos"]), el("input", { name: "fields", placeholder: "Data, Tipo de servico, Valor, Oficina, Observacoes" })]),
    el("div", { class: "field full" }, [el("label", {}, ["Descricao"]), el("textarea", { name: "description" })]),
    el("div", { class: "form-actions full" }, [el("button", { class: "primary-button" }, ["Criar modulo"])])
  ]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const data = Object.fromEntries(new FormData(form).entries());
    const fields = data.fields.split(",").map((name) => name.trim()).filter(Boolean).map((name) => ({ name, type: name.toLowerCase().includes("data") ? "date" : name.toLowerCase().includes("valor") ? "number" : "text" }));
    await api("/api/modules", { method: "POST", body: JSON.stringify({ name: data.name, description: data.description, fields }) });
    toast("Modulo criado.");
    renderModules();
  });
  return form;
}

function moduleView(module) {
  const form = el("form", { class: "form-grid" });
  module.fields.forEach((field) => form.append(el("div", { class: "field" }, [
    el("label", {}, [field.name]),
    el("input", { name: field.name, type: field.type === "number" ? "number" : field.type === "date" ? "date" : "text", step: "0.01" })
  ])));
  form.append(el("div", { class: "form-actions full" }, [el("button", { class: "primary-button" }, ["Adicionar registro"])]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    await api(`/api/modules/${module.id}/records`, { method: "POST", body: JSON.stringify({ data: Object.fromEntries(new FormData(form).entries()) }) });
    toast("Registro do modulo salvo.");
    renderModules();
  });
  return el("div", { class: "card" }, [el("div", { class: "card-body stack" }, [
    el("div", {}, [el("h2", {}, [module.name]), el("p", { class: "muted" }, [module.description || "Modulo personalizado"])]),
    form,
    module.records.length ? el("div", {}, module.records.map((record) => el("div", { class: "module-record" }, [
      ...module.fields.map((field) => el("span", {}, [`${field.name}: ${record.data[field.name] || ""}`])),
      el("button", { class: "danger-button", onclick: async () => {
        const ok = await confirmAction({
          title: "Excluir registro?",
          message: `Essa acao vai excluir este registro de ${module.name}.`,
          confirmText: "Excluir",
          danger: true
        });
        if (!ok) return;
        await api(`/api/modules/${module.id}/records/${record.id}`, { method: "DELETE" });
        renderModules();
      } }, ["Excluir"])
    ]))) : el("p", { class: "muted" }, ["Nenhum registro neste modulo."])
  ])]);
}

function parseCsvRows(text) {
  const rows = [];
  let row = [];
  let cell = "";
  let quoted = false;
  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];
    const next = text[index + 1];
    if (quoted && char === "\"" && next === "\"") {
      cell += "\"";
      index += 1;
    } else if (char === "\"") {
      quoted = !quoted;
    } else if (char === "," && !quoted) {
      row.push(cell);
      cell = "";
    } else if ((char === "\n" || char === "\r") && !quoted) {
      if (char === "\r" && next === "\n") index += 1;
      row.push(cell);
      if (row.some((value) => String(value).trim())) rows.push(row);
      row = [];
      cell = "";
    } else {
      cell += char;
    }
  }
  row.push(cell);
  if (row.some((value) => String(value).trim())) rows.push(row);
  return rows;
}

function normalizePasswordImportItem(item, source = "importado") {
  const login = item.login || {};
  const uri = login.uris?.[0]?.uri || item.login_uri || item.url || item.uri || "";
  return {
    name: item.name || item.title || uri || "Senha importada",
    username: login.username || item.login_username || item.username || item.user || "",
    password: login.password || item.login_password || item.password || item.senha || "",
    totp: login.totp || item.login_totp || item.totp || "",
    uri,
    folder: item.folder || item.folderName || "",
    notes: item.notes || item.note || item.observacoes || "",
    tags: item.tags || item.collectionIds?.join(", ") || "",
    favorite: Boolean(item.favorite),
    source,
    raw: item
  };
}

function parseBitwardenJson(text) {
  const data = JSON.parse(text);
  const folders = new Map((data.folders || []).map((folder) => [folder.id, folder.name]));
  const sourceItems = Array.isArray(data.items) ? data.items : Array.isArray(data) ? data : [];
  return sourceItems
    .filter((item) => item.login || item.password || item.login_password)
    .map((item) => normalizePasswordImportItem({ ...item, folder: folders.get(item.folderId) || item.folder || "" }, "bitwarden-json"));
}

function parsePasswordCsv(text) {
  const rows = parseCsvRows(text);
  if (rows.length < 2) return [];
  const header = rows[0].map((value) => String(value || "").trim());
  return rows.slice(1).map((row) => {
    const item = Object.fromEntries(header.map((key, index) => [key, row[index] || ""]));
    return normalizePasswordImportItem(item, "csv");
  }).filter((item) => item.name || item.username || item.password || item.uri);
}

function parsePasswordTxt(text) {
  return text.split(/\n\s*\n/g).map((block, index) => {
    const lines = block.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
    const findValue = (patterns) => {
      const line = lines.find((entry) => patterns.some((pattern) => pattern.test(entry)));
      return line ? line.replace(/^[^:=-]+[:=-]\s*/i, "").trim() : "";
    };
    const uri = lines.find((line) => /^https?:\/\//i.test(line)) || findValue([/^url/i, /^site/i]);
    const username = findValue([/^user/i, /^usuario/i, /^login/i, /^email/i]);
    const password = findValue([/^pass/i, /^senha/i, /^password/i]);
    const name = findValue([/^name/i, /^nome/i, /^titulo/i]) || uri || `Senha importada ${index + 1}`;
    return { name, username, password, uri, notes: block.trim(), source: "txt", raw: block.trim() };
  }).filter((item) => item.name || item.username || item.password || item.uri);
}

function parsePasswordImport(fileName, text) {
  const name = String(fileName || "").toLowerCase();
  if (name.endsWith(".json")) return parseBitwardenJson(text);
  if (name.endsWith(".csv")) return parsePasswordCsv(text);
  if (name.endsWith(".txt")) return parsePasswordTxt(text);
  try {
    return parseBitwardenJson(text);
  } catch {
    const csvItems = parsePasswordCsv(text);
    return csvItems.length ? csvItems : parsePasswordTxt(text);
  }
}

function passwordUnlockPanel() {
  const form = el("form", { class: "card password-unlock-card" });
  form.append(el("div", { class: "card-body password-unlock-body" }, [
    el("div", { class: "password-lock-icon" }, ["\uD83D\uDD10"]),
    el("div", {}, [
      el("h2", {}, ["Cofre de senhas bloqueado"]),
      el("p", { class: "muted" }, ["Digite a senha do sistema para abrir suas senhas. O acesso fica temporario e os dados sensiveis ficam criptografados no banco."])
    ]),
    el("div", { class: "field" }, [
      el("label", { for: "vault-password" }, ["Senha do sistema"]),
      el("input", { id: "vault-password", name: "password", type: "password", autocomplete: "current-password", required: "required", autofocus: "autofocus" })
    ]),
    el("button", { class: "primary-button" }, ["Abrir cofre"])
  ]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    try {
      const result = await api("/api/passwords/auth", { method: "POST", body: JSON.stringify(Object.fromEntries(new FormData(form).entries())) });
      state.passwordVaultToken = result.token;
      toast("Cofre aberto.");
      renderPasswords();
    } catch (error) {
      toast(error.message);
    }
  });
  return form;
}

function passwordImportPanel() {
  const fileInput = el("input", { type: "file", accept: ".json,.csv,.txt,application/json,text/csv,text/plain" });
  return el("div", { class: "card" }, [el("div", { class: "card-body stack" }, [
    el("h2", {}, ["Importar senhas"]),
    el("p", { class: "muted" }, ["Aceita exportacao JSON do Bitwarden, CSV e TXT. Antes de salvar, o sistema criptografa senha, 2FA e o conteudo bruto do item."]),
    el("div", { class: "password-import-box" }, [fileInput]),
    el("button", {
      class: "primary-button",
      type: "button",
      onclick: async () => {
        const file = fileInput.files?.[0];
        if (!file) return toast("Escolha um arquivo de senhas.");
        try {
          const text = await readTextFile(file);
          const items = parsePasswordImport(file.name, text);
          if (!items.length) return toast("Nao encontrei senhas validas nesse arquivo.");
          const ok = await confirmAction({
            title: "Importar senhas?",
            message: `Encontrei ${items.length} senha(s). Elas serao salvas criptografadas dentro do cofre.`,
            confirmText: "Importar"
          });
          if (!ok) return;
          await passwordApi("/api/passwords/import", { method: "POST", body: JSON.stringify({ source: file.name, items }) });
          fileInput.value = "";
          toast("Senhas importadas.");
          renderPasswords();
        } catch (error) {
          toast(error.message);
        }
      }
    }, ["Importar para o cofre"])
  ])]);
}

function passwordFormPanel() {
  const editing = state.editing?.vault ? state.editing : null;
  const form = el("form", { class: "card" });
  form.append(el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field full" }, [
      el("h2", {}, [editing ? "Editar senha" : "Nova senha"]),
      el("p", { class: "muted" }, ["Cadastre manualmente uma credencial. A senha e o 2FA entram criptografados no banco."])
    ]),
    el("div", { class: "field" }, [el("label", {}, ["Nome"]), el("input", { name: "name", value: editing?.name || "", required: "required", placeholder: "ex: Google, Banco, Trabalho" })]),
    el("div", { class: "field" }, [el("label", {}, ["Usuario"]), el("input", { name: "username", value: editing?.username || "", autocomplete: "off" })]),
    el("div", { class: "field full" }, [el("label", {}, ["URL"]), el("input", { name: "uri", value: editing?.uri || "", placeholder: "https://..." })]),
    el("div", { class: "field" }, [el("label", {}, ["Senha"]), el("input", { name: "password", value: editing?.password || "", type: "password", autocomplete: "new-password" })]),
    el("div", { class: "field" }, [el("label", {}, ["Codigo 2FA/TOTP"]), el("input", { name: "totp", value: editing?.totp || "", autocomplete: "off" })]),
    el("div", { class: "field" }, [el("label", {}, ["Pasta"]), el("input", { name: "folder", value: editing?.folder || "" })]),
    el("div", { class: "field" }, [el("label", {}, ["Tags"]), el("input", { name: "tags", value: editing?.tags || "" })]),
    el("div", { class: "field full" }, [el("label", {}, ["Observacoes"]), el("textarea", { name: "notes" }, [editing?.notes || ""])]),
    el("div", { class: "form-actions full" }, [
      el("button", { class: "primary-button" }, [editing ? "Salvar alteracoes" : "Cadastrar senha"]),
      editing ? el("button", { class: "secondary-button", type: "button", onclick: () => { state.editing = null; renderPasswords(); } }, ["Cancelar"]) : ""
    ])
  ]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = { ...Object.fromEntries(new FormData(form).entries()), source: editing?.source || "manual", raw: editing?.raw || "" };
    try {
      await passwordApi(editing ? `/api/passwords/${editing.id}` : "/api/passwords", {
        method: editing ? "PUT" : "POST",
        body: JSON.stringify(payload)
      });
      state.editing = null;
      toast(editing ? "Senha atualizada." : "Senha cadastrada.");
      renderPasswords();
    } catch (error) {
      toast(error.message);
    }
  });
  return form;
}

