function openPasswordModal(record) {
  const backdrop = el("div", { class: "note-modal-backdrop" });
  let passwordVisible = Boolean(state.visiblePasswords[record.id]);
  const passwordText = () => passwordVisible ? record.password || "-" : "************";
  const totpText = () => passwordVisible ? record.totp || "-" : "******";
  const passwordValue = el("strong", { class: "password-secret" }, [passwordText()]);
  const totpValue = el("strong", { class: "password-secret" }, [totpText()]);
  const eyeButton = el("button", {
    class: `vault-icon-action password-eye-button ${passwordVisible ? "active" : ""}`.trim(),
    type: "button",
    title: "Mostrar ou ocultar senha",
    "aria-label": "Mostrar ou ocultar senha",
    onclick: () => {
      passwordVisible = !passwordVisible;
      state.visiblePasswords = { ...state.visiblePasswords, [record.id]: passwordVisible };
      passwordValue.textContent = passwordText();
      totpValue.textContent = totpText();
      eyeButton.classList.toggle("active", passwordVisible);
      eyeButton.title = passwordVisible ? "Ocultar senha" : "Mostrar senha";
    }
  }, [el("span", { class: "vault-icon-eye", "aria-hidden": "true" })]);
  const close = () => {
    document.body.classList.remove("modal-open");
    backdrop.remove();
  };
  const copy = async (value, message) => {
    await navigator.clipboard.writeText(value || "");
    toast(message);
  };
  backdrop.append(el("div", { class: "confirm-modal password-detail-modal" }, [
    el("div", { class: "password-detail-head" }, [
      el("div", {}, [el("span", { class: "pill green" }, [`#${record.id}`]), el("h2", {}, [record.name])]),
      el("button", { class: "icon-button", onclick: close }, ["x"])
    ]),
    el("div", { class: "password-detail-grid" }, [
      el("div", { class: "password-info-box has-actions" }, [
        el("span", {}, ["Usuario"]),
        el("strong", {}, [record.username || "-"]),
        el("div", { class: "password-box-actions" }, [
          el("button", { class: "vault-icon-action copy-action", type: "button", title: "Copiar usuario", "aria-label": "Copiar usuario", onclick: () => copy(record.username, "Usuario copiado.") }, [
            el("span", { class: "vault-icon-copy", "aria-hidden": "true" })
          ])
        ])
      ]),
      el("div", { class: "password-info-box" }, [el("span", {}, ["URL"]), el("strong", {}, [record.uri || "-"])]),
      el("div", { class: "password-info-box" }, [el("span", {}, ["Pasta"]), el("strong", {}, [record.folder || "-"])]),
      el("div", { class: "password-info-box" }, [el("span", {}, ["Origem"]), el("strong", {}, [record.source || "-"])]),
      el("div", { class: "password-info-box has-actions full" }, [
        el("span", {}, ["Senha"]),
        passwordValue,
        el("div", { class: "password-box-actions" }, [
          eyeButton,
          el("button", { class: "vault-icon-action copy-action primary-copy", type: "button", title: "Copiar senha", "aria-label": "Copiar senha", onclick: () => copy(record.password, "Senha copiada.") }, [
            el("span", { class: "vault-icon-copy", "aria-hidden": "true" })
          ])
        ])
      ]),
      record.totp ? el("div", { class: "password-info-box has-actions full" }, [
        el("span", {}, ["Codigo 2FA"]),
        totpValue,
        el("div", { class: "password-box-actions" }, [
          el("button", { class: "vault-icon-action copy-action", type: "button", title: "Copiar 2FA", "aria-label": "Copiar 2FA", onclick: () => copy(record.totp, "Codigo 2FA copiado.") }, [
            el("span", { class: "vault-icon-copy", "aria-hidden": "true" })
          ])
        ])
      ]) : ""
    ]),
    record.notes ? el("pre", { class: "password-notes" }, [record.notes]) : "",
    el("div", { class: "confirm-actions" }, [
      el("button", { class: "secondary-button", onclick: () => copy(record.username, "Usuario copiado.") }, ["Copiar usuario"]),
      el("button", { class: "primary-button", onclick: () => copy(record.password, "Senha copiada.") }, ["Copiar senha"]),
      el("button", { class: "secondary-button", onclick: close }, ["Fechar"])
    ])
  ]));
  document.body.classList.add("modal-open");
  document.body.append(backdrop);
}

function passwordsTable(items) {
  if (!items.length) return el("div", { class: "card" }, [el("div", { class: "card-body" }, [el("p", { class: "muted" }, ["Nenhuma senha encontrada."])])]);
  const columns = ["id", "name", "username", "uri", "folder", "source", "updated_at", "actions"];
  return systemTable(columns, columns.map((key) => tableHeaderCell(key)), items.map((record) => el("tr", { ondblclick: () => openPasswordModal(record) }, [
    el("td", {}, [`#${record.id}`]),
    el("td", {}, [el("strong", {}, [record.name || "-"])]),
    el("td", {}, [record.username || "-"]),
    el("td", {}, [record.uri ? el("a", { href: record.uri, target: "_blank", rel: "noreferrer" }, [record.uri]) : "-"]),
    el("td", {}, [record.folder || "-"]),
    el("td", {}, [el("span", { class: "pill" }, [record.source || "manual"])]),
    el("td", {}, [formatBRDateTime(record.updated_at)]),
    el("td", { class: "action-column" }, [el("div", { class: "actions" }, [
      el("button", {
        class: "secondary-button",
        onclick: () => {
          state.visiblePasswords = { ...state.visiblePasswords, [record.id]: !state.visiblePasswords[record.id] };
          renderPasswords();
        }
      }, [state.visiblePasswords[record.id] ? "Ocultar" : "Mostrar"]),
      el("button", { class: "primary-button", onclick: async () => { await navigator.clipboard.writeText(record.password || ""); toast("Senha copiada."); } }, ["Copiar"]),
      el("button", { class: "secondary-button", onclick: () => { state.editing = { ...record, vault: true }; renderPasswords(); } }, ["Editar"]),
      el("button", {
        class: "danger-button",
        onclick: async () => {
          const ok = await confirmAction({ title: "Excluir senha?", message: `Remover ${record.name} do cofre?`, confirmText: "Excluir", danger: true });
          if (!ok) return;
          await passwordApi(`/api/passwords/${record.id}`, { method: "DELETE" });
          toast("Senha excluida.");
          renderPasswords();
        }
      }, ["Excluir"])
    ])])
  ])), { columnKey: "passwords:vault", wrapClass: "passwords-table-wrap" });
}

async function renderPasswords() {
  const view = document.querySelector("#view");
  if (!state.passwordVaultToken) {
    view.replaceChildren(passwordUnlockPanel());
    return;
  }
  try {
    const params = new URLSearchParams();
    if (state.passwordFilters.search) params.set("search", state.passwordFilters.search);
    const data = await passwordApi(`/api/passwords${params.toString() ? `?${params}` : ""}`);
    view.replaceChildren(
      passwordStats(data.totals || {}),
      passwordFiltersPanel(),
      el("div", { class: "passwords-layout" }, [
        el("div", { class: "stack" }, [passwordFormPanel(), passwordImportPanel()]),
        passwordsTable(data.items || [])
      ])
    );
  } catch (error) {
    state.passwordVaultToken = "";
    view.replaceChildren(passwordUnlockPanel());
    toast(error.message);
  }
}

