async function renderPersonal() {
  if (!document.querySelector(".confirm-modal-backdrop, .note-modal-backdrop, .document-preview-backdrop")) {
    document.body.classList.remove("modal-open");
  }
  const view = document.querySelector("#view");
  view.replaceChildren(el("div", { class: "loading" }, ["Carregando Jornada Profissional..."]));
  if (state.personalTab === "instagram") {
    try {
      const content = await renderInstagramManager();
      view.replaceChildren(el("div", { class: "stack personal-page" }, [personalSubnav(), content]));
    } catch (error) {
      view.replaceChildren(el("div", { class: "stack personal-page" }, [personalSubnav(), el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [el("h2", {}, ["Instagram indisponivel"]), el("p", { class: "muted" }, [error.message || "Reinicie o servidor para ativar o novo cofre."])])])]));
    }
    return;
  }
  const [data, options] = await Promise.all([api("/api/personal/overview"), api("/api/personal/options")]);
  const content = state.personalTab === "dashboard" ? personalDashboard(data)
    : state.personalTab === "evolution" ? personalEvolution(data)
      : state.personalTab === "plan12" ? personalPlan12(data)
        : state.personalTab === "reports" ? personalReports(data)
          : personalResourceView(state.personalTab, data, options);
  view.replaceChildren(el("div", { class: "stack personal-page" }, [personalSubnav(), content]));
}

