function loadYouTubePlayerApi() {
  if (window.YT?.Player) return Promise.resolve(window.YT);
  if (musicPlayerApiPromise) return musicPlayerApiPromise;
  musicPlayerApiPromise = new Promise((resolve) => {
    const previous = window.onYouTubeIframeAPIReady;
    window.onYouTubeIframeAPIReady = () => {
      if (typeof previous === "function") previous();
      resolve(window.YT);
    };
    if (!document.querySelector("script[src='https://www.youtube.com/iframe_api']")) {
      const script = document.createElement("script");
      script.src = "https://www.youtube.com/iframe_api";
      document.head.append(script);
    }
  });
  return musicPlayerApiPromise;
}

function currentMusicIndex() {
  return musicQueue.findIndex((item) => String(item.id) === String(state.musicCurrentId));
}

function isAudioMusic(song) {
  return String(song?.source_type || "").toLowerCase() === "audio" || Boolean(song?.audio_url);
}

function isYouTubeMusicLink(value) {
  try {
    const url = new URL(String(value || "").trim());
    const host = url.hostname.replace(/^www\./, "").toLowerCase();
    return ["youtube.com", "m.youtube.com", "music.youtube.com", "youtu.be"].includes(host);
  } catch {
    return false;
  }
}

function musicLinkValue(song = {}) {
  return song.audio_url || song.youtube_url || "";
}

function currentMusic() {
  return musicQueue[currentMusicIndex()];
}

function formatMusicTime(seconds) {
  const value = Number(seconds || 0);
  if (!Number.isFinite(value)) return "Ao vivo";
  const total = Math.max(0, Math.floor(value));
  const minutes = Math.floor(total / 60);
  const secs = total % 60;
  return `${minutes}:${String(secs).padStart(2, "0")}`;
}

function musicDuration() {
  const current = currentMusic();
  const duration = isAudioMusic(current) ? Number(musicAudioPlayer?.duration || 0)
    : musicPlayer?.getDuration ? Number(musicPlayer.getDuration() || 0)
      : 0;
  if (!Number.isFinite(duration) || Number.isNaN(duration)) return 0;
  return duration;
}

function musicRawDuration() {
  const current = currentMusic();
  return isAudioMusic(current) ? Number(musicAudioPlayer?.duration || 0)
    : musicPlayer?.getDuration ? Number(musicPlayer.getDuration() || 0)
      : 0;
}

function musicIsLiveStream() {
  const current = currentMusic();
  const audioUrl = String(current?.audio_url || "");
  const isStoredFile = Boolean(current?.audio_file_name) || audioUrl.startsWith("/api/music/audio/");
  const duration = musicRawDuration();
  return isAudioMusic(current) && !isStoredFile && (!Number.isFinite(duration) || duration === Infinity);
}

function musicPlayableCurrentTime() {
  const currentTime = musicCurrentTime();
  return Number.isFinite(currentTime) && !Number.isNaN(currentTime) ? currentTime : 0;
}

function musicPlayableDuration() {
  const duration = musicDuration();
  return Number.isFinite(duration) && !Number.isNaN(duration) ? duration : 0;
}

function musicHasFiniteProgress() {
  return musicPlayableDuration() > 0 && !musicIsLiveStream();
}

function musicLiveLabel() {
  return musicIsLiveStream() ? "Ao vivo" : "0:00";
}

function musicProgressPercent(current, duration) {
  if (!duration || !Number.isFinite(current) || !Number.isFinite(duration)) return 0;
  return Math.round((current / duration) * 1000);
}

function musicProgressCurrent(duration) {
  if (!duration) return 0;
  return Math.min(duration, musicPlayableCurrentTime());
}

function musicProgressDurationLabel(duration) {
  if (musicIsLiveStream()) return "Ao vivo";
  return duration > 0 ? formatMusicTime(duration) : "0:00";
}

function musicProgressCurrentLabel(current) {
  if (musicIsLiveStream()) return "Ao vivo";
  return formatMusicTime(current);
}

function musicProgressDisabled() {
  return musicHasFiniteProgress() ? false : true;
}

function musicProgressValue(current, duration) {
  return musicHasFiniteProgress() ? musicProgressPercent(current, duration) : 0;
}

function musicProgressStyleValue(percent) {
  return `${Math.max(0, Math.min(100, percent / 10))}%`;
}

function musicCanSeek() {
  return musicHasFiniteProgress();
}

function normalizedMusicDuration() {
  return musicPlayableDuration();
}

function normalizedMusicCurrentTime(duration) {
  return musicProgressCurrent(duration);
}

function updateMusicProgress() {
  const duration = normalizedMusicDuration();
  const current = normalizedMusicCurrentTime(duration);
  const percent = musicProgressValue(current, duration);
  document.querySelectorAll("[data-music-progress]").forEach((node) => {
    if (document.activeElement !== node) node.value = String(percent);
    node.style.setProperty("--progress", musicProgressStyleValue(percent));
    node.disabled = musicProgressDisabled();
  });
  document.querySelectorAll("[data-music-current-time]").forEach((node) => {
    node.textContent = musicProgressCurrentLabel(current);
  });
  document.querySelectorAll("[data-music-duration]").forEach((node) => {
    node.textContent = musicProgressDurationLabel(duration);
  });
}

function previousUpdateMusicProgress() {
  return 0;
}

function musicCurrentTime() {
  const current = currentMusic();
  if (isAudioMusic(current)) return Number(musicAudioPlayer?.currentTime || 0);
  if (musicPlayer?.getCurrentTime) return Number(musicPlayer.getCurrentTime() || 0);
  return 0;
}

function startMusicProgressLoop() {
  if (musicProgressTimer) clearInterval(musicProgressTimer);
  updateMusicProgress();
  musicProgressTimer = setInterval(updateMusicProgress, 500);
}

function seekMusicByPercent(value) {
  const duration = musicDuration();
  if (!duration) return;
  const nextTime = (Number(value || 0) / 1000) * duration;
  const current = currentMusic();
  if (isAudioMusic(current) && musicAudioPlayer) {
    musicAudioPlayer.currentTime = nextTime;
  } else if (musicPlayer?.seekTo) {
    musicPlayer.seekTo(nextTime, true);
  }
  updateMusicProgress();
}

function toggleMusicLoop() {
  state.musicLoop = !state.musicLoop;
  if (musicAudioPlayer) musicAudioPlayer.loop = Boolean(state.musicLoop);
  syncMusicPlayerButtons();
}

function clearGlobalMusicPauseHideTimer() {
  if (globalMusicPauseHideTimer) clearTimeout(globalMusicPauseHideTimer);
  globalMusicPauseHideTimer = null;
}

function scheduleGlobalMusicPauseHide() {
  clearGlobalMusicPauseHideTimer();
  globalMusicPauseGraceActive = true;
  globalMusicPauseHideTimer = setTimeout(() => {
    globalMusicPauseHideTimer = null;
    globalMusicPauseGraceActive = false;
    updateGlobalMusicBar();
  }, 30000);
}

function shouldShowGlobalMusicBar() {
  return state.section !== "music"
    && Boolean(state.musicCurrentId)
    && (state.musicPlayerState === "playing" || (state.musicPlayerState === "paused" && globalMusicPauseGraceActive))
    && Boolean(currentMusic());
}

function globalMusicBar() {
  const current = currentMusic();
  return el("aside", { id: "global-music-player", class: "global-music-player", "aria-label": "Player de musica" }, [
    el("div", { class: "global-music-track" }, [
      current?.thumbnail_url ? el("img", { src: current.thumbnail_url, alt: current.titulo || "Capa da musica" }) : el("div", { class: "music-cover-fallback" }, ["♪"]),
      el("div", {}, [
        el("strong", { "data-music-current-title": "1" }, [current?.titulo || "Musica atual"]),
        el("span", { "data-music-current-artist": "1" }, [current?.artista || (isAudioMusic(current) ? "Audio no sistema" : "YouTube")])
      ])
    ]),
    el("div", { class: "global-music-center" }, [
      el("div", { class: "global-music-controls" }, [
        el("button", { class: "music-icon-button", type: "button", onclick: playPreviousMusic, title: "Musica anterior" }, ["⏮"]),
        el("button", { class: "music-play-main compact", type: "button", onclick: toggleMusicPlayback }, [
          el("span", { "data-music-play-label": "1" }, [state.musicPlayerState === "playing" ? "⏸" : "▶"])
        ]),
        el("button", { class: "music-icon-button", type: "button", onclick: playNextMusic, title: "Proxima musica" }, ["⏭"]),
        el("button", { class: "music-icon-button music-loop-button", type: "button", "data-music-loop": "1", onclick: toggleMusicLoop, title: "Repetir musica" }, ["🔁"])
      ]),
      el("div", { class: "global-music-progress music-seek-row" }, [
        el("span", { "data-music-current-time": "1" }, ["0:00"]),
        el("input", {
          class: "music-progress-range",
          type: "range",
          min: "0",
          max: "1000",
          value: "0",
          "data-music-progress": "1",
          disabled: "disabled",
          oninput: (event) => seekMusicByPercent(event.currentTarget.value)
        }),
        el("span", { "data-music-duration": "1" }, ["0:00"])
      ])
    ]),
    el("button", { class: "secondary-button global-music-open", type: "button", onclick: () => setSection("music") }, ["Abrir Musicas"])
  ]);
}

function updateGlobalMusicBar() {
  let bar = document.querySelector("#global-music-player");
  const visible = shouldShowGlobalMusicBar();
  document.body.classList.toggle("music-mini-active", visible);
  if (!visible) {
    if (bar) bar.remove();
    return;
  }
  const next = globalMusicBar();
  if (bar) bar.replaceWith(next);
  else document.body.append(next);
  syncMusicPlayerButtons.allowGlobalUpdate = false;
  syncMusicPlayerButtons();
  syncMusicPlayerButtons.allowGlobalUpdate = true;
}

function stopMusicPlayback() {
  clearGlobalMusicPauseHideTimer();
  globalMusicPauseGraceActive = false;
  if (musicProgressTimer) clearInterval(musicProgressTimer);
  musicProgressTimer = null;
  if (musicAudioPlayer) stopLocalAudio();
  if (musicPlayer?.stopVideo) {
    try {
      musicPlayer.stopVideo();
    } catch {
      // Player externo pode estar indisponivel durante troca de tela.
    }
  }
  if (musicPlayer?.destroy) {
    try {
      musicPlayer.destroy();
    } catch {
      // Nada a fazer se o iframe ja foi removido.
    }
    musicPlayer = null;
  }
  musicPlaybackError = "";
  state.musicPlayerState = "stopped";
  state.musicCurrentId = "";
  musicQueue = [];
  document.querySelector("#global-music-player")?.remove();
  document.body.classList.remove("music-mini-active");
}

function syncMusicPlayerButtons() {
  const current = currentMusic();
  const isAudio = isAudioMusic(current);
  document.querySelectorAll("[data-music-current-title]").forEach((node) => {
    node.textContent = current?.titulo || "Escolha uma musica";
  });
  document.querySelectorAll("[data-music-current-artist]").forEach((node) => {
    node.textContent = current?.artista || "Nenhuma musica tocando";
  });
  document.querySelectorAll("[data-music-status]").forEach((node) => {
    node.textContent = musicPlaybackError || (state.musicPlayerState === "playing" ? (isAudio ? "Tocando audio no sistema" : "Reproduzindo no YouTube") : current ? "Pronto para tocar" : "Nenhuma musica tocando");
    node.classList.toggle("music-status-error", Boolean(musicPlaybackError));
  });
  document.querySelectorAll("[data-music-play-label]").forEach((node) => {
    node.textContent = state.musicPlayerState === "playing" ? "⏸" : "▶";
  });
  document.querySelectorAll("[data-music-loop]").forEach((node) => {
    node.classList.toggle("active", Boolean(state.musicLoop));
    node.setAttribute("aria-pressed", state.musicLoop ? "true" : "false");
    node.title = state.musicLoop ? "Loop ligado: repetir esta musica" : "Loop desligado";
  });
  document.querySelectorAll(".music-track-row").forEach((row) => {
    row.classList.toggle("active", row.dataset.musicId === String(state.musicCurrentId));
  });
  updateMusicProgress();
  if (state.musicPlayerState === "playing") {
    clearGlobalMusicPauseHideTimer();
    globalMusicPauseGraceActive = false;
  } else if (state.musicPlayerState === "paused" && !globalMusicPauseHideTimer && !globalMusicPauseGraceActive) {
    scheduleGlobalMusicPauseHide();
  } else if (state.musicPlayerState !== "paused") {
    clearGlobalMusicPauseHideTimer();
    globalMusicPauseGraceActive = false;
    document.querySelector("#global-music-player")?.remove();
    document.body.classList.remove("music-mini-active");
    return;
  }
  if (syncMusicPlayerButtons.allowGlobalUpdate !== false) {
    syncMusicPlayerButtons.allowGlobalUpdate = false;
    updateGlobalMusicBar();
    syncMusicPlayerButtons.allowGlobalUpdate = true;
  }
}
syncMusicPlayerButtons.allowGlobalUpdate = true;

function audioSourceForSong(song) {
  const audioUrl = song?.audio_url || "";
  if (!audioUrl || audioUrl.startsWith("/api/music/audio/")) return audioUrl;
  return `/api/music/radio-stream?url=${encodeURIComponent(audioUrl)}`;
}

function stopLocalAudio() {
  if (!musicAudioPlayer) return;
  musicAudioPlayer.pause();
  musicAudioPlayer.onended = null;
  musicAudioPlayer.ontimeupdate = null;
  musicAudioPlayer.onloadedmetadata = null;
  musicAudioPlayer.onerror = null;
  musicAudioPlayer.removeAttribute("src");
  musicAudioPlayer.load();
}

function showMusicEmbedFallback(message) {
  const current = musicQueue[currentMusicIndex()];
  const box = document.querySelector(".music-video-box");
  if (!box) return;
  box.classList.add("empty-player", "embed-error");
  box.replaceChildren(el("div", { class: "music-video-placeholder music-error-placeholder" }, [
    el("strong", {}, ["Esse link nao liberou player interno"]),
    el("span", {}, [message || "O YouTube bloqueou a reproducao incorporada desta musica."]),
    el("small", { class: "muted" }, ["Para tocar aqui dentro, use um link do YouTube que permita incorporacao ou uma URL direta de audio, como .mp3, .m4a, .wav ou .ogg."]),
    current?.youtube_url ? el("a", { class: "secondary-button", href: current.youtube_url, target: "_blank", rel: "noreferrer" }, ["Abrir no YouTube"]) : el("span")
  ]));
}

function openMusicExternal(song) {
  const url = String(song?.youtube_url || "").trim();
  if (!url) {
    toast("Essa musica nao tem link do YouTube cadastrado.");
    return;
  }
  window.open(url, "_blank", "noopener,noreferrer");
}

function youtubeOpenCard(song) {
  return el("button", { class: "music-youtube-open-card", type: "button", onclick: () => openMusicExternal(song) }, [
    song?.thumbnail_url ? el("img", { src: song.thumbnail_url, alt: song.titulo || "YouTube" }) : el("div", { class: "music-cover-fallback large" }, ["▶"]),
    el("span", { class: "auth-eyebrow" }, ["Player externo"]),
    el("strong", {}, [song?.titulo || "Musica no YouTube"]),
    el("small", {}, [song?.artista ? `${song.artista} · clicar abre no YouTube` : "Clique para abrir o link cadastrado"])
  ]);
}

function showYouTubeOpenPlayer(song) {
  const box = document.querySelector(".music-video-box");
  if (!box) return;
  box.classList.add("empty-player", "youtube-link-mode");
  box.classList.remove("embed-error", "audio-mode");
  box.replaceChildren(youtubeOpenCard(song));
}

async function playMusicTrack(song, songs = musicQueue) {
  if (!song) return;
  const sameSong = String(state.musicCurrentId || "") === String(song.id || "");
  if (sameSong && state.musicPlayerState === "playing") {
    syncMusicPlayerButtons();
    return;
  }
  musicQueue = songs;
  state.musicCurrentId = song.id;
  state.musicPlayerState = "playing";
  musicPlaybackError = "";
  if (isAudioMusic(song)) {
    if (musicPlayer?.destroy) {
      musicPlayer.destroy();
      musicPlayer = null;
    }
    const box = document.querySelector(".music-video-box");
    if (box) {
      box.classList.add("empty-player", "audio-mode");
      box.classList.remove("embed-error");
      box.replaceChildren(el("div", { class: "music-video-placeholder music-audio-placeholder" }, [
        el("strong", {}, ["Audio no sistema"]),
        el("span", {}, ["Tocando pelo link direto, sem upload e sem video."])
      ]));
    }
    musicAudioPlayer = musicAudioPlayer || new Audio();
    musicAudioPlayer.id = "music-audio-player";
    const nextSource = audioSourceForSong(song);
    const currentSource = musicAudioPlayer.currentSrc || musicAudioPlayer.src || "";
    if (!sameSong || !currentSource.includes(nextSource)) {
      musicAudioPlayer.pause();
      musicAudioPlayer.src = nextSource;
      musicAudioPlayer.currentTime = 0;
    }
    musicAudioPlayer.loop = Boolean(state.musicLoop);
    musicAudioPlayer.onended = () => {
      if (state.musicLoop) return;
      playNextMusic();
    };
    musicAudioPlayer.ontimeupdate = updateMusicProgress;
    musicAudioPlayer.onloadedmetadata = updateMusicProgress;
    musicAudioPlayer.onerror = () => {
      state.musicPlayerState = "unavailable";
      musicPlaybackError = "Nao consegui reproduzir este arquivo de audio.";
      syncMusicPlayerButtons();
    };
    await musicAudioPlayer.play().catch(() => {
      state.musicPlayerState = "paused";
      musicPlaybackError = "Clique em Play para iniciar o audio.";
    });
    startMusicProgressLoop();
    syncMusicPlayerButtons();
    return;
  }
  stopLocalAudio();
  if (musicPlayer?.destroy) {
    musicPlayer.destroy();
    musicPlayer = null;
  }
  state.musicPlayerState = "stopped";
  musicPlaybackError = "";
  showYouTubeOpenPlayer(song);
  syncMusicPlayerButtons();
}

function toggleMusicPlayback() {
  if (!musicQueue.length) return;
  const current = musicQueue[currentMusicIndex()] || musicQueue[0];
  if (isAudioMusic(current)) {
    const expectedSource = audioSourceForSong(current);
    const activeSource = musicAudioPlayer?.currentSrc || musicAudioPlayer?.src || "";
    if (!activeSource || !activeSource.includes(expectedSource)) return playMusicTrack(current, musicQueue);
    if (state.musicPlayerState === "playing") {
      musicAudioPlayer.pause();
      if (musicIsLiveStream()) {
        musicAudioPlayer.removeAttribute("src");
        musicAudioPlayer.load();
      }
      state.musicPlayerState = "paused";
    } else {
      if (musicIsLiveStream()) {
        musicAudioPlayer.pause();
        musicAudioPlayer.removeAttribute("src");
        musicAudioPlayer.load();
        return playMusicTrack(current, musicQueue);
      }
      musicPlaybackError = "";
      musicAudioPlayer.play().then(() => {
        state.musicPlayerState = "playing";
        syncMusicPlayerButtons();
      }).catch(() => {
        state.musicPlayerState = "paused";
        musicPlaybackError = "Clique em Play novamente se o navegador bloqueou o inicio automatico.";
        syncMusicPlayerButtons();
      });
      return;
    }
    syncMusicPlayerButtons();
    return;
  }
  openMusicExternal(current);
}

function playNextMusic() {
  if (!musicQueue.length) return;
  const index = currentMusicIndex();
  playMusicTrack(musicQueue[(index + 1 + musicQueue.length) % musicQueue.length], musicQueue);
}

function playPreviousMusic() {
  if (!musicQueue.length) return;
  const index = currentMusicIndex();
  playMusicTrack(musicQueue[(index - 1 + musicQueue.length) % musicQueue.length], musicQueue);
}

