async function moveMusic(playlist, song, direction) {
  const songs = [...playlist.musicas];
  const index = songs.findIndex((item) => item.id === song.id);
  const nextIndex = index + direction;
  if (index < 0 || nextIndex < 0 || nextIndex >= songs.length) return;
  [songs[index], songs[nextIndex]] = [songs[nextIndex], songs[index]];
  await api(`/api/music/playlists/${playlist.id}/reorder`, { method: "POST", body: JSON.stringify({ ids: songs.map((item) => item.id) }) });
  renderMusic();
}

