function drsoAiConfirmActionModal() {
  const action = state.drsoAiPendingAction;
  if (!action) return "";
  return el("div", { class: "modal-backdrop" }, [
    el("div", { class: "modal-card drso-ai-confirm-modal" }, [
      el("h2", {}, ["Confirmar acao"]),
      el("p", { class: "muted" }, ["A IA so executa alteracoes depois da sua confirmacao."]),
      el("pre", {}, [JSON.stringify(action.payload || {}, null, 2)]),
      el("div", { class: "form-actions" }, [
        el("button", { class: "secondary-button", type: "button", onclick: () => { state.drsoAiPendingAction = null; renderDrsoAi(); } }, ["Fechar"]),
        el("button", { class: "secondary-button", type: "button", onclick: () => drsoAiConfirmAction(action, "cancelled") }, ["Cancelar acao"]),
        el("button", { class: "primary-button", type: "button", onclick: () => drsoAiConfirmAction(action, "confirmed") }, ["Confirmar e executar"])
      ])
    ])
  ]);
}

async function renderDrsoAi() {
  const view = document.querySelector("#view");
  let conversations = [];
  let conversation = null;
  let insights = { cards: [], insights: [] };
  let memories = [];
  try {
    [conversations, insights, memories] = await Promise.all([
      api("/api/drso-ai/conversations"),
      api("/api/drso-ai/insights"),
      api("/api/drso-ai/memories")
    ]);
    if (state.drsoAiConversationId) {
      conversation = await api(`/api/drso-ai/conversations/${state.drsoAiConversationId}`);
    }
  } catch (error) {
    view.replaceChildren(el("div", { class: "stack drso-ai-page" }, [
      el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [
        el("h2", {}, ["Modulo instalado, servidor antigo aberto"]),
        el("p", { class: "muted" }, ["Reinicie o servidor para ativar /api/drso-ai."]),
        el("p", { class: "muted" }, [error.message])
      ])])
    ]));
    return;
  }
  view.replaceChildren(el("div", { class: "drso-ai-page" }, [
    drsoAiInsightCards(insights),
    el("div", { class: "drso-ai-layout" }, [
      drsoAiSidebar(conversations),
      drsoAiChat(conversation),
      el("div", { class: "drso-ai-right-stack" }, [drsoAiSettingsPanel(), drsoAiMemoriesPanel(memories)])
    ]),
    drsoAiConfirmActionModal()
  ]));
}

const biTabs = [
  ["geral", "Geral"],
  ["financeiro", "Financeiro"],
  ["veiculos", "Veiculos"],
  ["metas", "Metas e projetos"],
  ["apostas", "Apostas"],
  ["recorrencias", "Recorrencias"],
  ["uso", "Uso do sistema"]
];

function biDuration(seconds = 0) {
  const total = Math.max(0, Math.round(Number(seconds || 0)));
  const hours = Math.floor(total / 3600);
  const minutes = Math.floor((total % 3600) / 60);
  if (hours) return `${hours}h ${String(minutes).padStart(2, "0")}min`;
  return `${minutes}min`;
}

function biMetric(label, value, detail = "", tone = "") {
  return el("article", { class: `bi-metric ${tone}`.trim() }, [
    el("small", {}, [label]),
    el("strong", {}, [value]),
    detail ? el("span", {}, [detail]) : el("span")
  ]);
}

function biPanel(title, subtitle, children = [], extraClass = "") {
  return el("section", { class: `card bi-panel ${extraClass}`.trim() }, [el("div", { class: "card-body stack" }, [
    el("div", { class: "bi-panel-head" }, [
      el("div", {}, [el("h2", {}, [title]), subtitle ? el("p", { class: "muted" }, [subtitle]) : el("span")])
    ]),
    ...children
  ])]);
}

function biBarChart(title, rows = [], options = {}) {
  const valueKey = options.valueKey || "total";
  const labelKey = options.labelKey || "label";
  const formatter = options.formatter || ((value) => money(value));
  const max = Math.max(1, ...rows.map((row) => Math.abs(Number(row[valueKey] || 0))));
  return biPanel(title, options.subtitle || "", [
    rows.length ? el("div", { class: "bi-bars" }, rows.map((row) => {
      const value = Number(row[valueKey] || 0);
      return el("div", { class: value < 0 ? "negative" : "" }, [
        el("span", {}, [row[labelKey] || "Item"]),
        el("i", { style: `--bar:${Math.round((Math.abs(value) / max) * 100)}%` }),
        el("b", {}, [formatter(value)])
      ]);
    })) : el("p", { class: "muted" }, ["Sem dados suficientes ainda."])
  ]);
}

function biDonutChart(title, rows = [], options = {}) {
  const valueKey = options.valueKey || "total";
  const total = rows.reduce((sum, row) => sum + Math.max(0, Number(row[valueKey] || 0)), 0);
  let cursor = 0;
  const colors = ["#2dd4bf", "#38bdf8", "#fbbf24", "#fb7185", "#a78bfa", "#34d399", "#f97316", "#60a5fa"];
  const stops = total ? rows.slice(0, 8).map((row, index) => {
    const start = cursor;
    const size = (Math.max(0, Number(row[valueKey] || 0)) / total) * 100;
    cursor += size;
    return `${colors[index % colors.length]} ${start}% ${cursor}%`;
  }).join(", ") : "color-mix(in srgb, var(--line) 80%, transparent) 0 100%";
  return biPanel(title, options.subtitle || "", [
    el("div", { class: "bi-donut-layout" }, [
      el("div", { class: "bi-donut", style: `background: conic-gradient(${stops});` }, [el("span", {}, [options.center || String(rows.length || 0)])]),
      el("div", { class: "bi-legend" }, rows.slice(0, 8).map((row, index) => el("div", {}, [
        el("i", { style: `--dot:${colors[index % colors.length]}` }),
        el("span", {}, [row.label || "Item"]),
        el("b", {}, [options.formatter ? options.formatter(row[valueKey]) : String(row[valueKey] || 0)])
      ])))
    ])
  ]);
}

function biList(title, rows = [], options = {}) {
  return biPanel(title, options.subtitle || "", [
    rows.length ? el("div", { class: "bi-list" }, rows.map((row) => el("article", {}, [
      el("strong", {}, [row.title || row.label || row.name || "Item"]),
      el("span", {}, [row.detail || row.category || row.kind || row.date || ""]),
      row.total !== undefined ? el("b", {}, [money(row.total)]) : el("small", {}, [row.date || ""])
    ]))) : el("p", { class: "muted" }, ["Nada para mostrar ainda."])
  ]);
}

