async function renderBi() {
  const view = document.querySelector("#view");
  view.replaceChildren(el("div", { class: "loading" }, ["Carregando Meu BI..."]));
  try {
    const data = await api(`/api/bi/overview?month=${encodeURIComponent(state.biMonth || currentMonth())}`);
    state.biMonth = data.month || state.biMonth || currentMonth();
    view.replaceChildren(el("div", { class: "stack bi-page" }, [
      biHero(data),
      biTabButtons(),
      biContent(data)
    ]));
  } catch (error) {
    view.replaceChildren(el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [
      el("h2", {}, ["Meu BI ainda nao carregou"]),
      el("p", { class: "muted" }, ["Reinicie o servidor para ativar /api/bi/overview."]),
      el("p", { class: "muted" }, [error.message])
    ])]));
  }
}

function codexManagerQuery() {
  const params = new URLSearchParams();
  Object.entries(state.codexFilters || {}).forEach(([key, value]) => {
    if (value) params.set(key, value);
  });
  return params.toString();
}

async function codexManagerMutate(path, options = {}) {
  try {
    await api(path, options);
    await renderCodexManager();
  } catch (error) {
    toast(error.message);
  }
}

function codexStatusTone(status = "") {
  if (status === "Disponivel") return "positive";
  if (status === "Liberando em breve") return "warn";
  if (status === "Em espera") return "waiting";
  if (status === "Vencido") return "danger";
  return "muted";
}

function codexPlanTone(plan = "") {
  if (plan === "Plus Permanente") return "permanent";
  if (plan === "Plus") return "plus";
  return "free";
}

function codexBadge(text, kind = "status") {
  const tone = kind === "plan" ? codexPlanTone(text) : codexStatusTone(text);
  return el("span", { class: `codex-badge ${tone}` }, [text || "Sem informacao"]);
}

function codexMetric(label, value, icon, tone = "") {
  return el("article", { class: `codex-metric ${tone}`.trim() }, [
    el("span", { class: "codex-metric-icon" }, [icon]),
    el("div", {}, [el("small", {}, [label]), el("strong", {}, [value])])
  ]);
}

function codexDashboardCards(data) {
  const summary = data.summary || {};
  const next = (summary.upcoming || [])[0];
  return el("section", { class: "codex-dashboard-grid" }, [
    codexMetric("Total de contas", String(summary.total || 0), "Σ", "accent"),
    codexMetric("Contas Plus", String(summary.plus || 0), "+", "plus"),
    codexMetric("Plus Permanente", String(summary.permanent || 0), "∞", "permanent"),
    codexMetric("Contas Free", String(summary.free || 0), "F", "free"),
    codexMetric("Disponiveis agora", String(summary.available || 0), "✓", "positive"),
    codexMetric("Em espera", String(summary.waiting || 0), "⏳", "waiting"),
    codexMetric("Proxima liberacao", next ? `${next.email} · ${next.countdown}` : "Nada pendente", "⏱", next ? "warn" : "positive"),
    codexMetric("Telefone vinculado", String(summary.phone_linked || 0), "☎", "blue")
  ]);
}

function codexFilters(data) {
  const filters = state.codexFilters || {};
  const filterSelect = (key, label, rows) => el("select", { onchange: (event) => { state.codexFilters[key] = event.currentTarget.value; renderCodexManager(); } }, [
    el("option", { value: "", selected: !filters[key] ? "selected" : undefined }, [label]),
    ...(rows || []).map((row) => el("option", { value: row, selected: filters[key] === row ? "selected" : undefined }, [row]))
  ]);
  return el("section", { class: "card codex-hero-card" }, [el("div", { class: "card-body stack" }, [
    el("div", { class: "subscription-hero-row" }, [
      el("div", {}, [el("p", { class: "eyebrow" }, ["Controle semi-automatico"]), el("h2", {}, ["Codex Manager"]), el("p", { class: "muted" }, ["Contas do Codex App, resets de 5 horas, semanais, telefones e proximas liberacoes."])]),
      el("button", { class: "primary-button", type: "button", onclick: () => { state.codexEditing = {}; renderCodexManager(); } }, ["+ Nova conta"])
    ]),
    el("div", { class: "codex-filter-row" }, [
      el("input", { placeholder: "Buscar por e-mail, tag, telefone ou observacao...", value: filters.search || "", oninput: (event) => { state.codexFilters.search = event.currentTarget.value; clearTimeout(codexSearchTimer); codexSearchTimer = setTimeout(renderCodexManager, 300); } }),
      filterSelect("plan", "Plano", data.plans || []),
      filterSelect("status", "Status", data.statuses || []),
      filterSelect("reset_type", "Tipo de reset", data.reset_types || []),
      filterSelect("phone_linked", "Telefone", [["sim", "Com telefone"], ["nao", "Sem telefone"]].map(([value, label]) => ({ value, label })).map((item) => [item.value, item.label]))
    ])
  ])]);
}

