function codexWeeklyParts(value = "") {
  const match = String(value || "").match(/^([0-6])\s+(\d{2}:\d{2})$/);
  return { day: match?.[1] || "3", time: match?.[2] || "22:50" };
}

function codexAccountForm(data) {
  if (!state.codexEditing) return "";
  const editing = state.codexEditing || {};
  const weekly = codexWeeklyParts(editing.weekly_reset_at);
  const form = el("form", { class: "card codex-form-card" }, [el("div", { class: "card-body stack" }, [
    el("div", { class: "split-row" }, [
      el("div", {}, [el("h2", {}, [editing.id ? "Editar conta Codex" : "Nova conta Codex"]), el("p", { class: "muted" }, ["Cadastro manual; o sistema calcula disponibilidade, alertas e resets."])]),
      el("button", { class: "secondary-button", type: "button", onclick: () => { state.codexEditing = null; renderCodexManager(); } }, ["Fechar"])
    ]),
    el("div", { class: "form-grid" }, [
      fieldInput("email", "E-mail", editing.email, "conta@email.com", "email"),
      fieldSelect("plan", "Plano", editing.plan || "Free", data.plans || ["Free", "Plus", "Plus Permanente"]),
      fieldSelect("reset_type", "Tipo de reset", editing.reset_type || "Manual", data.reset_types || ["5 horas", "Semanal", "Manual"]),
      fieldInput("last_used_at", "Ultimo uso", toDateTimeLocalValue(editing.last_used_at), "", "datetime-local"),
      fieldInput("next_available_at", "Proxima liberacao", toDateTimeLocalValue(editing.next_available_at), "", "datetime-local"),
      fieldInput("plan_expires_at", "Plano expira em", editing.plan_expires_at, "", "date"),
      fieldSelect("weekly_reset_day", "Dia do reset semanal", weekly.day, [["0", "Domingo"], ["1", "Segunda"], ["2", "Terca"], ["3", "Quarta"], ["4", "Quinta"], ["5", "Sexta"], ["6", "Sabado"]]),
      fieldInput("weekly_reset_time", "Hora do reset semanal", weekly.time, "", "time"),
      fieldSelect("phone_linked", "Telefone vinculado?", editing.phone_linked ? "1" : "0", [["0", "Nao"], ["1", "Sim"]]),
      fieldSelect("manual_status", "Marcacao manual", editing.manual_status || "", [["", "Automatica"], ["Vencido", "Vencido"]]),
      fieldInput("phone_notes", "Detalhe do telefone", editing.phone_notes, "Telefone do TI, Geo..."),
      fieldInput("tags", "Tags", editing.tags, "free, ti, geo"),
      fieldTextarea("notes", "Observacoes", editing.notes)
    ]),
    el("div", { class: "form-actions" }, [
      el("button", { class: "primary-button" }, [editing.id ? "Salvar conta" : "Cadastrar conta"]),
      editing.id ? el("button", { class: "danger-button", type: "button", onclick: async () => {
        const ok = await confirmAction({ title: "Excluir conta Codex?", message: `Remover ${editing.email}?`, confirmText: "Excluir", danger: true });
        if (!ok) return;
        await codexManagerMutate(`/api/codex-manager/${editing.id}`, { method: "DELETE" });
        state.codexEditing = null;
      } }, ["Excluir"]) : el("span")
    ])
  ])]);
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = Object.fromEntries(new FormData(form).entries());
    payload.weekly_reset_at = `${payload.weekly_reset_day || "3"} ${payload.weekly_reset_time || "22:50"}`;
    delete payload.weekly_reset_day;
    delete payload.weekly_reset_time;
    payload.phone_linked = Number(payload.phone_linked || 0);
    const path = editing.id ? `/api/codex-manager/${editing.id}` : "/api/codex-manager";
    try {
      await api(path, { method: editing.id ? "PUT" : "POST", body: JSON.stringify(payload) });
      state.codexEditing = null;
      toast(editing.id ? "Conta Codex atualizada." : "Conta Codex cadastrada.");
      await renderCodexManager();
    } catch (error) {
      toast(error.message);
    }
  });
  return form;
}

function codexAccountRow(item) {
  return el("tr", {}, [
    el("td", {}, [el("strong", {}, [item.email]), el("small", { class: "codex-row-sub" }, [item.tags_list?.join(" · ") || "Sem tags"])]),
    el("td", {}, [codexBadge(item.plan, "plan")]),
    el("td", {}, [codexBadge(item.status)]),
    el("td", {}, [item.reset_type || "Manual"]),
    el("td", {}, [formatBRDateTime(item.last_used_at) || "-"]),
    el("td", {}, [el("strong", {}, [formatBRDateTime(item.next_available_at) || "-"]), el("small", { class: "codex-row-sub" }, [item.countdown || ""]) ]),
    el("td", {}, [codexWeeklyLabel(item.weekly_reset_at)]),
    el("td", {}, [item.phone_linked ? "Sim" : "Nao", item.phone_notes ? el("small", { class: "codex-row-sub" }, [item.phone_notes]) : ""]),
    el("td", {}, [item.notes ? el("span", { title: item.notes }, [item.notes.slice(0, 90)]) : el("span", { class: "muted" }, ["Sem observacao"])]),
    el("td", {}, [formatBRDateTime(item.updated_at)]),
    el("td", {}, [el("div", { class: "actions codex-actions" }, [
      el("button", { class: "secondary-button", type: "button", onclick: async () => { await navigator.clipboard.writeText(item.email); toast("E-mail copiado."); } }, ["Copiar"]),
      el("button", { class: "danger-button", type: "button", onclick: () => codexManagerMutate(`/api/codex-manager/${item.id}/use-now`, { method: "POST", body: JSON.stringify({}) }) }, ["Esgotado"]),
      el("button", { class: "primary-button", type: "button", onclick: () => codexManagerMutate(`/api/codex-manager/${item.id}/available`, { method: "POST", body: JSON.stringify({}) }) }, ["Disponivel"]),
      el("button", { class: "secondary-button", type: "button", onclick: () => { state.codexEditing = item; renderCodexManager(); } }, ["Editar"]),
      el("button", { class: "secondary-button", type: "button", onclick: async () => {
        const note = prompt("Observacao rapida para essa conta:");
        if (note) await codexManagerMutate(`/api/codex-manager/${item.id}/quick-note`, { method: "POST", body: JSON.stringify({ note }) });
      } }, ["Nota"])
    ])])
  ]);
}

function codexWeeklyLabel(value = "") {
  const days = ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sab"];
  const parts = codexWeeklyParts(value);
  return value ? `${days[Number(parts.day)] || "Dia"} ${parts.time}` : "-";
}

function codexAccountsTable(data) {
  const rows = data.accounts || [];
  return el("section", { class: "card codex-table-card" }, [el("div", { class: "card-body stack" }, [
    el("div", { class: "split-row" }, [el("div", {}, [el("h2", {}, ["Contas Codex"]), el("p", { class: "muted" }, ["Ordenadas pela proxima liberacao."])]), el("span", { class: "pill" }, [`${rows.length} registro(s)`])]),
    rows.length ? el("div", { class: "table-shell codex-table-shell" }, [
      el("table", {}, [
        el("thead", {}, [el("tr", {}, ["E-mail", "Plano", "Status", "Reset", "Ultimo uso", "Proxima liberacao", "Semanal", "Telefone", "Observacoes", "Atualizado", "Acoes"].map((head) => el("th", {}, [head])))]),
        el("tbody", {}, rows.map(codexAccountRow))
      ])
    ]) : el("p", { class: "muted" }, ["Nenhuma conta encontrada com esses filtros."])
  ])]);
}

async function renderCodexManager() {
  const view = document.querySelector("#view");
  let data;
  try {
    data = await api(`/api/codex-manager?${codexManagerQuery()}`);
  } catch (error) {
    view.replaceChildren(el("div", { class: "stack codex-manager-page" }, [
      el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [
        el("h2", {}, ["Modulo instalado, servidor antigo aberto"]),
        el("p", { class: "muted" }, ["A tela Codex Manager ja foi adicionada, mas reinicie o servidor para a rota /api/codex-manager ficar disponivel."]),
        el("p", { class: "muted" }, [error.message])
      ])])
    ]));
    return;
  }
  view.replaceChildren(el("div", { class: "stack codex-manager-page" }, [
    codexFilters(data),
    codexDashboardCards(data),
    codexAlertsPanel(data),
    codexAccountForm(data),
    codexAccountsTable(data)
  ]));
}

const googleFilterTabs = [
  ["all", "Todas"], ["active", "Ativas"], ["inactive", "Inativas"], ["archived", "Arquivadas"],
  ["no_2fa", "Sem 2FA"], ["no_recovery", "Sem recuperacao"], ["incomplete", "Cadastro incompleto"], ["review", "Precisa revisar"]
];
const googleServices = ["Gmail", "Drive", "Google Fotos", "YouTube", "Play Store", "Android", "Projetos", "Outros"];
const googleStatuses = ["Ativa", "Inativa", "Perdida", "Bloqueada", "Arquivada"];
const googleUses = ["Gmail", "Drive", "Fotos", "YouTube", "Play Store", "Android", "Projetos", "Outros"];
const googleTwoFactorTypes = ["", "SMS", "Authenticator", "Chave fisica", "Outro"];
const googleRiskLevels = ["Baixo", "Medio", "Alto"];

function googleQuery() {
  const params = new URLSearchParams();
  const filters = state.googleFilters || {};
  if (filters.filter && filters.filter !== "all") params.set("filter", filters.filter);
  if (filters.search) params.set("search", filters.search);
  return params.toString();
}

async function googleSecret(id) {
  return api(`/api/google-accounts/${id}/secret`);
}

async function googleMutate(path, options = {}) {
  const result = await api(path, options);
  await renderGoogleCentral();
  return result;
}

function googleBadge(text, tone = "") {
  return el("span", { class: `google-badge ${tone}`.trim() }, [text]);
}

function googleBadges(item) {
  const badges = [googleBadge(item.status || "Ativa", item.status === "Ativa" ? "good" : item.status === "Arquivada" ? "muted" : "warn")];
  if (item.sem_2fa) badges.push(googleBadge("Sem 2FA", "danger"));
  if (item.sem_recuperacao) badges.push(googleBadge("Sem recuperacao", "warn"));
  if (item.cadastro_incompleto) badges.push(googleBadge("Cadastro incompleto", "info"));
  if (item.precisa_revisar) badges.push(googleBadge("Revisar", "warn"));
  if (item.segura) badges.push(googleBadge("Segura", "good"));
  return el("div", { class: "google-badge-row" }, badges);
}

function googleMetric(label, value, hint, tone = "") {
  return el("article", { class: `google-metric-card ${tone}`.trim() }, [
    el("span", { class: "google-metric-icon" }, [label.slice(0, 1)]),
    el("div", {}, [el("small", {}, [label]), el("strong", {}, [String(value || 0)]), el("span", {}, [hint])])
  ]);
}

function googleMetrics(summary = {}) {
  return el("section", { class: "google-metrics-grid" }, [
    googleMetric("Total", summary.total, "contas cadastradas", "blue"),
    googleMetric("Ativas", summary.active, "em uso agora", "good"),
    googleMetric("Sem 2FA", summary.no_2fa, "alerta de seguranca", "danger"),
    googleMetric("Sem recuperacao", summary.no_recovery, "sem e-mail/telefone", "warn"),
    googleMetric("Incompletas", summary.incomplete, "faltam dados", "info"),
    googleMetric("Revisar", summary.review, "revisao pendente", "warn")
  ]);
}

function googleHero() {
  return el("section", { class: "card google-hero" }, [el("div", { class: "card-body" }, [
    el("div", {}, [
      el("span", { class: "mini-badge" }, ["Controle pessoal"]),
      el("h2", {}, ["Central Google"]),
      el("p", { class: "muted" }, ["Organize contas Google, recuperacao, servicos usados e seguranca sem expor senhas na listagem."])
    ]),
    el("div", { class: "google-hero-lock" }, [el("strong", {}, ["Senha protegida"]), el("span", {}, ["Criptografada no banco e mascarada por padrao."])])
  ])]);
}

function googleQuickForm() {
  const form = el("form", { class: "card google-quick-form" }, [el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field" }, [el("label", {}, ["E-mail"]), el("input", { name: "email", type: "email", required: "required", placeholder: "conta@gmail.com", autocomplete: "off" })]),
    el("div", { class: "field" }, [el("label", {}, ["Senha"]), el("input", { name: "password", type: "password", required: "required", placeholder: "Senha da conta", autocomplete: "new-password" })]),
    el("div", { class: "field" }, [el("label", {}, ["Nome da conta"]), el("input", { name: "nome_conta", placeholder: "Pessoal, projetos, fotos..." })]),
    el("div", { class: "field" }, [el("label", {}, ["Uso principal"]), el("select", { name: "uso_principal" }, googleUses.map((item) => el("option", { value: item }, [item])))]),
    el("div", { class: "form-actions full" }, [el("button", { class: "primary-button" }, ["Cadastrar conta"])])
  ])]);
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    try {
      await api("/api/google-accounts", { method: "POST", body: JSON.stringify(Object.fromEntries(new FormData(form).entries())) });
      form.reset();
      toast("Conta Google cadastrada.");
      renderGoogleCentral();
    } catch (error) {
      toast(error.message);
    }
  });
  return form;
}

function googleFiltersPanel() {
  const filters = state.googleFilters || {};
  return el("section", { class: "card google-filter-card" }, [el("div", { class: "card-body stack" }, [
    el("div", { class: "google-tabs" }, googleFilterTabs.map(([id, label]) => el("button", {
      class: filters.filter === id || (!filters.filter && id === "all") ? "active" : "",
      type: "button",
      onclick: () => { state.googleFilters.filter = id; renderGoogleCentral(); }
    }, [label]))),
    el("input", {
      class: "google-search",
      placeholder: "Buscar por nome, e-mail, uso, recuperacao ou observacao...",
      value: filters.search || "",
      oninput: (event) => {
        state.googleFilters.search = event.currentTarget.value;
        clearTimeout(googleSearchTimer);
        googleSearchTimer = setTimeout(renderGoogleCentral, 250);
      }
    })
  ])]);
}

async function googleCopyEmail(item) {
  await navigator.clipboard.writeText(item.email || "");
  toast("E-mail copiado.");
}

async function googleCopyPassword(item) {
  try {
    const secret = await googleSecret(item.id);
    await navigator.clipboard.writeText(secret.password || "");
    toast("Senha copiada.");
  } catch (error) {
    toast(error.message);
  }
}

function googlePasswordCell(item) {
  const visible = Boolean(state.googleVisibleSecrets?.[item.id]);
  const text = visible ? state.googleVisibleSecrets[item.id] : item.senha_mascarada;
  return el("div", { class: "google-password-cell" }, [
    el("strong", {}, [text || item.senha_mascarada]),
    el("button", {
      class: "icon-button",
      type: "button",
      title: visible ? "Ocultar senha" : "Mostrar senha",
      onclick: async () => {
        if (visible) {
          const next = { ...(state.googleVisibleSecrets || {}) };
          delete next[item.id];
          state.googleVisibleSecrets = next;
          renderGoogleCentral();
          return;
        }
        try {
          const secret = await googleSecret(item.id);
          state.googleVisibleSecrets = { ...(state.googleVisibleSecrets || {}), [item.id]: secret.password || "" };
          renderGoogleCentral();
        } catch (error) {
          toast(error.message);
        }
      }
    }, [visible ? "-" : "+"])
  ]);
}

function googleAccountRow(item) {
  return el("tr", { ondblclick: () => openGoogleAccountModal(item) }, [
    el("td", {}, [el("strong", {}, [item.nome_conta || "Sem nome"]), el("small", { class: "codex-row-sub" }, [item.uso_principal || "Outros"])]),
    el("td", {}, [item.email]),
    el("td", {}, [googlePasswordCell(item)]),
    el("td", {}, [googleBadge(item.status || "Ativa", item.status === "Ativa" ? "good" : "warn")]),
    el("td", {}, [item.uso_principal || "-"]),
    el("td", {}, [googleBadges(item)]),
    el("td", {}, [formatDateBR(item.ultima_revisao) || "-"]),
    el("td", {}, [item.cadastro_incompleto ? googleBadge("Incompleto", "warn") : googleBadge("Completo", "good")]),
    el("td", {}, [el("div", { class: "actions google-actions" }, [
      el("button", { class: "secondary-button", type: "button", onclick: () => googleCopyEmail(item) }, ["Copiar e-mail"]),
      el("button", { class: "secondary-button", type: "button", onclick: () => googleCopyPassword(item) }, ["Copiar senha"]),
      el("button", { class: "secondary-button", type: "button", onclick: () => openGoogleAccountModal(item) }, ["Editar"]),
      el("button", { class: "secondary-button", type: "button", onclick: () => googleMutate(`/api/google-accounts/${item.id}/review`, { method: "POST" }) }, ["Revisada"]),
      el("button", { class: "secondary-button", type: "button", onclick: () => googleMutate(`/api/google-accounts/${item.id}/archive`, { method: "POST" }) }, [item.arquivado ? "Reativar" : "Arquivar"])
    ])])
  ]);
}

function googleAccountsTable(items = []) {
  return el("section", { class: "card google-table-card" }, [el("div", { class: "card-body stack" }, [
    el("div", { class: "section-heading" }, [el("h2", {}, ["Contas Google"]), el("span", { class: "pill" }, [`${items.length} registro(s)`])]),
    items.length ? el("div", { class: "table-shell google-table-shell" }, [
      el("table", {}, [
        el("thead", {}, [el("tr", {}, ["Nome da conta", "E-mail", "Senha", "Status", "Uso principal", "Seguranca", "Ultima revisao", "Cadastro", "Acoes"].map((head) => el("th", {}, [head])))]),
        el("tbody", {}, items.map(googleAccountRow))
      ])
    ]) : el("div", { class: "empty" }, ["Nenhuma conta Google encontrada. Cadastre com e-mail e senha para comecar."])
  ])]);
}

function googleField(label, node) {
  return el("div", { class: "field" }, [el("label", {}, [label]), node]);
}

function formPayloadWithCheckboxes(form) {
  const data = Object.fromEntries(new FormData(form).entries());
  if (form.querySelector("input[name='servicos_usados']")) {
    data.servicos_usados = [...form.querySelectorAll("input[name='servicos_usados']:checked")].map((input) => input.value);
  }
  return data;
}

function openGoogleAccountModal(item) {
  state.googleModalTab = state.googleModalTab || "main";
  const secretState = { visible: false, password: "" };
  const backdrop = el("div", { class: "confirm-modal-backdrop google-account-backdrop", onclick: () => backdrop.remove() });
  const form = el("form", { class: "confirm-modal google-account-modal", onclick: (event) => event.stopPropagation() });
  const tabs = [["main", "Dados principais"], ["recovery", "Recuperacao"], ["services", "Servicos"], ["security", "Seguranca"], ["notes", "Observacoes"]];
  const bodyForTab = () => {
    const tab = state.googleModalTab || "main";
    if (tab === "main") {
      const passwordInput = el("input", { name: "password", type: "password", placeholder: "Preencha apenas se quiser trocar", autocomplete: "new-password" });
      return [
        googleField("Nome da conta", el("input", { name: "nome_conta", value: item.nome_conta || "" })),
        googleField("E-mail", el("input", { name: "email", type: "email", value: item.email || "", required: "required" })),
        el("div", { class: "field google-secret-field" }, [
          el("label", {}, ["Senha"]),
          passwordInput,
          el("button", { class: "secondary-button", type: "button", onclick: async () => {
            if (secretState.visible) {
              secretState.visible = false;
              passwordInput.type = "password";
              passwordInput.value = "";
              return;
            }
            const secret = await googleSecret(item.id);
            secretState.visible = true;
            secretState.password = secret.password || "";
            passwordInput.type = "text";
            passwordInput.value = secretState.password;
          } }, ["Mostrar/Ocultar"])
        ]),
        googleField("Data de criacao", el("input", { name: "data_criacao", type: "date", value: item.data_criacao || "" })),
        googleField("Status", el("select", { name: "status" }, googleStatuses.map((status) => el("option", { value: status, selected: item.status === status ? "selected" : undefined }, [status]))))
      ];
    }
    if (tab === "recovery") return [
      googleField("E-mail de recuperacao", el("input", { name: "email_recuperacao", type: "email", value: item.email_recuperacao || "" })),
      googleField("Telefone de recuperacao", el("input", { name: "telefone_recuperacao", value: item.telefone_recuperacao || "" })),
      googleField("Codigos de backup", el("textarea", { name: "codigos_backup", rows: "4", placeholder: item.codigos_backup_mascarados ? "Ja existem codigos salvos. Preencha para substituir." : "" }, [])),
      googleField("Observacoes de recuperacao", el("textarea", { name: "observacoes_recuperacao", rows: "4" }, [item.observacoes_recuperacao || ""]))
    ];
    if (tab === "services") return [
      el("div", { class: "google-service-grid full" }, googleServices.map((service) => el("label", {}, [
        el("input", { type: "checkbox", name: "servicos_usados", value: service, checked: item.servicos_usados?.includes(service) ? "checked" : undefined }),
        el("span", {}, [service])
      ])))
    ];
    if (tab === "security") return [
      googleField("2FA ativo", el("select", { name: "dois_fatores_ativo" }, [
        el("option", { value: "0", selected: !item.dois_fatores_ativo ? "selected" : undefined }, ["Nao"]),
        el("option", { value: "1", selected: item.dois_fatores_ativo ? "selected" : undefined }, ["Sim"])
      ])),
      googleField("Tipo de 2FA", el("select", { name: "tipo_dois_fatores" }, googleTwoFactorTypes.map((type) => el("option", { value: type, selected: item.tipo_dois_fatores === type ? "selected" : undefined }, [type || "Nao informado"])))),
      googleField("Ultima troca de senha", el("input", { name: "ultima_troca_senha", type: "date", value: item.ultima_troca_senha || "" })),
      googleField("Senha repetida", el("select", { name: "senha_repetida" }, [
        el("option", { value: "0", selected: !item.senha_repetida ? "selected" : undefined }, ["Nao"]),
        el("option", { value: "1", selected: item.senha_repetida ? "selected" : undefined }, ["Sim"])
      ])),
      googleField("Nivel de risco", el("select", { name: "nivel_risco" }, googleRiskLevels.map((risk) => el("option", { value: risk, selected: item.nivel_risco === risk ? "selected" : undefined }, [risk])))),
      googleField("Ultima revisao", el("input", { name: "ultima_revisao", type: "date", value: item.ultima_revisao || "" }))
    ];
    return [
      googleField("Uso principal", el("select", { name: "uso_principal" }, googleUses.map((use) => el("option", { value: use, selected: item.uso_principal === use ? "selected" : undefined }, [use])))),
      el("div", { class: "field full" }, [el("label", {}, ["Observacoes"]), el("textarea", { name: "observacoes", rows: "8" }, [item.observacoes || ""])])
    ];
  };
  const renderModal = () => {
    form.replaceChildren(
      el("div", { class: "modal-head" }, [
        el("div", {}, [el("h2", {}, [item.nome_conta || item.email]), el("p", { class: "muted" }, ["Detalhes completos da conta Google."])]),
        el("button", { class: "icon-button", type: "button", onclick: () => backdrop.remove() }, ["x"])
      ]),
      el("div", { class: "google-modal-tabs" }, tabs.map(([id, label]) => el("button", { class: state.googleModalTab === id ? "active" : "", type: "button", onclick: () => { state.googleModalTab = id; renderModal(); } }, [label]))),
      el("div", { class: "form-grid google-modal-grid" }, bodyForTab()),
      el("div", { class: "form-actions" }, [
        el("button", { class: "secondary-button", type: "button", onclick: () => googleCopyEmail(item) }, ["Copiar e-mail"]),
        el("button", { class: "secondary-button", type: "button", onclick: () => googleCopyPassword(item) }, ["Copiar senha"]),
        el("button", { class: "secondary-button", type: "button", onclick: async () => { await googleMutate(`/api/google-accounts/${item.id}/review`, { method: "POST" }); backdrop.remove(); } }, ["Marcar revisada"]),
        el("button", { class: "secondary-button", type: "button", onclick: async () => { await googleMutate(`/api/google-accounts/${item.id}/archive`, { method: "POST" }); backdrop.remove(); } }, [item.arquivado ? "Reativar" : "Arquivar"]),
        el("button", { class: "danger-button", type: "button", onclick: async () => {
          const ok = await confirmAction({ title: "Excluir conta Google?", message: item.email, confirmText: "Excluir", danger: true });
          if (!ok) return;
          await googleMutate(`/api/google-accounts/${item.id}`, { method: "DELETE" });
          backdrop.remove();
        } }, ["Excluir"]),
        el("button", { class: "primary-button" }, ["Salvar"])
      ])
    );
  };
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    try {
      const payload = formPayloadWithCheckboxes(form);
      if (!payload.password) delete payload.password;
      if (!payload.codigos_backup) delete payload.codigos_backup;
      await api(`/api/google-accounts/${item.id}`, { method: "PUT", body: JSON.stringify(payload) });
      toast("Conta Google salva.");
      backdrop.remove();
      renderGoogleCentral();
    } catch (error) {
      toast(error.message);
    }
  });
  renderModal();
  backdrop.append(form);
  document.body.append(backdrop);
}

async function renderGoogleCentral() {
  const view = document.querySelector("#view");
  let data = { items: [], summary: {} };
  try {
    const query = googleQuery();
    data = await api(`/api/google-accounts${query ? `?${query}` : ""}`);
  } catch (error) {
    view.replaceChildren(el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [
      el("h2", {}, ["Central Google indisponivel"]),
      el("p", { class: "muted" }, [error.message || "Reinicie o servidor para carregar as rotas novas."])
    ])]));
    return;
  }
  view.replaceChildren(el("div", { class: "stack google-page" }, [
    googleHero(),
    googleMetrics(data.summary || {}),
    googleQuickForm(),
    googleFiltersPanel(),
    googleAccountsTable(data.items || [])
  ]));
}

