function twofaUnlockPanel(status = {}) {
  const setup = !status.configured;
  const form = el("form", { class: "card twofa-unlock-card" }, [el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field" }, [el("label", {}, [setup ? "Criar senha mestre" : "Senha mestre"]), el("input", { name: "master_password", type: "password", required: "required", minlength: "6", autocomplete: "current-password" })]),
    el("div", { class: "field" }, [el("label", {}, ["Status"]), el("div", { class: "twofa-status-box" }, [setup ? "Primeiro acesso: configure sua senha mestre." : "Desbloqueie para acessar Steam Guard."])]),
    el("div", { class: "form-actions" }, [el("button", { class: "primary-button" }, [setup ? "Criar cofre" : "Desbloquear cofre"])])
  ])]);
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const payload = Object.fromEntries(new FormData(form).entries());
    try {
      if (setup) {
        await api("/api/2fa/setup", { method: "POST", body: JSON.stringify(payload) });
        toast("Senha mestre criada.");
      }
      const result = await api("/api/2fa/unlock", { method: "POST", body: JSON.stringify(payload) });
      state.twofaToken = result.token;
      form.reset();
      renderTwofaVault();
    } catch (error) {
      toast(error.message);
    }
  });
  return form;
}

