async function twofaCopy(value, message) {
  await navigator.clipboard.writeText(value || "");
  toast(message);
}

async function twofaCopySecret(item, key, message) {
  try {
    const secrets = await twofaApi(`/api/2fa/steam/${item.id}/secret`);
    await twofaCopy(secrets[key] || "", message);
  } catch (error) {
    toast(error.message);
  }
}

async function twofaGenerateCode(item, target) {
  try {
    const result = await twofaApi(`/api/2fa/steam/${item.id}/code`);
    state.twofaCodeCache = { ...(state.twofaCodeCache || {}), [item.id]: result };
    if (target) target.textContent = `${result.code} (${result.expires_in}s)`;
    clearInterval(twofaCodeTimer);
    twofaCodeTimer = setInterval(() => {
      const cached = state.twofaCodeCache?.[item.id];
      if (!cached) return;
      cached.expires_in = Math.max(0, Number(cached.expires_in || 0) - 1);
      if (target) target.textContent = `${cached.code} (${cached.expires_in}s)`;
      if (cached.expires_in <= 0) twofaGenerateCode(item, target);
    }, 1000);
    return result;
  } catch (error) {
    toast(error.message);
    return null;
  }
}

