async function renderTwofaTotp(status, provider = "google") {
  if (!status.unlocked) return twofaUnlockPanel(status);
  let data = { items: [], summary: {} };
  try {
    data = await twofaApi(`/api/2fa/totp?provider=${provider}`);
  } catch (error) {
    if (String(error.message || "").toLocaleLowerCase("pt-BR").includes("desbloqueie")) {
      state.twofaToken = "";
      return twofaUnlockPanel({ ...status, unlocked: false });
    }
    return el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [
      el("h2", {}, ["Nao consegui abrir o Autenticador Google"]),
      el("p", { class: "muted" }, [error.message || "Erro ao carregar os codigos Google."]),
      el("button", { class: "secondary-button", type: "button", onclick: renderTwofaVault }, ["Tentar novamente"])
    ])]);
  }
  return el("div", { class: "stack" }, [
    el("div", { class: "split-row twofa-toolbar" }, [
      el("div", {}, [el("h2", {}, ["Autenticador Google"]), el("p", { class: "muted" }, ["Use a chave manual do QR Code do Google para gerar codigos TOTP localmente."])]),
      el("button", { class: "secondary-button", type: "button", onclick: async () => { await twofaApi("/api/2fa/lock", { method: "POST" }); state.twofaToken = ""; state.twofaCodeCache = {}; renderTwofaVault(); } }, ["Bloquear Cofre"])
    ]),
    twofaTotpForm(),
    el("section", { class: "card twofa-table-card" }, [el("div", { class: "card-body stack" }, [
      el("div", { class: "section-heading" }, [el("h2", {}, ["Codigos Google"]), el("span", { class: "pill" }, [`${data.items?.length || 0} item(ns)`])]),
      data.items?.length ? el("div", { class: "table-shell twofa-table-shell" }, [el("table", {}, [
        el("thead", {}, [el("tr", {}, ["Servico", "Conta", "Status", "Padrao", "Observacoes", "Acoes"].map((head) => el("th", {}, [head])))]),
        el("tbody", {}, data.items.map(twofaTotpRow))
      ])]) : el("div", { class: "empty" }, ["Nenhum autenticador Google cadastrado ainda."])
    ])])
  ]);
}

