async function closeVendinhaMonth(data, mode = "exact") {
  const total = Number(data.summary?.total || 0);
  let totalPaid = total;
  if (mode === "actual") {
    totalPaid = promptBRL("Qual foi o valor exato que voce pagou?", data.summary?.status === "paid" ? data.summary?.paid : total);
    if (totalPaid === null) return;
    if (!Number.isFinite(totalPaid) || totalPaid < 0) return toast("Informe um valor pago valido.");
  }
  const difference = Math.round((totalPaid - total) * 100) / 100;
  const ok = await confirmAction({
    title: mode === "actual" ? "Registrar valor realmente pago?" : "Marcar pelo valor da conta?",
    message: `Conta de ${money(total)}. Valor pago: ${money(totalPaid)}. ${vendinhaAdjustmentLabel(difference)}. Todos os consumos de ${vendinhaMonthName(data.month)} serao quitados.`,
    confirmText: mode === "actual" ? "Registrar pagamento" : "Quitar valor da conta"
  });
  if (!ok) return;
  const notes = window.prompt("Observacao do pagamento (opcional):", data.current_closing?.notes || "") || "";
  await api("/api/vendinha/close-month", {
    method: "POST",
    body: JSON.stringify({ month: data.month, establishment_id: state.vendinhaEstablishment, total_paid: totalPaid, payment_date: today(), notes })
  });
  toast(difference < 0 ? `Pagamento registrado com desconto de ${money(Math.abs(difference))}.` : difference > 0 ? `Pagamento registrado com ${money(difference)} a mais.` : "Mes quitado pelo valor exato da conta.");
  renderVendinha();
}

async function reopenVendinhaMonth(data) {
  const ok = await confirmAction({
    title: "Estornar pagamento da vendinha?",
    message: `O pagamento de ${vendinhaMonthName(data.month)} sera removido e ${data.summary?.count || 0} lancamento(s) voltarao para Em aberto. Nenhum consumo sera apagado.`,
    confirmText: "Estornar pagamento",
    danger: true
  });
  if (!ok) return;
  await api("/api/vendinha/reopen-month", {
    method: "POST",
    body: JSON.stringify({ month: data.month, establishment_id: state.vendinhaEstablishment })
  });
  toast("Pagamento estornado. O mes voltou para Em aberto.");
  renderVendinha();
}

async function renderVendinha() {
  const view = document.querySelector("#view");
  view.replaceChildren(el("div", { class: "loading" }, ["Carregando Conta da Vendinha..."]));
  let data;
  try {
    data = await api(`/api/vendinha?${vendinhaQuery()}`);
  } catch (error) {
    if (String(error.message || "").toLowerCase().includes("rota nao encontrada")) {
      view.replaceChildren(el("section", { class: "card" }, [el("div", { class: "card-body stack" }, [
        el("h2", {}, ["Servidor antigo ainda esta rodando"]),
        el("p", { class: "muted" }, ["A tela da Vendinha ja foi instalada, mas o Node que esta aberto na porta 3334 ainda e uma versao antiga e nao conhece a rota /api/vendinha."]),
        el("p", { class: "muted" }, ["Feche o DRSOSystem/Node que esta aberto e abra novamente para carregar o backend atualizado."])
      ])]));
      return;
    }
    throw error;
  }
  state.vendinhaMonth = data.month || state.vendinhaMonth;
  view.replaceChildren(el("div", { class: "stack vendinha-page" }, [
    vendinhaFilters(data),
    vendinhaSummaryCards(data),
    vendinhaLimitCard(data),
    vendinhaQuickButtons(data),
    el("div", { class: "grid two-col vendinha-main-grid" }, [
      el("div", { class: "stack" }, [vendinhaConsumptionForm(data), vendinhaGroupedList(data)]),
      el("div", { class: "stack" }, [vendinhaSetupForms(data), vendinhaHistory(data)])
    ]),
    vendinhaCharts(data)
  ]));
}

async function renderMusic() {
  const view = document.querySelector("#view");
  if (musicPlayer?.destroy) {
    musicPlayer.destroy();
    musicPlayer = null;
    state.musicPlayerState = "stopped";
  }
  view.replaceChildren(el("div", { class: "loading" }, ["Carregando Musicas..."]));
  let playlists = await api("/api/music/playlists");
  const visiblePlaylists = displayMusicPlaylists(playlists);
  if (!state.musicPlaylistId && visiblePlaylists.length) state.musicPlaylistId = visiblePlaylists[0].id;
  let selected = null;
  if (state.musicPlaylistId && state.musicTab !== "radios") {
    selected = await api(`/api/music/playlists/${state.musicPlaylistId}`).catch(() => null);
    if (!selected || isRadioPlaylist(selected)) {
      state.musicPlaylistId = "";
      selected = null;
    }
  }
  let radioPlaylist = playlists.find(isRadioPlaylist) || null;
  if (state.musicTab === "radios") {
    radioPlaylist = await ensureRadioPlaylist(playlists);
    radioPlaylist = await api(`/api/music/playlists/${radioPlaylist.id}`);
    playlists = playlists.some((playlist) => playlist.id === radioPlaylist.id) ? playlists : [...playlists, radioPlaylist];
  }
  view.replaceChildren(el("div", { class: "stack music-page" }, [
    musicSubnav(),
    state.musicTab === "radios"
      ? radioPanel(radioPlaylist)
      : el("div", { class: "grid two-col music-layout" }, [
        el("div", { class: "stack music-sidebar" }, [playlistForm(), playlistCards(displayMusicPlaylists(playlists))]),
        selectedPlaylistPanel(selected)
      ])
  ]));
  if ((selected?.musicas?.length || radioPlaylist?.musicas?.length) && state.musicCurrentId) syncMusicPlayerButtons();
}

async function renderSettings() {
  const data = await api("/api/settings");
  setAuthenticatedUser(data.user);
  const form = el("form", { class: "card" });
  const themeSelect = el("select", { name: "theme" }, ["dark", "light"].map((theme) => el("option", { value: theme, selected: data.user.theme === theme ? "selected" : undefined }, [theme])));
  themeSelect.addEventListener("change", async () => {
    const next = applyTheme(themeSelect.value);
    try {
      const payload = Object.fromEntries(new FormData(form).entries());
      await saveThemePreference(next, payload);
      toast(`Tema ${next === "light" ? "claro" : "escuro"} aplicado.`);
    } catch (error) {
      toast("Tema aplicado nesta tela, mas nao foi salvo no perfil.");
      console.warn("Nao foi possivel salvar o tema no perfil.", error);
    }
  });
  form.append(el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field" }, [el("label", {}, ["Nome do usuario"]), el("input", { name: "name", value: data.user.name })]),
    el("div", { class: "field" }, [el("label", {}, ["Tema"]), themeSelect]),
    el("div", { class: "field full" }, [el("label", {}, ["Caminho do banco de dados"]), el("input", { value: data.dbPath, readonly: "readonly" })]),
    el("div", { class: "form-actions full" }, [el("button", { class: "primary-button" }, ["Salvar configuracoes"])])
  ]));
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const saved = await api("/api/settings", { method: "PUT", body: JSON.stringify(Object.fromEntries(new FormData(form).entries())) });
    setAuthenticatedUser(saved);
    applyTheme(saved.theme);
    toast("Configuracoes salvas.");
  });
  document.querySelector("#view").replaceChildren(
    form,
    userSecurityPanel(data.user),
    backupPanel(data.backups)
  );
}

function backupPanel(backups) {
  return el("div", { class: "card", style: "margin-top:14px" }, [el("div", { class: "card-body stack" }, [
    el("div", { class: "settings-card-head" }, [
      el("div", {}, [
        el("h2", {}, ["Backups"]),
        el("p", { class: "muted" }, ["Gere uma copia completa do sistema: banco, documentos protegidos, codigo e arquivos internos."])
      ]),
      el("button", {
        class: "primary-button",
        type: "button",
        onclick: async (event) => {
          if (backups.length) {
            const latest = backups[0];
            const ok = await confirmAction({
              title: "Gerar outro backup?",
              message: `Ja existe um backup gerado em ${formatBRDateTime(latest.created_at)}. Deseja criar outro backup completo mesmo assim?`,
              confirmText: "Gerar outro backup"
            });
            if (!ok) return;
          }
          const button = event.currentTarget;
          const loading = openLoadingModal("Gerando backup completo", "Aguarde enquanto o sistema empacota banco de dados, arquivos protegidos e estrutura do DRSOSystem.");
          button.disabled = true;
          button.textContent = "Gerando...";
          try {
            const result = await api("/api/backup", { method: "POST" });
            loading.success(result);
            toast("Backup gerado com sucesso.");
            renderSettings();
          } catch (error) {
            loading.error(error);
          } finally {
            button.disabled = false;
            button.textContent = "Gerar backup";
          }
        }
      }, ["Gerar backup"])
    ]),
    backups.length ? el("div", { class: "stack" }, backups.map((backup) => el("span", { class: "pill" }, [`${formatBRDateTime(backup.created_at)}  -  ${backup.file_name}`]))) : el("p", { class: "muted" }, ["Nenhum backup gerado."])
  ])]);
}

function userSecurityPanel(user) {
  const passwordForm = el("form", { class: "card" });
  passwordForm.append(el("div", { class: "card-body form-grid" }, [
    el("div", { class: "field full" }, [el("h2", {}, ["Usuario e seguranca"]), el("p", { class: "muted" }, [`Logado como ${user.username}. Senhas ficam protegidas por hash no banco local.`])]),
    el("div", { class: "field" }, [el("label", { for: "current-password" }, ["Senha atual"]), el("input", { id: "current-password", name: "currentPassword", type: "password", required: "required", autocomplete: "current-password" })]),
    el("div", { class: "field" }, [el("label", { for: "new-password" }, ["Nova senha"]), el("input", { id: "new-password", name: "newPassword", type: "password", required: "required", minlength: "6", autocomplete: "new-password" })]),
    el("div", { class: "form-actions full" }, [
      el("button", { class: "primary-button" }, ["Trocar senha"]),
      el("button", { class: "secondary-button", type: "button", onclick: logout }, ["Sair do sistema"])
    ])
  ]));
  passwordForm.addEventListener("submit", async (event) => {
    event.preventDefault();
    try {
      await api("/api/users/password", { method: "PUT", body: JSON.stringify(Object.fromEntries(new FormData(passwordForm).entries())) });
      passwordForm.reset();
      toast("Senha alterada.");
    } catch (error) {
      toast(error.message);
    }
  });
  return el("div", { style: "margin-top:14px" }, [passwordForm]);
}

async function renderProfile() {
  const data = await api("/api/settings");
  const user = data.user || {};
  if (isLegacyTruncatedAvatar(user.avatar_url)) user.avatar_url = "";
  setAuthenticatedUser(user);
  const avatarPreview = el("span", { class: "profile-avatar-preview" });
  updateProfileAvatarElement(avatarPreview, user.avatar_url);
  const avatarInput = el("input", { name: "avatar_url", type: "hidden", value: user.avatar_url || "" });
  const fileInput = el("input", { type: "file", accept: "image/png,image/jpeg,image/webp,image/gif" });
  fileInput.addEventListener("change", () => {
    const file = fileInput.files?.[0];
    if (!file) return;
    if (!/^image\/(png|jpeg|webp|gif)$/.test(file.type)) return toast("Use uma imagem PNG, JPG, WEBP ou GIF.");
    if (file.size > 1500 * 1024) return toast("Use uma imagem de ate 1,5 MB para o avatar.");
    const reader = new FileReader();
    reader.onload = () => {
      avatarInput.value = String(reader.result || "");
      if (avatarInput.value.length > 2200000) {
        avatarInput.value = "";
        return toast("Essa foto ficou muito grande. Tente uma imagem menor.");
      }
      updateProfileAvatarElement(avatarPreview, avatarInput.value);
      updateProfileAvatarElement(document.querySelector("#topbar-profile-avatar"), avatarInput.value);
    };
    reader.readAsDataURL(file);
  });
  const form = el("form", { class: "profile-page-form" });
  const profileThemeSelect = el("select", { name: "theme" }, ["light", "dark"].map((theme) => el("option", { value: theme, selected: (user.theme || "light") === theme ? "selected" : undefined }, [theme === "light" ? "Claro" : "Escuro"])));
  const accentColorInput = el("input", { name: "accent_color", type: "color", value: normalizeAccentColor(user.accent_color) });
  accentColorInput.addEventListener("input", () => applyAccentColor(accentColorInput.value));
  profileThemeSelect.addEventListener("change", async () => {
    const next = applyTheme(profileThemeSelect.value);
    try {
      const payload = Object.fromEntries(new FormData(form).entries());
      await saveThemePreference(next, payload);
      toast(`Tema ${next === "light" ? "claro" : "escuro"} aplicado.`);
    } catch (error) {
      toast("Tema aplicado nesta tela, mas nao foi salvo no perfil.");
      console.warn("Nao foi possivel salvar o tema no perfil.", error);
    }
  });
  form.append(
    avatarInput,
    el("section", { class: "profile-hero-card" }, [
      el("div", { class: "profile-hero-avatar" }, [
        avatarPreview,
        el("label", { class: "secondary-button profile-avatar-upload" }, ["Trocar foto", fileInput])
      ]),
      el("div", {}, [
        el("span", { class: "profile-status-pill" }, ["Online"]),
        el("h2", {}, [displayUserName()]),
        el("p", {}, [user.slogan || "Uma Vida. Um Sistema."]),
        el("small", {}, [user.bio || "Adicione uma breve descricao sobre voce."])
      ]),
      el("div", { class: "profile-hero-actions" }, [
        el("button", { class: "primary-button", type: "submit" }, ["Salvar alteracoes"]),
        el("button", { class: "secondary-button", type: "button", onclick: logout }, ["Sair do sistema"])
      ])
    ]),
    el("div", { class: "profile-grid" }, [
      el("section", { class: "card profile-card" }, [el("div", { class: "card-body form-grid" }, [
        el("div", { class: "field full" }, [el("h2", {}, ["Informacoes pessoais"]), el("p", { class: "muted" }, ["Esses dados aparecem no topo e na dashboard."])]),
        el("div", { class: "field" }, [el("label", {}, ["Nome de exibicao"]), el("input", { name: "name", value: user.name || "" })]),
        el("div", { class: "field" }, [el("label", {}, ["Primeiro nome"]), el("input", { name: "first_name", value: user.first_name || "" })]),
        el("div", { class: "field" }, [el("label", {}, ["Sobrenome"]), el("input", { name: "last_name", value: user.last_name || "" })]),
        el("div", { class: "field" }, [el("label", {}, ["Cidade"]), el("input", { name: "city", value: user.city || "" })]),
        el("div", { class: "field" }, [el("label", {}, ["Nascimento"]), el("input", { name: "birth_date", type: "date", value: user.birth_date || "" })]),
        el("div", { class: "field full" }, [el("label", {}, ["Biografia"]), el("textarea", { name: "bio", rows: "4" }, [user.bio || ""])])
      ])]),
      el("section", { class: "card profile-card" }, [el("div", { class: "card-body form-grid" }, [
        el("div", { class: "field full" }, [el("h2", {}, ["Aparencia"]), el("p", { class: "muted" }, ["Preferencias visuais do seu sistema pessoal."])]),
        el("div", { class: "field full" }, [el("label", {}, ["Slogan pessoal"]), el("input", { name: "slogan", value: user.slogan || "Uma Vida. Um Sistema." })]),
        el("div", { class: "field" }, [el("label", {}, ["Tema"]), profileThemeSelect]),
        el("div", { class: "field" }, [el("label", {}, ["Cor de destaque"]), accentColorInput]),
        el("div", { class: "field" }, [el("label", {}, ["Formato de data"]), el("select", { name: "date_format" }, ["pt-BR", "yyyy-MM-dd"].map((format) => el("option", { value: format, selected: (user.date_format || "pt-BR") === format ? "selected" : undefined }, [format])))]),
        el("div", { class: "field full profile-avatar-actions" }, [
          el("button", { class: "secondary-button", type: "button", onclick: () => {
            avatarInput.value = "";
            updateProfileAvatarElement(avatarPreview, "");
            updateProfileAvatarElement(document.querySelector("#topbar-profile-avatar"), "");
          } }, ["Remover avatar"])
        ])
      ])]),
      el("section", { class: "card profile-card card-no-collapse" }, [el("div", { class: "card-body stack" }, [
        el("h2", {}, ["Informacoes do sistema"]),
        el("div", { class: "profile-system-list" }, [
          profileSystemRow("Usuario", user.username || "Nao disponivel"),
          profileSystemRow("Criado em", user.created_at ? formatBRDateTime(user.created_at) : "Nao disponivel"),
          profileSystemRow("Ultimo backup", data.backups?.[0]?.created_at ? formatBRDateTime(data.backups[0].created_at) : "Nao disponivel"),
          profileSystemRow("Banco de dados", data.dbPath || "Nao disponivel")
        ]),
        el("img", {
          class: "profile-security-illustration",
          src: "/assets/profile-security-illustration.png",
          alt: "Seguranca dos dados",
          loading: "lazy"
        })
      ])])
    ])
  );
  form.addEventListener("submit", async (event) => {
    event.preventDefault();
    const submit = form.querySelector('button[type="submit"]');
    submit.disabled = true;
    submit.textContent = "Salvando...";
    try {
      const payload = Object.fromEntries(new FormData(form).entries());
      if (!String(payload.name || "").trim()) throw new Error("Informe um nome de exibicao.");
      const saved = await api("/api/settings", { method: "PUT", body: JSON.stringify(payload) });
      setAuthenticatedUser(saved);
      applyTheme(saved.theme);
      toast("Perfil atualizado.");
      renderProfile();
    } catch (error) {
      toast(error.message || "Nao foi possivel salvar o perfil.");
    } finally {
      submit.disabled = false;
      submit.textContent = "Salvar alteracoes";
    }
  });
  document.querySelector("#view").replaceChildren(el("div", { class: "profile-page" }, [form]));
}

function profileSystemRow(label, value) {
  return el("div", {}, [el("span", {}, [label]), el("strong", {}, [value])]);
}

const notificationCategoryConfig = {
  AGENDA: { icon: "📅", label: "Agenda" },
  TASK: { icon: "✅", label: "Tarefas" },
  FINANCE: { icon: "💵", label: "Financeiro" },
  BACKUP: { icon: "☁️", label: "Backup" },
  SECURITY: { icon: "🛡️", label: "Seguranca" },
  PROJECT: { icon: "🚀", label: "Projetos" },
  GOAL: { icon: "🎯", label: "Objetivos" },
  WISHLIST: { icon: "🛒", label: "Lista de desejos" },
  GALLERY: { icon: "🖼️", label: "Galeria" },
  MUSIC: { icon: "🎧", label: "Musicas" },
  INTEGRATION: { icon: "🔗", label: "Integracoes" },
  SYSTEM: { icon: "⚙️", label: "Sistema" },
  OTHER: { icon: "✨", label: "Outros" }
};
const notificationSeverityLabels = { INFO: "Informacao", SUCCESS: "Sucesso", WARNING: "Atencao", ERROR: "Erro", CRITICAL: "Critica" };

function notificationRelativeTime(value) {
  const raw = String(value || "").replace(" ", "T");
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return formatBRDateTime(value);
  const diff = Date.now() - date.getTime();
  const minute = 60 * 1000;
  const hour = 60 * minute;
  const day = 24 * hour;
  if (diff < minute) return "Agora mesmo";
  if (diff < hour) return `Ha ${Math.floor(diff / minute)} min`;
  if (diff < day) return `Ha ${Math.floor(diff / hour)} h`;
  if (diff < 2 * day) return "Ontem";
  return formatBRDateTime(value).slice(0, 10);
}

function notificationGroupLabel(value) {
  const date = String(value || "").slice(0, 10);
  const now = today();
  if (date === now) return "Hoje";
  if (date === addDays(now, -1)) return "Ontem";
  if (date >= addDays(now, -7)) return "Esta semana";
  return "Anteriores";
}

function setNotificationBadge(count) {
  const badge = document.querySelector("#topbar-notification-badge");
  const button = document.querySelector("#topbar-notification-button");
  const total = Number(count || 0);
  if (!badge || !button) return;
  badge.textContent = total > 99 ? "99+" : String(total);
  badge.hidden = total <= 0;
  button.setAttribute("aria-label", total > 0 ? `Notificacoes, ${total} nao lidas` : "Notificacoes");
  if (total > notificationLastUnreadCount) {
    button.classList.remove("has-new-notification");
    void button.offsetWidth;
    button.classList.add("has-new-notification");
  }
  notificationLastUnreadCount = total;
}

function notificationBrowserEnabled() {
  return notificationState.preferences.some((pref) => pref.browserEnabled);
}

function notificationSoundEnabled() {
  return notificationState.preferences.some((pref) => pref.soundEnabled);
}

function playNotificationSound() {
  if (!notificationSoundEnabled()) return;
  try {
    const AudioContextClass = window.AudioContext || window.webkitAudioContext;
    if (!AudioContextClass) return;
    const context = new AudioContextClass();
    const oscillator = context.createOscillator();
    const gain = context.createGain();
    oscillator.type = "sine";
    oscillator.frequency.value = 740;
    gain.gain.setValueAtTime(0.0001, context.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.05, context.currentTime + 0.02);
    gain.gain.exponentialRampToValueAtTime(0.0001, context.currentTime + 0.18);
    oscillator.connect(gain);
    gain.connect(context.destination);
    oscillator.start();
    oscillator.stop(context.currentTime + 0.2);
    setTimeout(() => context.close?.(), 260);
  } catch {
    // O navegador pode bloquear audio sem interacao; nesse caso seguimos silenciosamente.
  }
}

async function maybeNotifyNewNotifications(previousCount, nextCount) {
  if (!authState.authenticated || document.hidden || nextCount <= previousCount || previousCount < 0) return;
  playNotificationSound();
  try {
    const data = await api("/api/notifications?tab=unread&page=1&limit=1");
    const item = data.items?.[0];
    if (!item) return;
    toast(`Nova notificacao: ${item.title}`);
    if (notificationBrowserEnabled() && "Notification" in window && Notification.permission === "granted") {
      const systemNotification = new Notification(item.title, {
        body: item.message || "Abra a central para ver os detalhes.",
        tag: `drso-notification-${item.id}`,
        silent: !notificationSoundEnabled()
      });
      systemNotification.onclick = () => {
        window.focus();
        openNotificationCenter();
        systemNotification.close();
      };
    }
  } catch {
    // O badge continua atualizado mesmo quando o resumo da notificacao falha.
  }
}

async function refreshNotificationCount() {
  if (!authState.authenticated) return;
  try {
    const data = await api("/api/notifications/count");
    const nextCount = Number(data.unreadCount || 0);
    const previousCount = notificationLastUnreadCount;
    setNotificationBadge(nextCount);
    await maybeNotifyNewNotifications(previousCount, nextCount);
    if (notificationState.open) await loadNotifications({ keepItems: false });
  } catch {
    // Falhas temporarias nao devem atrapalhar o uso do sistema.
  }
}

function startNotificationPolling() {
  stopNotificationPolling();
  refreshNotificationCount();
  notificationPollTimer = setInterval(() => {
    if (document.hidden) return;
    refreshNotificationCount();
  }, 45000);
}

function stopNotificationPolling() {
  if (notificationPollTimer) clearInterval(notificationPollTimer);
  notificationPollTimer = null;
  notificationAbortController?.abort();
  notificationAbortController = null;
  setNotificationBadge(0);
}

function notificationQueryParams() {
  const params = new URLSearchParams({ tab: notificationState.tab, page: String(notificationState.page), limit: "20" });
  if (notificationState.category) params.set("category", notificationState.category);
  if (notificationState.severity) params.set("severity", notificationState.severity);
  return params;
}

async function loadNotifications(options = {}) {
  if (!notificationState.open && !options.force) return;
  notificationAbortController?.abort();
  notificationAbortController = new AbortController();
  notificationState.loading = true;
  notificationState.error = "";
  renderNotificationPopover();
  try {
    const data = await api(`/api/notifications?${notificationQueryParams().toString()}`, { signal: notificationAbortController.signal });
    notificationState.items = options.keepItems ? [...notificationState.items, ...(data.items || [])] : (data.items || []);
    notificationState.hasMore = Boolean(data.hasMore);
    notificationState.modules = data.modules || [];
    notificationState.preferences = data.preferences || [];
    setNotificationBadge(data.unreadCount || 0);
  } catch (error) {
    if (error.name !== "AbortError") notificationState.error = "Nao foi possivel carregar as notificacoes.";
  } finally {
    notificationState.loading = false;
    renderNotificationPopover();
  }
}

function openNotificationCenter() {
  notificationState.open = true;
  document.querySelector("#topbar-notification-button")?.setAttribute("aria-expanded", "true");
  renderNotificationPopover();
  loadNotifications({ force: true });
}

function closeNotificationCenter() {
  notificationState.open = false;
  notificationAbortController?.abort();
  document.querySelector(".notification-popover")?.remove();
  document.querySelector(".notification-backdrop")?.remove();
  document.querySelector("#topbar-notification-button")?.setAttribute("aria-expanded", "false");
  document.querySelector("#topbar-notification-button")?.focus();
}

function toggleNotificationCenter() {
  if (notificationState.open) return closeNotificationCenter();
  openNotificationCenter();
}

function renderNotificationPopover() {
  document.querySelector(".notification-popover")?.remove();
  document.querySelector(".notification-backdrop")?.remove();
  if (!notificationState.open) return;
  const unread = notificationLastUnreadCount;
  const popover = el("aside", { class: "notification-popover", role: "dialog", "aria-label": "Central de notificacoes" }, [
    el("header", { class: "notification-head" }, [
      el("div", {}, [el("h2", {}, ["Notificacoes"]), el("span", {}, [`${unread} nao lida${unread === 1 ? "" : "s"}`])]),
      el("div", { class: "notification-head-actions" }, [
        el("button", { type: "button", disabled: unread ? undefined : "disabled", onclick: markAllNotificationsRead }, ["Marcar todas como lidas"]),
        el("button", { type: "button", "aria-label": "Preferencias de notificacoes", onclick: openNotificationPreferences }, ["⚙"]),
        el("button", { type: "button", class: "notification-mobile-close", "aria-label": "Fechar", onclick: closeNotificationCenter }, ["×"])
      ])
    ]),
    notificationTabs(),
    notificationFilters(),
    notificationList()
  ]);
  const backdrop = el("button", { class: "notification-backdrop", type: "button", "aria-label": "Fechar notificacoes", onclick: closeNotificationCenter });
  document.body.append(backdrop, popover);
}

function notificationTabs() {
  const tabs = [["all", "Todas"], ["unread", "Nao lidas"], ["important", "Importantes"]];
  return el("div", { class: "notification-tabs", role: "tablist" }, tabs.map(([value, label]) => el("button", {
    type: "button",
    class: notificationState.tab === value ? "active" : "",
    onclick: () => {
      notificationState.tab = value;
      notificationState.page = 1;
      loadNotifications({ force: true });
    }
  }, [label])));
}

function notificationFilters() {
  return el("div", { class: "notification-filters" }, [
    el("select", { onchange: (event) => { notificationState.category = event.target.value; notificationState.page = 1; loadNotifications({ force: true }); } }, [
      el("option", { value: "" }, ["Todos os modulos"]),
      ...notificationState.modules.map((item) => el("option", { value: item.value, selected: notificationState.category === item.value ? "selected" : undefined }, [item.label]))
    ]),
    el("select", { onchange: (event) => { notificationState.severity = event.target.value; notificationState.page = 1; loadNotifications({ force: true }); } }, [
      el("option", { value: "" }, ["Todas severidades"]),
      ...Object.entries(notificationSeverityLabels).map(([value, label]) => el("option", { value, selected: notificationState.severity === value ? "selected" : undefined }, [label]))
    ]),
    el("button", { type: "button", onclick: () => {
      notificationState.category = "";
      notificationState.severity = "";
      notificationState.page = 1;
      loadNotifications({ force: true });
    } }, ["Limpar filtros"])
  ]);
}

function notificationList() {
  if (notificationState.loading && !notificationState.items.length) {
    return el("div", { class: "notification-list" }, Array.from({ length: 5 }, () => el("div", { class: "notification-skeleton" })));
  }
  if (notificationState.error) {
    return el("div", { class: "notification-empty" }, [el("strong", {}, [notificationState.error]), el("button", { class: "secondary-button", type: "button", onclick: () => loadNotifications({ force: true }) }, ["Tentar novamente"])]);
  }
  if (!notificationState.items.length) {
    return el("div", { class: "notification-empty" }, [
      el("strong", {}, [notificationState.tab === "all" ? "Voce nao possui notificacoes." : "Nenhuma notificacao encontrada neste filtro."]),
      el("span", {}, ["Quando houver novidades importantes, elas aparecerao aqui."])
    ]);
  }
  const groups = new Map();
  for (const item of notificationState.items) {
    const group = notificationGroupLabel(item.createdAt);
    if (!groups.has(group)) groups.set(group, []);
    groups.get(group).push(item);
  }
  return el("div", { class: "notification-list" }, [
    ...[...groups.entries()].map(([group, items]) => el("section", { class: "notification-group" }, [
      el("h3", {}, [group]),
      ...items.map(notificationItem)
    ])),
    notificationState.hasMore ? el("button", { class: "notification-load-more", type: "button", onclick: () => {
      notificationState.page += 1;
      loadNotifications({ force: true, keepItems: true });
    } }, [notificationState.loading ? "Carregando..." : "Carregar mais"]) : el("span")
  ]);
}

function notificationItem(item) {
  const category = notificationCategoryConfig[item.category] || notificationCategoryConfig.OTHER;
  return el("article", {
    class: `notification-item ${item.isRead ? "read" : "unread"} severity-${String(item.severity || "INFO").toLowerCase()}`,
    onclick: (event) => {
      if (event.target.closest("button")) return;
      openNotificationDetails(item);
    }
  }, [
    el("span", { class: "notification-icon", "aria-hidden": "true" }, [category.icon]),
    el("div", { class: "notification-copy" }, [
      el("div", { class: "notification-title-row" }, [
        el("strong", {}, [item.title]),
        !item.isRead ? el("i", { title: "Nao lida" }) : el("span")
      ]),
      el("p", {}, [item.message || "Sem detalhes adicionais."]),
      el("small", {}, [`${category.label} · ${notificationSeverityLabels[item.severity] || item.severity} · ${notificationRelativeTime(item.createdAt)}`]),
      el("div", { class: "notification-actions" }, [
        item.actionUrl ? el("button", { type: "button", onclick: () => openNotificationAction(item) }, [item.primaryActionLabel || "Abrir"]) : el("span"),
        el("button", { type: "button", onclick: () => mutateNotification(item.id, item.isRead ? "unread" : "read") }, [item.isRead ? "Nao lida" : "Lida"]),
        el("button", { type: "button", onclick: () => mutateNotification(item.id, item.isPinned ? "unpin" : "pin") }, [item.isPinned ? "Desafixar" : "Fixar"]),
        el("button", { type: "button", onclick: () => snoozeNotification(item.id, "hour") }, ["Adiar"]),
        el("button", { type: "button", onclick: () => mutateNotification(item.id, "archive") }, ["Arquivar"])
      ])
    ])
  ]);
}

async function mutateNotification(id, action, extra = {}) {
  try {
    const result = await api(`/api/notifications/${id}`, { method: "PATCH", body: JSON.stringify({ action, ...extra }) });
    setNotificationBadge(result.unreadCount || 0);
    toast(action === "archive" ? "Notificacao arquivada." : action === "pin" ? "Notificacao fixada." : "Notificacao atualizada.");
    await loadNotifications({ force: true });
  } catch (error) {
    toast(error.message || "Nao foi possivel concluir esta acao.");
  }
}

function snoozeNotification(id, option) {
  const date = option === "tomorrow"
    ? `${addDays(today(), 1)} 08:00:00`
    : option === "10"
      ? localDateTimeFromMilliseconds(Date.now() + 10 * 60 * 1000)
      : localDateTimeFromMilliseconds(Date.now() + 60 * 60 * 1000);
  mutateNotification(id, "snooze", { snoozedUntil: date });
  toast(option === "tomorrow" ? "Notificacao adiada ate amanha." : "Notificacao adiada.");
}

async function markAllNotificationsRead() {
  try {
    const data = await api("/api/notifications/read-all", { method: "POST" });
    setNotificationBadge(data.unreadCount || 0);
    toast("Todas as notificacoes foram marcadas como lidas.");
    await loadNotifications({ force: true });
  } catch (error) {
    toast(error.message || "Nao foi possivel marcar como lidas.");
  }
}

async function openNotificationAction(item) {
  if (!item.isRead) await mutateNotification(item.id, "read");
  const target = String(item.actionUrl || "").replace(/^#/, "");
  if (target) {
    closeNotificationCenter();
    setSection(target);
  }
}

function openNotificationModal(title, content, actions = []) {
  document.querySelector(".notification-modal-backdrop")?.remove();
  const close = () => {
    overlay.remove();
    document.body.classList.remove("modal-open");
  };
  const overlay = el("div", { class: "confirm-modal-backdrop notification-modal-backdrop", onclick: close }, [
    el("article", { class: "confirm-modal notification-modal", onclick: (event) => event.stopPropagation() }, [
      el("button", { class: "notification-modal-close", type: "button", "aria-label": "Fechar", onclick: close }, ["x"]),
      el("h2", {}, [title]),
      typeof content === "string" ? el("p", { class: "muted" }, [content]) : content,
      el("div", { class: "confirm-actions gallery-modal-actions" }, actions.length ? actions.map((action) => el("button", {
        class: action.primary ? "primary-button" : "secondary-button",
        type: "button",
        onclick: async () => {
          await action.run?.();
          close();
        }
      }, [action.label])) : [el("button", { class: "primary-button", type: "button", onclick: close }, ["Fechar"])])
    ])
  ]);
  document.body.append(overlay);
  document.body.classList.add("modal-open");
}

function openNotificationDetails(item) {
  openNotificationModal(item.title, el("div", { class: "notification-detail-body" }, [
    el("p", {}, [item.message || "Sem detalhes adicionais."]),
    el("dl", {}, [
      el("dt", {}, ["Modulo"]), el("dd", {}, [notificationCategoryConfig[item.category]?.label || item.category]),
      el("dt", {}, ["Severidade"]), el("dd", {}, [notificationSeverityLabels[item.severity] || item.severity]),
      el("dt", {}, ["Data"]), el("dd", {}, [formatBRDateTime(item.createdAt)]),
      item.sourceEntityType ? el("dt", {}, ["Origem"]) : el("span"),
      item.sourceEntityType ? el("dd", {}, [`${item.sourceEntityType} #${item.sourceEntityId || "-"}`]) : el("span")
    ])
  ]), item.actionUrl ? [{ label: item.primaryActionLabel || "Abrir modulo", primary: true, run: () => openNotificationAction(item) }] : []);
  if (!item.isRead) mutateNotification(item.id, "read");
}

function openNotificationPreferences() {
  const rows = notificationState.preferences.length ? notificationState.preferences : Object.keys(notificationCategoryConfig).map((category) => ({
    category,
    label: notificationCategoryConfig[category].label,
    inAppEnabled: true,
    browserEnabled: false,
    soundEnabled: false,
    minimumSeverity: "INFO",
    quietHoursEnabled: false,
    quietHoursStart: "22:00",
    quietHoursEnd: "07:00"
  }));
  const form = el("form", { class: "notification-preferences-form" }, [
    el("p", { class: "muted" }, ["Escolha como cada modulo pode te avisar. Se ativar notificacoes do navegador, o sistema vai pedir permissao uma unica vez."]),
    el("div", { class: "notification-preferences-list" }, rows.map((pref) => el("fieldset", { class: "notification-pref-row" }, [
      el("legend", {}, [pref.label]),
      el("label", {}, [
        el("input", { type: "checkbox", name: `${pref.category}:inApp`, checked: pref.inAppEnabled ? "checked" : undefined }),
        el("span", {}, ["Dentro do sistema"])
      ]),
      el("label", {}, [
        el("input", { type: "checkbox", name: `${pref.category}:browser`, checked: pref.browserEnabled ? "checked" : undefined }),
        el("span", {}, ["Navegador"])
      ]),
      el("label", {}, [
        el("input", { type: "checkbox", name: `${pref.category}:sound`, checked: pref.soundEnabled ? "checked" : undefined }),
        el("span", {}, ["Som"])
      ]),
      el("label", { class: "notification-pref-wide" }, [
        el("span", {}, ["Severidade minima"]),
        el("select", { name: `${pref.category}:minimumSeverity` }, Object.entries(notificationSeverityLabels).map(([value, label]) => el("option", { value, selected: pref.minimumSeverity === value ? "selected" : undefined }, [label])))
      ]),
      el("label", {}, [
        el("input", { type: "checkbox", name: `${pref.category}:quiet`, checked: pref.quietHoursEnabled ? "checked" : undefined }),
        el("span", {}, ["Silenciar horario"])
      ]),
      el("label", {}, [
        el("span", {}, ["Inicio"]),
        el("input", { type: "time", name: `${pref.category}:quietStart`, value: pref.quietHoursStart || "22:00" })
      ]),
      el("label", {}, [
        el("span", {}, ["Fim"]),
        el("input", { type: "time", name: `${pref.category}:quietEnd`, value: pref.quietHoursEnd || "07:00" })
      ])
    ])))
  ]);
  openNotificationModal("Preferencias de notificacoes", form, [{
    label: "Salvar preferencias",
    primary: true,
    run: async () => {
      const formData = new FormData(form);
      const wantsBrowser = rows.some((pref) => formData.get(`${pref.category}:browser`) === "on");
      if (wantsBrowser && "Notification" in window && Notification.permission === "default") {
        await Notification.requestPermission();
      }
      const preferences = rows.map((pref) => ({
        category: pref.category,
        inAppEnabled: formData.get(`${pref.category}:inApp`) === "on",
        browserEnabled: formData.get(`${pref.category}:browser`) === "on" && (!("Notification" in window) || Notification.permission !== "denied"),
        soundEnabled: formData.get(`${pref.category}:sound`) === "on",
        minimumSeverity: formData.get(`${pref.category}:minimumSeverity`) || "INFO",
        quietHoursEnabled: formData.get(`${pref.category}:quiet`) === "on",
        quietHoursStart: formData.get(`${pref.category}:quietStart`) || "22:00",
        quietHoursEnd: formData.get(`${pref.category}:quietEnd`) || "07:00"
      }));
      const data = await api("/api/notifications/preferences", { method: "PUT", body: JSON.stringify({ preferences }) });
      notificationState.preferences = data.preferences || [];
      toast("Preferencias salvas.");
      await loadNotifications({ force: true });
    }
  }]);
}

async function logout(options = {}) {
  if (options.clearRemember !== false) localStorage.removeItem("drso_keep_connected");
  TimeCenter.close();
  clearIdleLogoutTimer();
  stopNotificationPolling();
  stopBiUsageTracker();
  stopMusicPlayback();
  await api("/api/auth/logout", { method: "POST" });
  await renderAuth();
}

async function render() {
  if (state.section === "dashboard") return dashboard();
  if (state.section === "timeCenter") return renderTimeCenterPage();
  if (state.section === "bi") return renderBi();
  if (state.section === "drsoAi") return renderDrsoAi();
  if (state.section === "finance") return renderFinance();
  if (state.section === "deliveries") return renderDeliveries();
  if (state.section === "bets") return renderBets();
    if (state.section === "agenda") return renderAgenda();
    if (state.section === "music") return renderMusic();
    if (state.section === "codexManager") return renderCodexManager();
    if (state.section === "googleCentral") return renderGoogleCentral();
    if (state.section === "twofaVault") return renderTwofaVault();
    if (state.section === "subscriptions") return renderSubscriptions();
    if (state.section === "wishlist") return renderWishlist();
    if (state.section === "vendinha") return renderVendinha();
    if (state.section === "steam") return renderSteam();
    if (state.section === "csgoSkins") return renderCsgoSkins();
    if (state.section === "moto") return renderMoto();
    if (state.section === "lifeKanban") return renderLifeKanban();
    if (state.section === "personal") return renderPersonal();
    if (state.section === "gallery") return renderGallery();
    if (state.section === "planning") return renderPlanning();
  if (state.section === "notes") return renderNotes();
  if (state.section === "documents") return renderDocuments();
  if (state.section === "passwords") return renderPasswords();
  if (state.section === "timeline") return renderTimeline();
  if (state.section === "modules") return renderModules();
  if (state.section === "database") return renderDatabase();
  if (state.section === "settings") return renderSettings();
  if (state.section === "profile") return renderProfile();
  return renderCrud();
}

document.querySelector("#floating-brand-toggle")?.addEventListener("click", (event) => event.preventDefault());
document.querySelector("#topbar-toggle")?.addEventListener("click", () => setTopbarCollapsed(true));
document.querySelector("#floating-topbar-toggle")?.addEventListener("click", () => setTopbarCollapsed(false));
document.querySelector("#section-info-button")?.addEventListener("click", openSectionInfoModal);
document.querySelector("#topbar-agenda-button")?.addEventListener("click", () => setSection("agenda"));

document.querySelector("#logout-button")?.addEventListener("click", logout);
const topbarOptionsButton = document.querySelector("#topbar-profile-button");
const topbarOptionsMenu = document.querySelector("#topbar-options-menu");
function setTopbarOptionsOpen(open) {
  topbarOptionsMenu?.classList.toggle("open", open);
  topbarOptionsMenu?.setAttribute("aria-hidden", open ? "false" : "true");
  topbarOptionsButton?.setAttribute("aria-expanded", open ? "true" : "false");
}
topbarOptionsButton?.addEventListener("click", (event) => {
  event.stopPropagation();
  setTopbarOptionsOpen(!topbarOptionsMenu?.classList.contains("open"));
});
document.querySelector("#topbar-options-profile")?.addEventListener("click", () => {
  setTopbarOptionsOpen(false);
  setSection("profile");
});
document.querySelector("#topbar-options-logout")?.addEventListener("click", async () => {
  setTopbarOptionsOpen(false);
  await logout();
});
document.addEventListener("click", (event) => {
  if (!event.target.closest?.("#topbar-profile-button, #topbar-options-menu")) setTopbarOptionsOpen(false);
});
document.querySelector("#topbar-notification-button")?.addEventListener("click", (event) => {
  event.stopPropagation();
  toggleNotificationCenter();
});
document.addEventListener("keydown", (event) => {
  if (event.key === "Escape" && notificationState.open) closeNotificationCenter();
});
document.addEventListener("visibilitychange", () => {
  if (!document.hidden) refreshNotificationCount();
});
setupTopbarGlobalSearch();

const viewObserver = new MutationObserver(() => {
  scheduleEnhanceCollapsibleCards();
  scheduleAutoIndicators();
  enhanceTableActions(document.querySelector("#view"));
});
viewObserver.observe(document.querySelector("#view"), { childList: true, subtree: true });

async function bootApp() {
  authState = await api("/api/auth/status");
  if (!authState.authenticated) return renderAuth();
  setKeepConnectedSession(Boolean(authState.session?.keepConnected));
  document.body.classList.remove("locked");
  setSidebarCollapsed(sidebarCollapsed);
  setTopbarCollapsed(topbarCollapsed);
  setPlanningPanelCollapsed(planningPanelCollapsed);
  renderNav();
  const settings = await api("/api/settings");
  const loginTheme = storedThemePreference();
  if (loginTheme && loginTheme !== settings.user.theme) {
    settings.user = await api("/api/settings", { method: "PUT", body: JSON.stringify({ ...settings.user, theme: loginTheme }) });
  }
  setAuthenticatedUser(settings.user);
  applyTheme(loginTheme || settings.user.theme || systemThemePreference(), { persist: false });
  localStorage.setItem(THEME_STORAGE_KEY, getActiveTheme());
  localStorage.removeItem("drso_login_theme");
  topbarClock();
  loadTopbarWeather();
  TimeCenter.init();
  startNotificationPolling();
  startBiUsageTracker();
  setSection(state.section || "dashboard");
}

bootApp();
